  const { data, isLoading, error, refetch } = useGetChatsQuery();
  const [respondToInvitation] = useRespondToInvitationMutation();
  const { socket, isUserOnline } = useSocket();
  const [unreadCounts, setUnreadCounts] = useState({});
  const [typingChats, setTypingChats] = useState({});
  const [isAddMenuOpen, setIsAddMenuOpen] = useState(false);
  const [activeMenu, setActiveMenu] = useState(null);
  const addMenuRef = useRef(null);
  const menuRef = useRef(null);
  
  const [togglePinChat] = useTogglePinChatMutation();
  const [deleteChatMutation] = useDeleteChatMutation();
  const [removeFromGroup] = useRemoveFromGroupMutation();

  const [expandedCommunities, setExpandedCommunities] = useState({});
  const [isAddGroupModalOpen, setIsAddGroupModalOpen] = useState(false);
  const [selectedCommunityId, setSelectedCommunityId] = useState(null);
  
  const [isManageAdminsOpen, setIsManageAdminsOpen] = useState(false);
  const [selectedCommunityForAdmins, setSelectedCommunityForAdmins] = useState(null);

  const handleOpenManageAdmins = (community, event) => {
    if (event) event.stopPropagation();
    setSelectedCommunityForAdmins(community);
    setIsManageAdminsOpen(true);
  };

  const isCommunityAdmin = (communityChat) => {
    const myId = (user?._id || user?.id || user?.userId)?.toString();
    
    // Check direct creator IDs from database
    const creatorUserId = communityChat.createdByUserId?.toString();
    const creatorOwnerId = communityChat.createdByOwnerId?.toString();
    if (creatorUserId === myId || creatorOwnerId === myId) return true;

    const creatorId = (communityChat.createdBy?.user?._id || communityChat.createdBy?.user || communityChat.createdBy)?.toString();
    if (creatorId === myId) return true;
    
    const isGroupAdmin = communityChat.groupAdmins?.some(admin => {
      const adminId = (admin.user?._id || admin.user)?.toString();
      return adminId === myId;
    });
    if (isGroupAdmin) return true;

    const adminSingleId = (communityChat.groupAdmin?._id || communityChat.groupAdmin?.user?._id || communityChat.groupAdmin)?.toString();
    if (adminSingleId === myId) return true;

    return false;
  };

  const getCommunityTotalUnread = (communityId) => {
    let total = unreadCounts[communityId] || 0;
    chats.forEach(c => {
      if ((c.parentCommunity === communityId || c.parentCommunity?._id === communityId) && !c.isCommunity) {
        total += unreadCounts[c._id] || 0;
      }
    });
    return total;
  };

  const handleOpenAddGroup = (communityId, event) => {
    event.stopPropagation();
    setSelectedCommunityId(communityId);
    setIsAddGroupModalOpen(true);
  };

  const [confirmModalConfig, setConfirmModalConfig] = useState({
    isOpen: false,
    title: "",
    message: "",
    onConfirm: () => {},
  });

  const openConfirmModal = (title, message, onConfirm) => {
    setConfirmModalConfig({
      isOpen: true,
      title,
      message,
      onConfirm,
    });
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (addMenuRef.current && !addMenuRef.current.contains(event.target)) {
        setIsAddMenuOpen(false);
      }
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setActiveMenu(null);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Listen for incoming messages to bump unread count
  useEffect(() => {
    if (!socket) return;

    const handleNewMessage = (newMessage) => {
      const transformed = transformMessage(newMessage);
      const chatId = transformed.chat?._id || transformed.chat?.id || transformed.chat;
      // If this chat is not currently selected, increment unread
      if (chatId && chatId !== selectedChatId) {
        setUnreadCounts(prev => ({
          ...prev,
          [chatId]: (prev[chatId] || 0) + 1
        }));
      }
      // Refetch chat list to update latest message preview
      refetch();
    };

    const handleTyping = (room) => {
      setTypingChats(prev => ({ ...prev, [room]: true }));
    };

    const handleStopTyping = (room) => {
      setTypingChats(prev => ({ ...prev, [room]: false }));
    };

    const handleChatUpdated = () => {
      refetch();
    };

    const handleChatDeleted = (deletedChatId) => {
      refetch();
      if (selectedChatId === deletedChatId && onChatDeleted) {
        onChatDeleted();
      }
    };

    const handleProfileUpdated = () => {
      refetch();
    };

    socket.on('message recieved', handleNewMessage);
    socket.on('typing', handleTyping);
    socket.on('stop typing', handleStopTyping);
    socket.on('chat updated', handleChatUpdated);
    socket.on('chat deleted', handleChatDeleted);
    socket.on('user profile updated', handleProfileUpdated);

    return () => {
      socket.off('message recieved', handleNewMessage);
      socket.off('typing', handleTyping);
      socket.off('stop typing', handleStopTyping);
      socket.off('chat updated', handleChatUpdated);
      socket.off('chat deleted', handleChatDeleted);
      socket.off('user profile updated', handleProfileUpdated);
    };
  }, [socket, selectedChatId, refetch]);

  // Clear unread count when a chat is selected
  useEffect(() => {
    if (selectedChatId) {
      setUnreadCounts(prev => ({ ...prev, [selectedChatId]: 0 }));
    }
  }, [selectedChatId]);

  const getChatName = (chat) => {
    if (chat.isGroupChat) return chat.chatName;
    const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
    const otherUser = chat.users?.find((u) => {
      const uid = u.user?._id || u.user;
      return !myIds.includes(uid);
    });
    return otherUser?.user?.name || "Unknown User";
  };

  const getChatOtherUser = (chat) => {
    if (chat.isGroupChat) return null;
    const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
    // Try matching by IDs
    const byId = chat.users?.find((u) => {
      const uid = u.user?._id || u.user;
      return !myIds.includes(uid);
    })?.user;
    if (byId) return byId;
    // Fallback: match by name
    const byName = chat.users?.find((u) => u.user?.name !== user?.name)?.user;
    return byName || null;
  };

  const getChatImage = (chat) => {
    if (chat.isGroupChat) return null;
    const otherUser = getChatOtherUser(chat);
    return otherUser?.profilePicture || otherUser?.profileImage;
  };

  const renderAvatar = (chat) => {
    const otherUser = getChatOtherUser(chat);
    const online = otherUser?._id ? isUserOnline(otherUser._id) : false;

    const getInitials = (name) => {
      if (!name) return "?";
      return name.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2);
    };

    if (chat.isGroupChat) {
      const groupImg = chat.groupImage;
      return (
        <div className="relative">
          <div className="w-10 h-10 rounded-full border border-white/5 bg-[#BFF367]/10 flex items-center justify-center overflow-hidden shadow-lg">
            {groupImg ? (
              <img 
                src={groupImg} 
                className="w-full h-full object-cover" 
                alt={chat.chatName}
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.nextElementSibling.style.display = 'flex';
                }}
              />
            ) : null}
            <div 
              className="w-full h-full flex items-center justify-center bg-gradient-to-br from-[#BFF367]/20 to-[#BFF367]/5"
              style={{ display: groupImg ? 'none' : 'flex' }}
            >
              <Users size={19} className="text-[#BFF367] opacity-80" />
            </div>
          </div>
        </div>
      );
    }

    const imageUrl = otherUser?.profilePicture || otherUser?.profileImage;

    return (
      <div className="relative">
        <div className="w-10 h-10 rounded-full border border-white/5 bg-white/5 flex items-center justify-center overflow-hidden shadow-lg group-hover/chat:border-[#BFF367]/30 transition-all">
          {imageUrl ? (
            <img 
              src={imageUrl} 
              alt={otherUser?.name} 
              className="w-full h-full object-cover"
              onError={(e) => {
                e.target.style.display = 'none';
                e.target.nextElementSibling.style.display = 'flex';
              }}
            />
          ) : null}
          <div 
            className="w-full h-full flex items-center justify-center bg-gradient-to-br from-white/10 to-white/5"
            style={{ display: imageUrl ? 'none' : 'flex' }}
          >
              <span className="text-[#BFF367] font-bold text-xs tracking-tighter">
              {getInitials(otherUser?.name)}
            </span>
          </div>
        </div>
        {/* Online dot */}
        {online && (
          <div className="absolute bottom-0 right-0 w-3.5 h-3.5 bg-[#BFF367] rounded-full border-[3px] border-[#1A1A1A] shadow-sm animate-pulse" />
        )}
      </div>
    );
  };

  const formatTime = (dateStr) => {
    if (!dateStr) return "";
    const date = new Date(dateStr);
    const now = new Date();
    const diff = now - date;
    const oneDay = 86400000;

    if (diff < oneDay && date.getDate() === now.getDate()) {
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    }
    if (diff < 2 * oneDay) return "Yesterday";
    return date.toLocaleDateString([], { day: '2-digit', month: '2-digit', year: '2-digit' });
  };

  const handleRespond = async (chatId, status) => {
    try {
      await respondToInvitation({ chatId, status }).unwrap();
    } catch (err) {
      console.error("Failed to respond to invitation:", err);
    }
  };

  if (isLoading) {
    return (
      <div className="w-full md:w-[340px] h-full border-r border-white/5 bg-black flex flex-col items-center justify-center">
        <Loader2 className="w-8 h-8 text-[#BFF367] animate-spin mb-4 opacity-20" />
        <p className="chat-subheading text-white/20 font-bold uppercase">Loading Chats</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="w-full md:w-[340px] h-full border-r border-white/5 bg-black flex flex-col items-center justify-center p-8 text-center">
        <div className="w-16 h-16 rounded-full bg-red-500/10 flex items-center justify-center mb-4">
          <AlertCircle className="w-8 h-8 text-red-500" />
        </div>
        <h3 className="text-white font-bold mb-2">Sync Failed</h3>
        <p className="chat-subheading text-white/40 mb-6">We couldn't load your conversations. Please try again.</p>
        <button 
          onClick={() => window.location.reload()}
          className="px-6 py-2 bg-white/5 hover:bg-white/10 text-white rounded-[8px] text-xs font-bold transition-all"
        >
          Retry
        </button>
      </div>
    );
  }

  const chats = data?.chats || [];
  const invitations = data?.invitations || [];

  return (
    <div className="w-full md:w-[340px] h-full border-r border-white/5 bg-black flex flex-col overflow-hidden">
      <div className="p-3 border-b border-white/5 flex justify-between items-center bg-[#0A0A0A]">
        <div>
          <h2 className="text-xs font-bold text-white/50 tracking-widest uppercase font-sans">Messages</h2>
        </div>
        <div className="relative" ref={addMenuRef}>
          <button 
            onClick={() => setIsAddMenuOpen(!isAddMenuOpen)}
            className={`w-10 h-10 ${isAddMenuOpen ? 'bg-[#BFF367] text-black' : 'bg-[#BFF367]/10 text-[#BFF367]'} hover:bg-[#BFF367] hover:text-black rounded-[8px] transition-all flex items-center justify-center group`}
            title="Add New"
          >
            <Plus size={20} className={`${isAddMenuOpen ? 'rotate-45' : ''} transition-transform duration-300`} />
          </button>

          {isAddMenuOpen && (
            <div className="absolute right-0 top-12 w-56 bg-[#121212] border border-white/5 rounded-[8px] shadow-2xl py-2 z-50 animate-scale-up overflow-hidden">
              <button 
                onClick={() => {
                  setIsAddMenuOpen(false);
                  onCreateGroup();
                }}
                className="w-full px-4 py-3 text-left text-sm text-white hover:bg-white/[0.04] flex items-center gap-3 transition-colors group/menu"
              >
                <div className="w-8 h-8 rounded-lg bg-white/[0.04] border border-white/5 flex items-center justify-center text-[#BFF367] group-hover/menu:border-[#BFF367]/40">
                  <Users size={16} />
                </div>
                <div className="flex flex-col">
                  <span className="font-bold text-white">Create Group</span>
                  <span className="text-[10px] text-white/45">Chat with multiple people</span>
                </div>
              </button>

              <button 
                onClick={() => {
                  setIsAddMenuOpen(false);
                  // Trigger community creation
                  if (typeof onCreateCommunity === 'function') onCreateCommunity();
                }}
                className="w-full px-4 py-3 text-left text-sm text-white hover:bg-white/[0.04] flex items-center gap-3 transition-colors group/menu"
              >
                <div className="w-8 h-8 rounded-lg bg-white/[0.04] border border-white/5 flex items-center justify-center text-[#BFF367] group-hover/menu:border-[#BFF367]/40">
                  <MessageSquare size={16} />
                </div>
                <div className="flex flex-col">
                  <span className="font-bold text-white">Create Community</span>
                  <span className="text-[10px] text-white/45">Organize related groups</span>
                </div>
              </button>
            </div>
          )}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto [&::-webkit-scrollbar]:hidden [-ms-overflow-style:none] [scrollbar-width:none]">

        {/* Invitations Section */}
        {invitations.length > 0 && (
          <div className="p-3 space-y-2">
            <h3 className="px-3 py-2 text-xs font-semibold text-white/50 uppercase tracking-wider">Pending Invitations</h3>
            {invitations.map((chat) => (
              <div key={chat._id} className="bg-white/[0.03] border border-white/5 rounded-[8px] p-4">
                <div className="flex items-center gap-3 mb-3">
                  <div className="w-10 h-10 rounded-full border border-white/5 bg-white/5 flex items-center justify-center overflow-hidden">
                    {getChatImage(chat) ? (
                      <img src={getChatImage(chat)} alt={chat.chatName} className="w-full h-full object-cover" />
                    ) : (
                      <Users size={18} className="text-white/20" />
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-white text-base truncate">{chat.chatName}</p>
                    <p className="chat-subheading text-white/40 font-medium uppercase">Group Invitation</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleRespond(chat._id, 'accepted')}
                    className="flex-1 h-9 bg-[#BFF367] text-black text-[10px] font-bold uppercase tracking-widest rounded-[8px] hover:scale-[1.02] active:scale-[0.98] transition-all"
                  >
                    Accept
                  </button>
                  <button 
                    onClick={() => handleRespond(chat._id, 'rejected')}
                    className="flex-1 h-9 bg-white/5 text-white text-[10px] font-bold uppercase tracking-widest rounded-[8px] hover:bg-white/10 transition-all"
                  >
                    Decline
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* All Chats Section */}
        <div className="px-2 py-3 space-y-2.5">
          {chats.filter(chat => !chat.parentCommunity)
            .sort((a, b) => {
              const myId = user?._id || user?.id || user?.userId;
              const aPinned = a.pinnedBy?.includes(myId) ? 1 : 0;
              const bPinned = b.pinnedBy?.includes(myId) ? 1 : 0;
              if (aPinned !== bPinned) return bPinned - aPinned;
              return 0; 
            })
            .map((chat) => {
            const myId = user?._id || user?.id || user?.userId;
            const unreadCount = unreadCounts[chat._id] || 0;
            const isTypingInChat = typingChats[chat._id];
            const isSelected = selectedChatId === chat._id;
            const isPinned = chat.pinnedBy?.includes(myId);
            const latestSenderId = chat.latestMessage?.sender?.user?._id || chat.latestMessage?.sender?.user;
            const latestSenderName = chat.latestMessage?.sender?.user?.name || chat.latestMessage?.sender?.name;
            const isMySentMessage = [myId].includes(latestSenderId) || (latestSenderName && latestSenderName === user?.name);
            const isExpanded = !!expandedCommunities[chat._id];
            const childGroups = chat.isCommunity
              ? chats.filter(c => (c.parentCommunity === chat._id || c.parentCommunity?._id === chat._id) && !c.isCommunity)
              : [];
            const isChildSelected = chat.isCommunity && childGroups.some(c => selectedChatId === c._id);

            return (
              <div key={chat._id} className="relative group/chat">
                <div className="relative">
                  <button
                  onClick={() => {
                    if (chat.isCommunity) {
                      const announcementGroup = chats.find(c => 
                        (c.parentCommunity === chat._id || c.parentCommunity?._id === chat._id) && 
                        (c.isAnnouncementGroup || c.chatName === "Announcements")
                      );
                      if (announcementGroup) {
                        onSelectChat(announcementGroup);
                      } else {
                        onSelectChat(chat);
                      }
                    } else {
                      onSelectChat(chat);
                    }
                  }}
                  className={`w-full flex items-center gap-3 px-3 py-3 rounded-[8px] transition-all ${chat.isCommunity ? 'pr-20' : 'pr-12'} ${ isSelected || (chat.isCommunity && isChildSelected) ? 'bg-[#BFF367]/10 border border-[#BFF367]/20' : 'hover:bg-white/[0.03] border border-transparent' }`}
                >
                  <div className="relative shrink-0">
                    {renderAvatar(chat)}
                    {chat.isCommunity ? (
                      <div className="absolute -bottom-1 -right-1 bg-[#BFF367] text-black text-[6px] px-1 py-0.5 rounded font-bold uppercase">Com</div>
                    ) : chat.isGroupChat ? (
                      <div className="absolute -bottom-1 -right-1 bg-[#BFF367] text-black text-[6px] px-1 py-0.5 rounded font-bold uppercase">Grp</div>
                    ) : null}
                  </div>
                  <div className="flex-1 text-left overflow-hidden min-w-0">
                    <div className="flex justify-between items-center mb-0.5">
                      <div className="flex items-center gap-1.5 min-w-0">
                        <p className={`font-bold truncate text-sm transition-colors ${ isSelected || (chat.isCommunity && isChildSelected) ? 'text-[#BFF367]' : unreadCount > 0 ? 'text-white' : 'text-white/80 group-hover/chat:text-white' }`}>
                          {isPinned && <Pin size={10} className="inline mr-1 text-[#BFF367]" />}
                          {getChatName(chat)}
                        </p>
                      </div>
                      <span className={`text-[10px] font-medium shrink-0 ml-2 ${ unreadCount > 0 ? 'text-[#BFF367]' : 'text-white/20' }`}>
                        {chat.latestMessage ? formatTime(chat.latestMessage.createdAt) : ""}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="flex items-center gap-1 flex-1 min-w-0">
                        {isMySentMessage && !isTypingInChat && (
                          <CheckCheck size={14} className="text-[#BFF367]/40 shrink-0" />
                        )}
                        <p className={`text-xs truncate ${ isTypingInChat ? 'text-[#BFF367] font-medium italic' : isSelected ? 'text-[#BFF367]/60' : unreadCount > 0 ? 'text-white/70 font-medium' : 'text-white/40 group-hover:text-white/60' }`}>
                          {isTypingInChat 
                            ? 'typing...' 
                            : chat.latestMessage 
                              ? chat.latestMessage.content 
                              : chat.isCommunity ? "Community Created" : "No messages yet"
                          }
                        </p>
                      </div>
                      {unreadCount > 0 && (
                        <div className="shrink-0 min-w-[20px] h-5 bg-[#BFF367] text-black text-[10px] font-bold rounded-full flex items-center justify-center px-1.5">
                          {unreadCount > 99 ? '99+' : unreadCount}
                        </div>
                      )}
                    </div>
                  </div>
                </button>
                
                {/* Right Side Controls: Chevron (for Communities) & 3-Dot (always visible) */}
                <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-0.5 z-10">
                  {chat.isCommunity && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setExpandedCommunities(prev => ({
                          ...prev,
                          [chat._id]: !prev[chat._id]
                        }));
                      }}
                      className="text-white/60 hover:text-[#BFF367] w-7 h-7 rounded-full hover:bg-white/10 transition-all flex items-center justify-center"
                      title={isExpanded ? "Collapse" : "Expand"}
                    >
                      <ChevronDown 
                        size={18} 
                        className={`transition-transform duration-200 ${isExpanded ? 'rotate-0' : '-rotate-90'}`} 
                      />
                    </button>
                  )}
                  <button 
                    onClick={(e) => { 
                      e.stopPropagation(); 
                      setActiveMenu(activeMenu === chat._id ? null : chat._id); 
                    }} 
                    className="text-white/45 hover:text-white w-7 h-7 rounded-full hover:bg-white/10 transition-colors flex items-center justify-center"
                  >
                    <MoreVertical size={16} />
                  </button>
                </div>

                {/* Dropdown Menu */}
                {activeMenu === chat._id && (() => {
                  const isGroupAdmin = chat.isGroupChat && chat.groupAdmins?.some(admin => {
                    const adminId = (admin.user?._id || admin.user)?.toString();
                    return adminId === myId;
                  });

                  const creatorId = (chat.createdBy?.user?._id || chat.createdBy?.user || chat.createdBy || chat.createdByUserId || chat.createdByOwnerId)?.toString();
                  const isCreator = creatorId === myId || chat.createdByUserId?.toString() === myId || chat.createdByOwnerId?.toString() === myId;

                  const handleDelete = async () => {
                    setActiveMenu(null);
                    try {
                      await deleteChatMutation(chat._id).unwrap();
                      if (selectedChatId === chat._id) onChatDeleted?.();
                    } catch (err) {
                      console.error("Delete failed:", err);
                      alert(err.data?.message || "Failed to delete");
                    }
                  };

                  const handleExit = async () => {
                    setActiveMenu(null);
                    try {
                      await removeFromGroup({ chatId: chat._id, userId: myId }).unwrap();
                      if (selectedChatId === chat._id) onChatDeleted?.();
                    } catch (err) {
                      console.error("Exit failed:", err);
                      alert(err.data?.message || "Failed to exit");
                    }
                  };

                  return (
                    <div ref={menuRef} className="absolute right-2 top-10 w-44 bg-[#121212] border border-white/5 rounded-[8px] shadow-2xl py-1.5 z-50 animate-scale-up">
                      {/* Pin / Unpin */}
                      <button 
                        onClick={(e) => { e.stopPropagation(); togglePinChat({ chatId: chat._id }); setActiveMenu(null); }}
                        className="w-full px-3 py-2 text-left text-sm text-white/80 hover:bg-white/5 flex items-center gap-2.5 transition-colors"
                      >
                        {isPinned ? <PinOff size={14} /> : <Pin size={14} />}
                        {isPinned ? "Unpin chat" : "Pin chat"}
                      </button>

                      {/* --- 1-on-1 Chat: just Delete --- */}
                      {!chat.isGroupChat && (
                        <button 
                          onClick={(e) => { 
                            e.stopPropagation(); 
                            setActiveMenu(null);
                            openConfirmModal(
                              "Delete Chat",
                              "Are you sure you want to delete this entire conversation?",
                              handleDelete
                            );
                          }}
                          className="w-full px-3 py-2 text-left text-sm text-red-400 hover:bg-red-500/10 flex items-center gap-2.5 transition-colors"
                        >
                          <Trash2 size={14} /> Delete chat
                        </button>
                      )}

                      {/* --- Group (not community): Leave or Delete --- */}
                      {chat.isGroupChat && !chat.isCommunity && (
                        <>
                          {!(isCreator || isGroupAdmin) ? (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                openConfirmModal(
                                  "Leave Group",
                                  "Are you sure you want to leave this group?",
                                  handleExit
                                );
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-red-400 hover:bg-red-500/10 flex items-center gap-2.5 transition-colors font-bold"
                            >
                              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                              Leave group
                            </button>
                          ) : (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                openConfirmModal(
                                  "Delete Group",
                                  "Permanently delete this group and all messages for everyone?",
                                  handleDelete
                                );
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-red-500 font-bold hover:bg-red-500/10 flex items-center gap-2.5 transition-colors"
                            >
                              <Trash2 size={14} /> Delete group
                            </button>
                          )}
                        </>
                      )}

                      {/* --- Community: Exit + Delete --- */}
                      {chat.isCommunity && (
                        <>
                          {isCommunityAdmin(chat) && (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                handleOpenAddGroup(chat._id, e);
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-white/80 hover:bg-[#BFF367] hover:text-black flex items-center gap-2.5 transition-colors font-bold"
                            >
                              <Plus size={14} /> Add group
                            </button>
                          )}
                          {isCommunityAdmin(chat) && (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                handleOpenManageAdmins(chat, e);
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-white/80 hover:bg-[#BFF367] hover:text-black flex items-center gap-2.5 transition-colors font-bold"
                            >
                              <Crown size={14} /> Manage admins
                            </button>
                          )}
                          {!isCreator ? (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                openConfirmModal(
                                  "Leave Community",
                                  "Are you sure you want to leave this community? You will be removed from all its sub-groups as well.",
                                  handleExit
                                );
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-red-400 hover:bg-red-500/10 flex items-center gap-2.5 transition-colors font-bold"
                            >
                              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                              Leave community
                            </button>
                          ) : (
                            <button 
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                setActiveMenu(null);
                                openConfirmModal(
                                  "Delete Community",
                                  "Permanently delete this community and ALL its groups and messages for everyone?",
                                  handleDelete
                                );
                              }}
                              className="w-full px-3 py-2 text-left text-sm text-red-500 font-bold hover:bg-red-500/10 flex items-center gap-2.5 transition-colors"
                            >
                              <Trash2 size={14} /> Delete community
                            </button>
                          )}
                        </>
                      )}
                    </div>
                  );
                })()}
                </div>

                {/* Community Sub-groups Dropdown */}
                {chat.isCommunity && isExpanded && (
                  <div className="pl-4 pr-2 pb-2 mt-1 space-y-1 ml-6 border-l border-white/5 animate-fade-in">
                    {childGroups.map((group) => {
                      const isGroupSelected = selectedChatId === group._id;
                      const isAnnouncement = group.isAnnouncementGroup || group.chatName === "Announcements";
                      const childUnreadCount = unreadCounts[group._id] || 0;
                      
                      return (
                        <button
                          key={group._id}
                          onClick={() => onSelectChat(group)}
                          className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-[8px] transition-all ${ isGroupSelected ? 'bg-[#BFF367]/10 text-[#BFF367] border border-[#BFF367]/20' : 'text-white/60 hover:text-white hover:bg-white/[0.03] border border-transparent' }`}
                        >
                          {isAnnouncement ? (
                            <Megaphone size={13} className="text-[#BFF367] shrink-0" />
                          ) : (
                            <Users size={13} className="text-white/40 shrink-0" />
                          )}
                          <span className="text-xs font-bold truncate flex-1 text-left">
                            {group.chatName}
                          </span>
                          {childUnreadCount > 0 && (
                            <div className="shrink-0 min-w-[16px] h-4 bg-[#BFF367] text-black text-[9px] font-bold rounded-full flex items-center justify-center px-1">
                              {childUnreadCount}
                            </div>
                          )}
                        </button>
                      );
                    })}
                    {isCommunityAdmin(chat) && (
                      <button
                        onClick={(e) => handleOpenAddGroup(chat._id, e)}
                        className="w-full flex items-center gap-2 px-3 py-2 rounded-[8px] border border-dashed border-white/5 hover:border-[#BFF367]/30 hover:bg-[#BFF367]/5 text-white/40 hover:text-[#BFF367] transition-all text-xs font-bold mt-1"
                      >
                        <Plus size={14} className="shrink-0" />
                        <span>Add more group</span>
                      </button>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
      
      {/* Custom Confirmation Modal */}
      <ConfirmModal
        isOpen={confirmModalConfig.isOpen}
        onClose={() => setConfirmModalConfig(prev => ({ ...prev, isOpen: false }))}
        onConfirm={confirmModalConfig.onConfirm}
        title={confirmModalConfig.title}
        message={confirmModalConfig.message}
        confirmText="Delete"
        cancelText="Cancel"
        isDestructive={true}
      />
      <AddGroupToCommunityModal
        isOpen={isAddGroupModalOpen}
        onClose={() => {
          setIsAddGroupModalOpen(false);
          setSelectedCommunityId(null);
        }}
        communityId={selectedCommunityId}
      />
      <ManageCommunityAdminsModal
        isOpen={isManageAdminsOpen}
        onClose={() => {
          setIsManageAdminsOpen(false);
          setSelectedCommunityForAdmins(null);
        }}
        community={selectedCommunityForAdmins}
        allChats={chats}
      />
    </div>
  );
};

export default ChatSidebar;

import React, { useState, useEffect, useRef } from 'react';
import { useGetMessagesQuery, useSendMessageMutation, useMarkMessagesReadMutation, useRemoveFromGroupMutation, useDeleteMessagesMutation, useDeleteChatMutation, useGetChatsQuery, transformMessage } from '@redux/api/chatApi';
import { useSocket } from '@context/SocketContext';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import GroupInfoModal from './GroupInfoModal';
import { Plus, Users, MessageSquare, Globe } from 'lucide-react';
import AddGroupToCommunityModal from './AddGroupToCommunityModal';

const ChatWindow = ({ chat, onBack, onSelectChat }) => {
 const { user } = useSelector((state) => state.auth);
 const { socket, isUserOnline, getLastSeen } = useSocket();
 const navigate = useNavigate();
 const [message, setMessage] = useState('');
 const [messages, setMessages] = useState([]);
 const [isTyping, setIsTyping] = useState(false);
 const [showTypingIndicator, setShowTypingIndicator] = useState(false);
 const [isGroupInfoOpen, setIsGroupInfoOpen] = useState(false);
 const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 const [isSearchOpen, setIsSearchOpen] = useState(false);
 const [messageSearchQuery, setMessageSearchQuery] = useState("");
 const [isSelectionMode, setIsSelectionMode] = useState(false);
 const [selectedMessages, setSelectedMessages] = useState([]);
 const [showDeleteOptions, setShowDeleteOptions] = useState(false);
 const [isAddGroupToCommunityOpen, setIsAddGroupToCommunityOpen] = useState(false);
 const scrollRef = useRef();
 const typingTimeoutRef = useRef(null);
 const dropdownRef = useRef(null);

 const [removeFromGroup] = useRemoveFromGroupMutation();
 const [deleteMessages] = useDeleteMessagesMutation();
 const [deleteChatMutation] = useDeleteChatMutation();
 const { data: chatData } = useGetChatsQuery();

 const { data, isLoading } = useGetMessagesQuery(chat?._id, {
 skip: !chat?._id
 });
 const [sendMessageMutation] = useSendMessageMutation();
 const [markMessagesReadMutation] = useMarkMessagesReadMutation();

 useEffect(() => {
 if (data) {
 setMessages(data);
 }
 }, [data]);

 // Redirect community view to Announcements page automatically
 useEffect(() => {
   if (chat?.isCommunity && chatData?.chats && onSelectChat) {
     const announcementGroup = chatData.chats.find(c => 
       (c.parentCommunity === chat._id || c.parentCommunity?._id === chat._id) && 
       (c.isAnnouncementGroup || c.chatName === "Announcements")
     );
     if (announcementGroup) {
       onSelectChat(announcementGroup);
     }
   }
 }, [chat, chatData, onSelectChat]);

 useEffect(() => {
 // Close dropdown on outside click
 const handleClickOutside = (event) => {
 if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
 setIsDropdownOpen(false);
 }
 };
 document.addEventListener("mousedown", handleClickOutside);
 return () => document.removeEventListener("mousedown", handleClickOutside);
 }, [chat]);

 // Notify server we've read messages when chat opens or new messages arrive
 useEffect(() => {
 if (socket && chat && messages.length > 0) {
 const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
 // Check if there are any messages not read by me
 const hasUnread = messages.some(m => {
 if (!m.readBy) return true;
 return !m.readBy.some(r => myIds.includes(r.user?._id || r.user));
 });

 if (hasUnread) {
 const myIdToSend = user?._id || user?.id;
 socket.emit('messages read', { chatId: chat._id, userId: myIdToSend });
 markMessagesReadMutation(chat._id).catch(console.error);
 }
 }
 }, [socket, chat?._id, messages, user, markMessagesReadMutation]);

 useEffect(() => {
 if (socket && chat) {
 socket.emit('join chat', chat._id);

    const handleNewMessage = (newMessage) => {
      const transformed = transformMessage(newMessage);
      const incomingChatId = transformed.chat?._id || transformed.chat?.id || transformed.chat;
      if (chat._id === incomingChatId) {
        setMessages((prev) => {
          if (prev.some(m => m._id === transformed._id)) return prev;
          return [...prev, transformed];
        });
        // Mark as read immediately since chat is open
        socket.emit('messages read', { chatId: chat._id, userId: user?._id || user?.id });
      }
    };

 const handleTyping = (room) => {
 if (room === chat._id) setShowTypingIndicator(true);
 };

 const handleStopTyping = (room) => {
 if (room === chat._id) setShowTypingIndicator(false);
 };

 const handleMessagesRead = ({ chatId, userId }) => {
 if (chatId === chat._id) {
 setMessages((prev) => prev.map(m => {
 // Add to readBy array if not already present
 const readByArray = m.readBy || [];
 const alreadyRead = readByArray.some(r => (r.user?._id || r.user) === userId);
 if (!alreadyRead) {
 return { ...m, readBy: [...readByArray, { user: userId }] };
 }
 return m;
 }));
 }
 };

 socket.on('message recieved', handleNewMessage);
 socket.on('typing', handleTyping);
 socket.on('stop typing', handleStopTyping);
 socket.on('messages read', handleMessagesRead);

 return () => {
 socket.off('message recieved', handleNewMessage);
 socket.off('typing', handleTyping);
 socket.off('stop typing', handleStopTyping);
 socket.off('messages read', handleMessagesRead);
 };
 }
 }, [socket, chat]);

  useEffect(() => {
    if (scrollRef.current && scrollRef.current.parentElement) {
      const parent = scrollRef.current.parentElement;
      // Use scrollTo instead of scrollIntoView to prevent entire page shifting
      parent.scrollTo({ top: parent.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, showTypingIndicator]);

 const handleSendMessage = async (e) => {
 e.preventDefault();
 if (!message.trim()) return;

 socket.emit('stop typing', chat._id);
 setIsTyping(false);
 if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);

 const messageContent = message;
 setMessage('');

 const tempId = `temp-${Date.now()}`;
 const optimisticMsg = {
   _id: tempId,
   id: tempId,
   content: messageContent,
   createdAt: new Date().toISOString(),
   sender: user,
   isOptimistic: true,
   chat: chat._id
 };

 setMessages((prev) => [...prev, optimisticMsg]);

 try {
 const data = await sendMessageMutation({
 chatId: chat._id,
 content: messageContent
 }).unwrap();

 setMessages((prev) => prev.map(m => m._id === tempId ? data : m));
 } catch (err) {
 console.error("Failed to send message:", err);
 setMessages((prev) => prev.filter(m => m._id !== tempId));
 }
 };

 const typingHandler = (e) => {
 setMessage(e.target.value);

 if (!socket) return;

 if (!isTyping) {
 setIsTyping(true);
 socket.emit('typing', chat._id);
 }

 if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);

 typingTimeoutRef.current = setTimeout(() => {
 socket.emit('stop typing', chat._id);
 setIsTyping(false);
 }, 1200);
 };

 const getChatOtherUser = () => {
 if (!chat || chat.isGroupChat) return null;
 // Match by _id, handling Owner/User polymorphism
 const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
 return chat.users?.find((u) => {
 const uid = u.user?._id || u.user;
 return !myIds.includes(uid);
 })?.user;
 };

 // Get "my" user entry from the chat to extract my ID in the chat context
 const getMyUserEntry = () => {
 if (!chat) return null;
 const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
 // First try matching by any of my IDs
 const byId = chat.users?.find((u) => {
 const uid = u.user?._id || u.user;
 return myIds.includes(uid);
 });
 if (byId) return byId;
 // Fallback: match by name (for Owner/User cross-model)
 return chat.users?.find((u) => u.user?.name === user?.name);
 };

  const getChatName = () => {
    if (chat.isGroupChat) return chat.chatName || (chat.isAnnouncementGroup ? "Announcements" : "Unnamed Group");
    const otherUser = getChatOtherUser();
    return otherUser?.name || "Unknown User";
  };

 // Format last seen
 // Format status text (online/last seen)
  const getStatusText = () => {
    if (chat.isGroupChat) return `${chat.users?.length || 0} members`;

 const otherUser = getChatOtherUser();
 const otherId = otherUser?._id;
 if (!otherId) return "";

 if (isUserOnline(otherId)) return "online";

 // Try socket state first, then fallback to DB value
 const lastSeen = getLastSeen(otherId) || otherUser?.lastSeen;
 if (lastSeen) {
 const date = new Date(lastSeen);
 const now = new Date();
 
 const isToday = date.toDateString() === now.toDateString();
 const yesterday = new Date(now);
 yesterday.setDate(yesterday.getDate() - 1);
 const isYesterday = date.toDateString() === yesterday.toDateString();

 const timeStr = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

 if (isToday) return `last seen today at ${timeStr}`;
 if (isYesterday) return `last seen yesterday at ${timeStr}`;
 
 return `last seen ${date.toLocaleDateString([], { day: 'numeric', month: 'short' })} at ${timeStr}`;
 }

 return "offline";
 };

 // Group messages by date
 const getDateLabel = (dateStr) => {
 const date = new Date(dateStr);
 const today = new Date();
 const yesterday = new Date(today);
 yesterday.setDate(yesterday.getDate() - 1);

 if (date.toDateString() === today.toDateString()) return "Today";
 if (date.toDateString() === yesterday.toDateString()) return "Yesterday";
 return date.toLocaleDateString([], { day: 'numeric', month: 'short', year: 'numeric' });
 };

 // Determine sender ID from message object (handles nested and flat sender shapes)
 const getSenderId = (m) => {
 return m.sender?.user?._id || m.sender?.user || m.sender?._id || m.sender;
 };

 // Check if a message was sent by the current user
 const checkIsMine = (m) => {
 const senderId = getSenderId(m);
 const myIds = [user?._id, user?.id, user?.userId].filter(Boolean);
 // Direct ID match against any of my IDs
 if (myIds.includes(senderId)) return true;
 // Cross-model match: check if sender ID matches my chat entry
 const myEntry = getMyUserEntry();
 const myEntryId = myEntry?.user?._id || myEntry?.user;
 if (myEntryId && senderId === myEntryId) return true;
 // Name-based fallback for edge cases
 const senderName = m.sender?.user?.name || m.sender?.name;
 if (senderName && senderName === user?.name) return true;
 return false;
 };

 if (!chat) {
 return (
 <div className="flex-1 flex flex-col items-center justify-center bg-[#0A0A0A] text-white/40">
 <div className="w-20 h-20 rounded-full bg-white/[0.03] border border-white/5 flex items-center justify-center mb-6">
 <svg className="w-10 h-10 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
 </svg>
 </div>
 <p className="chat-heading text-sm font-bold uppercase text-white/20">Select a conversation</p>
 <p className="chat-subheading text-white/10 mt-1">to start chatting</p>
 </div>
 );
 }

 const otherUserObj = getChatOtherUser();
 const imageUrl = otherUserObj?.profilePicture || otherUserObj?.profileImage;
 const otherOnline = otherUserObj?._id ? isUserOnline(otherUserObj._id) : false;

 return (
 <div className="flex-1 flex flex-col h-full bg-[#0A0A0A] relative">
 {/* Header */}
 <div className="px-4 py-3 border-b border-white/5 flex items-center gap-3 bg-[#0A0A0A] backdrop-blur-md sticky top-0 z-10">
 <button 
 onClick={onBack}
 className="md:hidden p-2 -ml-2 text-white/60 hover:text-white transition-colors"
 >
 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
 </svg>
 </button>

 {/* Avatar with online dot - clickable to profile/group info */}
 <div 
 className="relative shrink-0 cursor-pointer" 
 onClick={() => {
 if (chat.isGroupChat) {
 setIsGroupInfoOpen(true);
 } else if (otherUserObj?._id) {
 navigate(`/profile/${otherUserObj._id}`);
 }
 }}
 >
 <div className="w-10 h-10 rounded-full border border-white/20 overflow-hidden bg-[#BFF367]/10 flex items-center justify-center">
 {chat.isGroupChat ? (
 <svg className="w-5 h-5 text-[#BFF367]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
 </svg>
 ) : (
 <>
 {imageUrl ? (
 <img 
 src={imageUrl} 
 alt={getChatName()}
 className="w-full h-full object-cover"
 onError={(e) => {
 e.target.style.display = 'none';
 if (e.target.nextSibling) e.target.nextSibling.style.display = 'flex';
 }}
 />
 ) : null}
 <div 
 className="w-full h-full flex items-center justify-center"
 style={{ display: imageUrl ? 'none' : 'flex' }}
 >
 <span className="text-[#BFF367] font-bold text-xs">
 {otherUserObj?.name ? otherUserObj.name.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2) : "U"}
 </span>
 </div>
 </>
 )}
 </div>
 {/* Online indicator dot */}
 {!chat.isGroupChat && otherOnline && (
 <div className="absolute -bottom-0.5 -right-0.5 w-3 h-3 bg-green-500 rounded-full border-2 border-black" />
 )}
 </div>

 <div 
 className="flex-1 min-w-0 cursor-pointer" 
 onClick={() => {
 if (chat.isGroupChat) {
 setIsGroupInfoOpen(true);
 } else if (otherUserObj?._id) {
 navigate(`/profile/${otherUserObj._id}`);
 }
 }}
 >
 <h3 className="text-white font-bold text-sm truncate hover:underline">{getChatName()}</h3>
 <p className={`text-[11px] transition-colors ${ showTypingIndicator ? 'text-[#BFF367] font-medium' : otherOnline ? 'text-green-400' : 'text-white/40' }`}>
 {showTypingIndicator ? 'typing...' : getStatusText()}
 </p>
 </div>

 {/* Header Actions (Search & Three Dots Dropdown) */}
 <div className="flex items-center gap-2 relative" ref={dropdownRef}>
 {chat.isCommunity && !isSelectionMode && (
 <button 
 onClick={() => setIsAddGroupToCommunityOpen(true)}
 className="flex items-center gap-2 px-3 py-1.5 bg-[#BFF367]/10 text-[#BFF367] hover:bg-[#BFF367] hover:text-black rounded-[6px] transition-all text-[11px] font-bold uppercase tracking-wider shadow-sm"
 >
 <Plus size={14} />
 <span>Add Group</span>
 </button>
 )}
 {!isSelectionMode && (
 <button 
 onClick={() => {
 setIsSearchOpen(!isSearchOpen);
 if (isSearchOpen) setMessageSearchQuery("");
 }}
 className={`p-2 transition-colors rounded-full ${isSearchOpen ? 'bg-white/[0.1] text-white' : 'text-white/60 hover:text-white hover:bg-white/[0.05]'}`}
 >
 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
 </svg>
 </button>
 )}
 <button 
 onClick={() => setIsDropdownOpen(!isDropdownOpen)}
 className={`p-2 transition-colors rounded-full ${isDropdownOpen ? 'bg-white/[0.1] text-white' : 'text-white/60 hover:text-white hover:bg-white/[0.05]'}`}
 >
 <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
 <path d="M12 7a2 2 0 1 0-.001-4.001A2 2 0 0 0 12 7zm0 2a2 2 0 1 0-.001 3.999A2 2 0 0 0 12 9zm0 6a2 2 0 1 0-.001 3.999A2 2 0 0 0 12 15z" />
 </svg>
 </button>

 {/* Dropdown Menu */}
 {isDropdownOpen && (
 <div className="absolute top-12 right-0 w-48 bg-[#121212] border border-white/5 rounded-[8px] shadow-xl py-2 z-50 animate-fade-in">
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 if (chat.isGroupChat || chat.isCommunity) setIsGroupInfoOpen(true);
 else if (otherUserObj?._id) navigate(`/profile/${otherUserObj._id}`);
 }}
 className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/[0.05] hover:text-white transition-colors"
 >
 {chat.isCommunity ? 'Community info' : chat.isGroupChat ? 'Group info' : 'Contact info'}
 </button>
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 setIsSearchOpen(true);
 }}
 className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/[0.05] hover:text-white transition-colors"
 >
 Search
 </button>
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 setIsSelectionMode(true);
 setSelectedMessages([]);
 }}
 className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/[0.05] hover:text-white transition-colors"
 >
 Select messages
 </button>
 {chat.isCommunity && (
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 setIsAddGroupToCommunityOpen(true);
 }}
 className="w-full text-left px-4 py-2 text-sm text-[#BFF367] hover:bg-white/[0.05] transition-colors"
 >
 Add group to community
 </button>
 )}
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 onBack();
 }}
 className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/[0.05] hover:text-white transition-colors"
 >
 Close chat
 </button>
 <button 
 onClick={() => {
 setIsDropdownOpen(false);
 alert("Clear chat functionality coming soon!");
 }}
 className="w-full text-left px-4 py-2 text-sm text-white/80 hover:bg-white/[0.05] hover:text-white transition-colors"
 >
 Clear chat
 </button>
 {chat.isCommunity && (
 <>
 <button 
 onClick={async () => {
 setIsDropdownOpen(false);
 if (window.confirm("Are you sure you want to exit this community? This will remove you from all community groups.")) {
 try {
 const myId = user?._id || user?.id || user?.userId;
 await removeFromGroup({ chatId: chat._id, userId: myId }).unwrap();
 onBack();
 } catch (err) {
 console.error("Failed to exit community", err);
 }
 }
 }}
 className="w-full text-left px-4 py-2 text-sm text-red-400 hover:bg-white/[0.05] transition-colors"
 >
 Exit community
 </button>
 {(() => {
 const myId = (user?._id || user?.id || user?.userId)?.toString();
 const isAdmin = chat.groupAdmins?.some(admin => {
   const adminId = (admin.user?._id || admin.user)?.toString();
   return adminId === myId;
 });
 
 return isAdmin && (
 <button 
 onClick={async () => {
 setIsDropdownOpen(false);
 if (window.confirm("Are you sure you want to PERMANENTLY delete this community? All child groups and messages will be removed.")) {
 try {
 await deleteChatMutation(chat._id).unwrap();
 onBack();
 } catch (err) {
 console.error("Failed to delete community", err);
 alert("Failed to delete community: " + (err.data?.message || err.error));
 }
 }
 }}
 className="w-full text-left px-4 py-2 text-sm text-red-600 font-bold hover:bg-white/[0.05] transition-colors"
 >
 Delete community
 </button>
 );
 })()}
 </>
 )}
 {chat.isGroupChat && !chat.isCommunity && (
 <button 
 onClick={async () => {
 setIsDropdownOpen(false);
 if (window.confirm("Are you sure you want to leave this group?")) {
 try {
 const myId = user?._id || user?.id || user?.userId;
 await removeFromGroup({ chatId: chat._id, userId: myId }).unwrap();
 onBack();
 } catch (err) {
 console.error("Failed to leave group", err);
 }
 }
 }}
 className="w-full text-left px-4 py-2 text-sm text-red-500 hover:bg-white/[0.05] transition-colors"
 >
 Exit group
 </button>
 )}
 </div>
 )}
 </div>
