              <div className="p-8 lg:p-10">
                <div className="flex flex-col md:flex-row justify-between gap-8">
                  <div className="flex gap-6">
                    <div className="relative">
                      <img 
                        src={booking.user?.profilePicture || "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=200&q=80"} 
                        className="w-16 h-16 rounded-[8px] object-cover border border-white/5"
                        alt={booking.user?.name}
                      />
                      <div className="absolute -bottom-2 -right-2 w-7 h-7 rounded-lg flex items-center justify-center shadow-lg" style={{ backgroundColor: themeColor }}>
                        <User size={14} className="text-black" />
                      </div>
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-white tracking-tight font-inter uppercase mb-1.5">{booking.user?.name}</h3>
                      <div className="flex flex-wrap gap-5">
                        <span className="flex items-center gap-2 text-[10px] font-black text-neutral-500 uppercase tracking-widest font-inter"><Phone size={12} style={{ color: themeColor }} /> {booking.user?.phone}</span>
                        <span className="flex items-center gap-2 text-[10px] font-black text-neutral-500 uppercase tracking-widest font-inter"><Mail size={12} style={{ color: themeColor }} /> {booking.user?.email}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col md:items-end gap-3">
                    <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border font-inter ${ booking.status === 'PENDING' ? 'bg-orange-500/10 border-orange-500/20 text-orange-500' : booking.status === 'ACCEPTED' ? 'bg-[#BFF367]/10 border-[#BFF367]/20' : 'bg-red-500/10 border-red-500/20 text-red-500' }`}
                    style={{ 
                      color: booking.status === 'ACCEPTED' ? themeColor : undefined,
                      borderColor: booking.status === 'ACCEPTED' ? themeColor : undefined 
                    }}>
                      {booking.status === 'ACCEPTED' ? 'SCHEDULED' : booking.status}
                    </div>
                    <p className="text-3xl font-black text-white mt-2 font-inter tracking-tighter">Γé╣{Number(booking.totalAmount).toLocaleString()}</p>
                  </div>
                </div>

                <div className="mt-10 pt-10 border-t border-white/5 grid grid-cols-1 md:grid-cols-3 gap-10">
                  <div className="space-y-5">
                    <p className="text-[10px] font-black text-neutral-500 uppercase tracking-widest font-inter">Match Schedule</p>
                    <div className="flex items-center gap-5">
                      <div className="w-14 h-14 rounded-lg bg-white/[0.05] flex flex-col items-center justify-center border border-white/10 text-center shadow-inner">
                        <span className="text-[9px] font-black uppercase font-inter" style={{ color: themeColor }}>{format(new Date(booking.date), 'MMM')}</span>
                        <span className="text-xl font-black text-white leading-none font-inter mt-0.5">{format(new Date(booking.date), 'dd')}</span>
                      </div>
                      <div>
                        <p className="text-sm font-black text-white font-inter tracking-tight uppercase">
                          {booking.slots.map(s => s.startTime).join(", ")}
                        </p>
                        <p className="text-[9px] font-black text-neutral-500 uppercase tracking-widest font-inter mt-1">{booking.bookingType} Portal</p>
                      </div>
                    </div>
                  </div>

                  <div className="space-y-5 md:col-span-2">
                    <p className="text-[10px] font-black text-neutral-500 uppercase tracking-widest font-inter">Match Brief</p>
                    <div className="p-5 bg-white/[0.05] border border-white/10 rounded-[8px] text-[13px] text-neutral-400 italic font-inter leading-relaxed">
                      "{booking.message || "Standard match scoring and management assignment."}"
                    </div>
                  </div>
                </div>

                {booking.status === 'PENDING' && (
                  <div className="mt-10 flex gap-4">
                    <button 
                      onClick={() => handleAction(booking._id, 'ACCEPTED')}
                      disabled={actionLoading === booking._id}
                      className="flex-1 h-14 text-black rounded-lg font-black uppercase text-[12px] tracking-[0.2em] transition-all transform active:scale-95 flex items-center justify-center gap-3 font-inter shadow-xl"
                      style={{ backgroundColor: themeColor, boxShadow: `0 10px 30px ${themeColor}33` }}
                    >
                      {actionLoading === booking._id ? <Loader2 className="animate-spin" size={20} /> : <Check size={20} />} Confirm Slot
                    </button>
                    <button 
                      onClick={() => handleAction(booking._id, 'REJECTED')}
                      disabled={actionLoading === booking._id}
                      className="flex-1 h-14 bg-white/5 text-neutral-500 hover:text-white border border-white/10 rounded-[8px] font-black uppercase text-[12px] tracking-[0.2em] hover:bg-red-500/10 hover:border-red-500/30 hover:text-red-500 transition-all transform active:scale-95 flex items-center justify-center gap-3 font-inter"
                    >
                      {actionLoading === booking._id ? <Loader2 className="animate-spin" size={20} /> : <X size={20} />} Decline
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

﻿import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import axiosInstance from "@hooks/useAxiosInstance";
import { Star, MessageSquare, Send, Loader2, Reply, X, BadgeCheck } from "lucide-react";
import toast from "react-hot-toast";
import { format } from "date-fns";
import { useNavigate } from "react-router-dom";

/**
 * ProfessionalReviews ΓÇö High-fidelity feedback management.
 * Fully rebranded for the Scorer Portal with Teal Green (#BFF367) and Inter font.
 */

export default function ProfessionalReviews() {
  const { role, user: authUser } = useSelector((state) => state.auth);
  const isScorer = role?.toLowerCase().includes("scorer");
  const themeColor = isScorer ? "#BFF367" : "#BFF367";

  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [replyText, setReplyText] = useState("");
  const [replyingTo, setReplyingTo] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchReviews();
  }, []);

  const fetchReviews = async () => {
    try {
      setLoading(true);
      const profId = authUser?._id || authUser?.id || authUser?.user;
      if (!profId) return;
      const res = await axiosInstance.get(`/api/professional/details/${profId}?date=${format(new Date(), 'yyyy-MM-dd')}`);
      setReviews(res.data.reviews || []);
    } catch (error) {
      console.error("Error fetching reviews:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleReply = async (reviewId) => {
    if (!replyText.trim()) return;
    try {
      setActionLoading(true);
      await axiosInstance.post("/api/professional/review/reply", { reviewId, reply: replyText });
      toast.success("Response dispatched to client", {
        style: { background: "#000", color: "#fff", border: `1px solid ${themeColor}`, fontSize: "10px", fontWeight: "black" }
      });
      setReplyText("");
      setReplyingTo(null);
      fetchReviews();
    } catch (error) {
      toast.error("Dispatch failed");
    } finally {
      setActionLoading(false);
    }
  };

  if (loading) return (
    <div className="py-24 flex justify-center"><Loader2 className="animate-spin" style={{ color: themeColor }} size={48} /></div>
  );

  return (
    <div className="space-y-10 animate-fade-in font-inter h-full custom-scrollbar pb-32">
      <div className="pb-8 border-b border-white/5 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
            <h1 className="text-4xl lg:text-6xl font-black tracking-tighter text-white font-inter uppercase">
            User <span style={{ color: themeColor }}>FEEDBACK</span>
            </h1>
            <p className="text-neutral-500 text-[10px] font-black uppercase tracking-[0.3em] font-inter mt-2">Engage with verified clients and maintain your professional standing</p>
        </div>
        <div className="px-6 py-3 bg-white/[0.02] border border-white/5 rounded-[8px] flex items-center gap-4">
            <div className="w-10 h-10 rounded-[8px] bg-white/5 flex items-center justify-center border border-white/5">
                <Star size={20} style={{ color: themeColor, fill: themeColor }} />
            </div>
            <div>
                <p className="text-[14px] font-black text-white leading-none">
                    {(reviews.reduce((acc, curr) => acc + curr.rating, 0) / (reviews.length || 1)).toFixed(1)}
                </p>
                <p className="text-[8px] font-black text-neutral-600 uppercase tracking-widest mt-1">Average Index</p>
            </div>
        </div>
      </div>

      {reviews.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-32 bg-black rounded-[8px] border-2 border-white/5 border-dashed p-12 text-center shadow-2xl relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-b from-[#BFF367]/5 to-transparent opacity-50" />
          <MessageSquare size={64} className="text-neutral-900 mb-6 relative z-10" />
          <h3 className="text-[12px] font-black text-neutral-700 uppercase tracking-[0.4em] font-inter mb-2 relative z-10">Feedback Vault Empty</h3>
          <p className="text-[11px] text-neutral-800 font-inter relative z-10 max-w-xs mx-auto">Client appraisals and performance metrics will be archived here upon receipt.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8">
          {reviews.map((review) => (
            <div key={review._id} className="bg-black border border-white/5 rounded-[8px] overflow-hidden group hover:border-[#BFF367]/20 transition-all duration-500 shadow-2xl relative">
              <div className="absolute top-0 right-0 w-32 h-32 bg-[#BFF367]/5 blur-3xl pointer-events-none" />
              <div className="p-8 lg:p-10 relative z-10">
                <div className="flex flex-col md:flex-row justify-between items-start mb-10 gap-6">
                  <div className="flex gap-5">
                    <div 
                      onClick={() => review.user?._id && navigate(`/profile/${review.user._id}`)}
                      className="w-16 h-16 rounded-[8px] border border-white/5 overflow-hidden cursor-pointer hover:border-[#BFF367]/50 transition-all shadow-xl group-hover:scale-105"
                    >
                      {review.user?.profilePicture ? (
                        <img src={review.user.profilePicture} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full bg-white/5 flex items-center justify-center text-[18px] font-black text-neutral-500 font-inter uppercase">
                          {review.user?.name?.charAt(0)}
                        </div>
                      )}
                    </div>
                    <div>
                      <h4 
                        onClick={() => review.user?._id && navigate(`/profile/${review.user._id}`)}
                        className="text-[18px] font-black text-white tracking-tight cursor-pointer hover:opacity-80 transition-opacity font-inter uppercase"
                        style={{ '--hover-color': themeColor }}
                      >
                        {review.user?.name}
                      </h4>
                      <div className="flex items-center gap-3 mt-2">
                         <div className="flex items-center gap-1.5 px-3 py-1 bg-[#BFF367]/10 rounded-[6px] border border-[#BFF367]/20">
                            <BadgeCheck size={12} style={{ color: themeColor }} />
                            <p className="text-[9px] font-black uppercase tracking-[0.1em] font-inter" style={{ color: themeColor }}>Verified Client</p>
                         </div>
                         <p className="text-[10px] font-black text-neutral-600 uppercase tracking-widest font-inter">{format(new Date(review.createdAt), 'MMM dd, yyyy')}</p>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 bg-white/[0.02] p-3 rounded-[8px] border border-white/5">
                    {[...Array(5)].map((_, i) => (
                      <Star key={i} size={18} className={i < review.rating ? "" : "text-neutral-800"} 
                            style={{ color: i < review.rating ? themeColor : undefined, fill: i < review.rating ? themeColor : "none" }} />
                    ))}
                  </div>
                </div>

                <div className="relative p-8 bg-white/[0.02] border border-white/5 rounded-[8px] mb-10 group-hover:border-[#BFF367]/10 transition-all">
                   <p className="text-[15px] text-neutral-400 font-inter leading-relaxed italic">"{review.comment}"</p>
                </div>

                {review.reply ? (
                  <div className="ml-6 md:ml-12 p-8 bg-white/[0.03] border-l-4 rounded-r-[2rem] shadow-inner" style={{ borderLeftColor: themeColor }}>
                    <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-3 flex items-center gap-3 font-inter" style={{ color: themeColor }}>
                      <Reply size={14} /> Official Response
                    </p>
                    <p className="text-[14px] text-neutral-300 font-inter leading-relaxed">"{review.reply}"</p>
                  </div>
                ) : replyingTo === review._id ? (
                  <div className="ml-6 md:ml-12 space-y-6 animate-in slide-in-from-top-4 duration-300 relative z-20">
                    <div className="relative">
                        <textarea 
                        placeholder="Draft your official response..."
                        className="w-full bg-white/[0.03] border border-white/5 rounded-[8px] p-6 text-[14px] text-white focus:border-[#BFF367]/50 outline-none h-32 resize-none font-inter font-medium transition-all"
                        value={replyText}
                        onChange={(e) => setReplyText(e.target.value)}
                        />
                        <button 
                            onClick={() => setReplyingTo(null)}
                            className="absolute top-4 right-4 p-2 text-neutral-600 hover:text-white transition-colors"
                        >
                            <X size={18} />
                        </button>
                    </div>
                    <div className="flex gap-4">
                      <button 
                        onClick={() => handleReply(review._id)}
                        disabled={actionLoading}
                        className="flex-[2] h-14 text-black rounded-[8px] font-black uppercase text-[11px] tracking-[0.2em] flex items-center justify-center gap-3 transition-all active:scale-95 shadow-2xl"
                        style={{ backgroundColor: themeColor, boxShadow: `0 10px 25px ${themeColor}33` }}
                      >
                        {actionLoading ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />} Dispatch Response
                      </button>
                      <button 
                        onClick={() => setReplyingTo(null)}
                        className="flex-1 h-14 bg-white/5 text-neutral-500 border border-white/5 rounded-[8px] font-black uppercase text-[11px] tracking-[0.2em] hover:bg-white/10 hover:text-white transition-all"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <button 
                    onClick={() => setReplyingTo(review._id)}
                    className="ml-6 md:ml-12 px-6 py-3 bg-white/[0.03] border border-white/5 rounded-[8px] text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-3 hover:bg-[#BFF367]/10 hover:border-[#BFF367]/30 transition-all font-inter"
                    style={{ color: themeColor }}
                  >
                    <MessageSquare size={16} /> Lodge Official Reply
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { X, Image as ImageIcon, Camera, Loader2, Send, ChevronDown, Globe, ShieldCheck } from "lucide-react";
import { motion } from "framer-motion";
import { useCreatePostMutation, useUpdatePostMutation } from "@redux/api/communityApi";
import { startUpload } from "@redux/slices/mediaUploadSlice";
import toast from "react-hot-toast";
import { useLazyGetCommunityUploadUrlQuery, useConfirmCommunityPostMutation } from "@redux/api/communityApi";
import { uploadFileToR2 } from '@utils/mediaUpload';
import GlobalBackButton from '@/shared/components/GlobalBackButton';

const HEADING_STYLE = { fontFamily: "'Open Sans', sans-serif" };
const SUBHEADING_STYLE = { fontFamily: "'Inter 28pt Light', sans-serif", fontWeight: 300 };

const CreatePostPage = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useSelector((state) => state.auth);
  
  const [createPost] = useCreatePostMutation();
  const [updatePost] = useUpdatePostMutation();

  const editingPost = location.state?.editingPost || null;
  const preSelectedFile = location.state?.preSelectedFile || null;

  const [getCommunityUploadUrl] = useLazyGetCommunityUploadUrlQuery();
  const [confirmCommunityPost] = useConfirmCommunityPostMutation();

  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [sport, setSport] = useState("");
  const [mediaFiles, setMediaFiles] = useState([]);
  const [mediaPreviews, setMediaPreviews] = useState([]);
  const [isPublishing, setIsPublishing] = useState(false);

  useEffect(() => {
    if (editingPost) {
      setTitle(editingPost.title || "");
      setContent(editingPost.content || "");
      setSport(editingPost.sport || "");
      setImage(null);
      setImagePreview(editingPost.image || editingPost.imageUrl || editingPost.mediaUrl || null);
    } else {
      setTitle("");
      setContent("");
      setSport("");
      setMediaFiles([]);
      setMediaPreviews([]);
      
      const preSelectedFiles = location.state?.preSelectedFiles;
      
      if (preSelectedFiles && preSelectedFiles.length > 0) {
        const validFiles = preSelectedFiles.slice(0, 10); // Limit to 10
        setMediaFiles(validFiles);
        setMediaPreviews(validFiles.map(f => URL.createObjectURL(f)));
      } else if (preSelectedFile) {
        setMediaFiles([preSelectedFile]);
        setMediaPreviews([URL.createObjectURL(preSelectedFile)]);
      }
    }
  }, [editingPost, preSelectedFile]);

  const handlePostImageChange = (e) => {
    const files = Array.from(e.target.files);
    if (files.length === 0) return;

    if (files.some(file => file.type.startsWith('video'))) {
      toast.error("Only photos are allowed for posts", { id: "post-type-error" });
      e.target.value = '';
      return;
    }

    if (mediaFiles.length + files.length > 10) {
      toast.error("Maximum 10 images allowed", { id: "post-count-error" });
      e.target.value = '';
      return;
    }

    setMediaFiles(prev => [...prev, ...files]);
    setMediaPreviews(prev => [...prev, ...files.map(f => URL.createObjectURL(f))]);
    
    e.target.value = '';
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!content.trim() && mediaFiles.length === 0) {
      return toast.error("Content or image is required");
    }

    setIsPublishing(true);
    try {
      if (editingPost && !editingPost.isPrefill) {
        const formData = new FormData();
        if (title) formData.append("title", title);
        if (content) formData.append("content", content);
        await updatePost({ postId: editingPost._id || editingPost.id, formData }).unwrap();
        toast.success("Post updated!");
        navigate('/community', { state: { scrollToTop: true } });
      } else {
        if (mediaFiles.length === 1 && !content.trim()) {
          // Use Flash Upload (Backgrounding) for single media without content
          dispatch(
            startUpload({
              id: Date.now().toString(),
              file: mediaFiles[0],
              previewUrl: mediaPreviews[0],
              metadata: {
                type: "community",
                title,
                content: content || "",
                sport: sport || "",
              },
            })
          );
          toast.success("Uploading post in background...");
          navigate('/community', { state: { scrollToTop: true } });
          return;
        } 
        
        if (mediaFiles.length > 0) {
          // Foreground upload for multiple files or single file with content
          const mediaItems = [];
          for (const file of mediaFiles) {
            const { data: uploadData } = await getCommunityUploadUrl({
              contentType: file.type,
              fileName: file.name,
            });
            await uploadFileToR2(uploadData.uploadUrl, file);
            mediaItems.push({
              key: uploadData.key,
              mediaType: "image",
            });
          }
          await confirmCommunityPost({
            postId: Date.now().toString(),
            title,
            content,
            sport,
            mediaItems
          }).unwrap();
          toast.success("Post created!");
        } else {
          // Plain text post
          const formData = new FormData();
          formData.append("title", title);
          formData.append("content", content);
          if (sport) formData.append("sport", sport);
          await createPost(formData).unwrap();
          toast.success("Post created!");
        }
        navigate('/community', { state: { scrollToTop: true } });
      }
    } catch (error) {
      toast.error(error?.data?.message || error.message || "Failed to save post");
    } finally {
      setIsPublishing(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] w-full min-h-[100dvh] bg-black/95 flex items-center justify-center md:p-6 overflow-hidden">
      <div className="w-full h-[100dvh] md:h-full md:max-h-[800px] md:max-w-[500px] bg-[#050505] md:rounded-[32px] md:border md:border-white/10 shadow-2xl flex flex-col font-sans overflow-hidden relative">
      <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-[#BFF367]/10 to-transparent pointer-events-none" />

      {/* Header */}
      <div className="relative px-5 py-4 border-b border-white/5 flex items-center justify-between gap-4 bg-black/40 backdrop-blur-md z-10">
        <div className="flex items-center gap-3">
          <GlobalBackButton />
          <div>
            <h3 className="font-black text-lg text-white tracking-wide uppercase" style={HEADING_STYLE}>
              {editingPost ? "Edit Post" : "Create Post"}
            </h3>
            <p className="text-xs text-neutral-500 font-medium tracking-tight mt-0.5" style={SUBHEADING_STYLE}>
              Share something with the community
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {!editingPost && (
            <div className="relative">
              <select
                className="border border-transparent rounded-[8px] py-2 pl-3 pr-8 text-black text-xs font-bold focus:outline-none transition-all appearance-none cursor-pointer bg-[#BFF367]"
                style={{
                  fontFamily: "'Inter', sans-serif",
                }}
                value={sport}
                onChange={(e) => setSport(e.target.value)}
              >
                <option value="" className="bg-neutral-950 text-white">All Sports</option>
                {["Cricket", "Football", "Rugby", "Baseball", "Hockey", "Athletics"].map((s) => (
                  <option key={s} value={s.toUpperCase()} className="bg-neutral-950 text-white">
                    {s}
                  </option>
                ))}
              </select>
              <div className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 flex items-center text-black/50">
                <ChevronDown size={14} />
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-3 px-5 pt-6 pb-2 relative z-10">
        <img
          src={user?.profilePicture || "/default-avatar.png"}
          className="w-10 h-10 rounded-full object-cover border border-white/10 bg-neutral-900"
          alt=""
        />
        <div>
          <span className="text-sm font-bold text-white block tracking-wide" style={SUBHEADING_STYLE}>
            {user?.username || user?.name || "Player"}
          </span>
          <div className="flex items-center gap-1 text-[10px] font-bold text-[#BFF367] uppercase tracking-wider mt-1" style={SUBHEADING_STYLE}>
            <Globe size={12} />
            <span>Posting publicly</span>
          </div>
        </div>
      </div>

      <form onSubmit={handleCreatePost} className="relative px-5 pb-5 pt-3 flex flex-col flex-1 min-h-0 z-10 space-y-4">
        
        <div className="relative group/content flex-1 flex flex-col min-h-0 w-full">
          <textarea
            value={content}
            onChange={(e) => {
              setContent(e.target.value);
              e.target.style.height = 'auto';
              e.target.style.height = e.target.scrollHeight + 'px';
            }}
            placeholder="What’s happening in your match? Share updates, highlights, or announcements…"
            maxLength={1000}
            style={{ ...SUBHEADING_STYLE, minHeight: "150px" }}
