const FindPlayers = () => {
  const { user: currentUser } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const { gateInteraction } = useLoginOnDemand();
  const navigate = useNavigate();

  const [players, setPlayers] = useState([]);
  const [allNearbyPlayers, setAllNearbyPlayers] = useState([]);
  const [displayedPlayers, setDisplayedPlayers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [followingIds, setFollowingIds] = useState([]);
  const [filters, setFilters] = useState({ state: "", city: "", sport: "" });
  const [searchParams, setSearchParams] = useSearchParams();
  const activeTab = searchParams.get("tab") || "players";
  
  const setActiveTab = (tab) => {
    setSearchParams({ tab });
  };
  const [teams, setTeams] = useState([]);
  const [viewingStoryGroup, setViewingStoryGroup] = useState(null);
  
  const [snapState, setSnapState] = useState("HALF");
  const [selectedRadius, setSelectedRadius] = useState(5);
  const [isRadiusChanging, setIsRadiusChanging] = useState(false);
  
  const [statesList, setStatesList] = useState([]);
  const [citiesList, setCitiesList] = useState([]);

  useEffect(() => {
    const loadStates = async () => {
      const s = await fetchStates();
      setStatesList(s);
    };
    loadStates();
  }, []);

  useEffect(() => {
    const loadCities = async () => {
      if (filters.state) {
        const c = await fetchCities(filters.state);
        setCitiesList(c);
      } else {
        setCitiesList([]);
      }
    };
    loadCities();
  }, [filters.state]);

  const [showNearbyOnly, setShowNearbyOnly] = useState(false);
  const [userLocation, setUserLocation] = useState(() => {
    const cached = localStorage.getItem("kridaz_guest_location");
    if (cached) {
      try { return JSON.parse(cached); } catch(e) {}
    }
    return null;
  });
  const { socket } = useSocket();
  const lastBoundsRef = useRef(null);
  const [currentZoom, setCurrentZoom] = useState(14);
  const [hasShownLimitToast, setHasShownLimitToast] = useState(false);
  
  // Adaptive tracking & Privacy states
  const [isTrackingActive, setIsTrackingActive] = useState(true);
  const [isLocationSharing, setIsLocationSharing] = useState(() => {
    // Prefer server truth (synced into localStorage by authSlice) over an
    // unset/legacy value. Falls back to "ON" for users who pre-date the column.
    if (typeof currentUser?.locationSharingEnabled === "boolean") {
      return currentUser.locationSharingEnabled;
    }
    return localStorage.getItem("kridaz_location_sharing") !== "false";
  });

  useEffect(() => {
    if (typeof currentUser?.locationSharingEnabled === "boolean") {
      setIsLocationSharing(currentUser.locationSharingEnabled);
    }
  }, [currentUser?.locationSharingEnabled]);
  const [isMapTilesLoaded, setIsMapTilesLoaded] = useState(false);
  const [locationError, setLocationError] = useState(null);
  
  const lastEmittedLocation = useRef(null);
  const lastEmitTime = useRef(0);
  const watchId = useRef(null);
  const MOVEMENT_THRESHOLD_METERS = 50;
  const HEARTBEAT_INTERVAL_MS = 30000;

  const clusterPlayers = (players, zoom, radiusPx) => {
    if (!players.length) return [];
    
    const clusters = [];
    const assigned = new Set();
    
    players.forEach((player, i) => {
      if (assigned.has(i)) return;
      
      const nearby = players.filter((other, j) => {
        if (j === i || assigned.has(j)) return false;
        const latDiff = Math.abs(player.lat - other.lat);
        const lngDiff = Math.abs(player.lng - other.lng);
        const pxPerDegree = 256 * Math.pow(2, zoom) / 360;
        const distPx = Math.sqrt((latDiff * pxPerDegree)**2 + (lngDiff * pxPerDegree)**2);
        return distPx < radiusPx;
      });
      
      // If there is at least 1 other nearby player, form a cluster (total >= 2)
      if (nearby.length >= 1) {
        const clusterMembers = [player, ...nearby];
        clusterMembers.forEach(member => {
          const idx = players.findIndex(p => (p.id || p._id) === (member.id || member._id));
          if (idx !== -1) assigned.add(idx);
        });
        
        const centerLat = clusterMembers.reduce((s, p) => s + p.lat, 0) / clusterMembers.length;
        const centerLng = clusterMembers.reduce((s, p) => s + p.lng, 0) / clusterMembers.length;
        const previews = [...clusterMembers].sort(() => Math.random() - 0.5).slice(0, 3);
        
        clusters.push({ 
          type: "cluster", 
          lat: centerLat, 
          lng: centerLng, 
          count: clusterMembers.length, 
          previews, 
          members: clusterMembers,
          _id: `cluster-${centerLat}-${centerLng}-${clusterMembers.length}`
        });
      } else {
        assigned.add(i);
        clusters.push({ type: "single", ...player });
      }
    });
    
    return clusters;
  };

  const sports = ["Cricket", "Football", "Badminton", "Tennis", "Basketball", "Volleyball", "Table Tennis"];

  useEffect(() => {
    const handleVisibilityChange = () => {
      setIsTrackingActive(document.visibilityState === "visible");
    };
    
    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  }, []);

  useEffect(() => {
    if (!isTrackingActive || activeTab !== "players") {
      if (watchId.current) {
        navigator.geolocation.clearWatch(watchId.current);
        watchId.current = null;
      }
      return;
    }
    
    if (!("geolocation" in navigator)) {
      toast.error("Geolocation is not supported by your browser");
      return;
    }

    watchId.current = navigator.geolocation.watchPosition(
      (position) => {
        const newLat = position.coords.latitude;
        const newLng = position.coords.longitude;
        const newLocation = {
          lat: newLat,
          lng: newLng,
          profilePicture: currentUser?.profilePicture || currentUser?.profileImage
        };

        setUserLocation(prev => {
          if (!prev) {
            localStorage.setItem("kridaz_guest_location", JSON.stringify({ lat: newLat, lng: newLng }));
            return newLocation;
          }
          const dist = haversineMeters(prev.lat, prev.lng, newLat, newLng);
          if (dist > MOVEMENT_THRESHOLD_METERS) {
            localStorage.setItem("kridaz_guest_location", JSON.stringify({ lat: newLat, lng: newLng }));
            return newLocation;
          }
          return prev;
        });
        setLocationError(null);

        // Adaptive emitting logic
        if (socket && isLocationSharing) {
          const now = Date.now();
          const shouldEmit = !lastEmittedLocation.current || 
            haversineMeters(
              lastEmittedLocation.current.lat, 
              lastEmittedLocation.current.lng,
              newLocation.lat,
              newLocation.lng
            ) > MOVEMENT_THRESHOLD_METERS ||
            (now - lastEmitTime.current) > HEARTBEAT_INTERVAL_MS;

          if (shouldEmit) {
            socket.emit("location:update", newLocation);
            lastEmittedLocation.current = newLocation;
            lastEmitTime.current = now;
          }
        }
      },
      (error) => {
        console.error("WatchPosition error:", error);
        setLocationError(error.message);
        if (error.code === 1) { // PERMISSION_DENIED
          // Silently handle, UI will show map placeholder or error state
        }
      },
      { enableHighAccuracy: true, maximumAge: 10000, timeout: 5000 }
    );

    return () => {
      if (watchId.current) {
        navigator.geolocation.clearWatch(watchId.current);
        watchId.current = null;
      }
    };
  }, [isTrackingActive, isLocationSharing, socket, activeTab]);

  useEffect(() => {
    if (activeTab === 'players' && snapState !== 'COLLAPSED') {
      document.body.style.overflow = 'hidden';
      document.documentElement.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
      if (activeTab === 'players' && snapState === 'COLLAPSED') {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    }
    return () => {
      document.body.style.overflow = '';
      document.documentElement.style.overflow = '';
    };
  }, [snapState, activeTab]);

  const toggleLocationSharing = async () => {
    const newState = !isLocationSharing;
    setIsLocationSharing(newState);
    localStorage.setItem("kridaz_location_sharing", newState.toString());
    dispatch(updateUser({ locationSharingEnabled: newState }));

    try {
      await axiosInstance.post("/api/user/players/location", {
        sharing: newState,
        lat: userLocation?.lat || 0,
        lng: userLocation?.lng || 0
      });

      if (!newState) {
        toast.success("Privacy On: You are now hidden from others");
      } else {
        toast.success("Sharing enabled: Nearby players can see you");
      }
    } catch (err) {
      console.error("Failed to update privacy setting:", err);
      toast.error("Failed to update privacy setting");
      setIsLocationSharing(!newState);
      localStorage.setItem("kridaz_location_sharing", (!newState).toString());
      dispatch(updateUser({ locationSharingEnabled: !newState }));
    }
  };

  const fetchPlayers = useCallback(async () => {
    try {
      setLoading(true);
      const params = {
        state: filters.state,
        city: filters.city,
        sportType: filters.sport,
        search: searchQuery,
        radius: selectedRadius
      };
      
      const response = await axiosInstance.get("/api/user/players", {
        params: {
          state: filters.state,
          city: filters.city,
          sport: filters.sport,
          search: searchQuery,
          ...(showNearbyOnly && userLocation ? {
            lat: userLocation.lat,
            lng: userLocation.lng,
            radius: selectedRadius * 1000
          } : {})
        }
      });
      if (response.data.success) {
        setPlayers(response.data.players || []);
        if (response.data.followingIds) setFollowingIds(response.data.followingIds);
      }
    } catch (error) {
      console.error("Error fetching players:", error);
    } finally {
      setLoading(false);
    }
  }, [filters, searchQuery, userLocation, selectedRadius, showNearbyOnly]);

  const fetchNearbyPlayers = useCallback(async () => {
    if (!userLocation) return;
    try {
      const res = await axiosInstance.get("/api/user/players/nearby", {
        params: {
          lat: userLocation.lat,
          lng: userLocation.lng,
          radius: selectedRadius * 1000,
          limit: 50
        }
      });
      if (res.data.success) {
        if (res.data.players.length > 100 && !hasShownLimitToast) {
          toast("Showing top nearby players. Zoom in to see more.", { icon: "=ƒôì" });
          setHasShownLimitToast(true);
        }
        const mapPlayers = res.data.players
          .map(p => ({
            _id: p.id || p._id,
            name: p.name,
            username: p.username,
            profilePicture: p.profilePicture,
            lat: p.lat,
            lng: p.lng,
            distanceKm: p.distanceKm,
            city: p.city,
            sportTypes: p.sportTypes,
            lastSeen: p.lastSeen
          }))
          .filter(p => p.lat != null && p.lng != null);

        setAllNearbyPlayers(mapPlayers);
      }
    } catch (err) {
      console.error("Failed to fetch nearby players:", err);
    }
  }, [userLocation, selectedRadius]);

  const handleMapMove = useCallback((bounds, zoom) => {
    lastBoundsRef.current = bounds;
    if (zoom) setCurrentZoom(zoom);
    if (!bounds || !allNearbyPlayers.length) {
      if (allNearbyPlayers.length) {
        setDisplayedPlayers(allNearbyPlayers.map(p => ({ type: "single", ...p })));
      }
      return;
    }

    const visiblePlayers = allNearbyPlayers.filter(p => {
      try {
        return bounds.contains([p.lat, p.lng]);
      } catch (e) {
        return true; // Fallback to showing if bounds check fails
      }
    });
    
    let radiusPx = 60;
    const z = zoom || currentZoom;
    if (z < 13) radiusPx = 80;
    else if (z >= 13 && z <= 15) radiusPx = 60;
    else if (z > 15 && z <= 17) radiusPx = 30;
    else radiusPx = 0;

    if (radiusPx > 0 && visiblePlayers.length > 0) {
      const clustered = clusterPlayers(visiblePlayers, z, radiusPx);
      setDisplayedPlayers(clustered);
    } else {
      setDisplayedPlayers(visiblePlayers.map(p => ({ type: "single", ...p })));
    }
  }, [allNearbyPlayers, currentZoom]);

  useEffect(() => {
    if (lastBoundsRef.current) {
      handleMapMove(lastBoundsRef.current, currentZoom);
    }
  }, [allNearbyPlayers, handleMapMove, currentZoom]);

  useEffect(() => {
    if (userLocation) {
      fetchNearbyPlayers();
      const interval = setInterval(fetchNearbyPlayers, HEARTBEAT_INTERVAL_MS);
      return () => clearInterval(interval);
    }
  }, [userLocation, fetchNearbyPlayers]);

  useEffect(() => {
    if (userLocation) {
      setIsRadiusChanging(true);
      setTimeout(() => setIsRadiusChanging(false), 500);
    }
  }, [selectedRadius]);

  useEffect(() => {
    if (!socket || !userLocation || snapState === 'COLLAPSED' || !isLocationSharing) return;
    
    socket.emit("location:update", {
      lat: userLocation.lat,
      lng: userLocation.lng,
      radiusKm: selectedRadius
    });
  }, [socket, userLocation, selectedRadius, snapState, isLocationSharing]);

  useEffect(() => {
    if (!socket) return;
    
    const handleLocationUpdate = ({ userId, lat, lng }) => {
      setAllNearbyPlayers(prev => {
        const existing = prev.find(p => (p.id || p._id) === userId);
        if (existing) {
          return prev.map(p => (p.id || p._id) === userId ? { ...p, lat, lng } : p);
        } else {
          // New user moved into radius, trigger fetch to get their profile data
          fetchNearbyPlayers();
          return prev;
        }
      });
    };

    socket.on("nearby:location:update", handleLocationUpdate);
    
    return () => {
      socket.off("nearby:location:update", handleLocationUpdate);
    };
  }, [socket]);

  const fetchTeams = useCallback(async () => {
    try {
      setLoading(true);
      const params = {};
      if (filters.state) params.state = filters.state;
      if (filters.city) params.city = filters.city;
      if (filters.sport) params.sportType = filters.sport;
      if (searchQuery) params.search = searchQuery;

      const response = await axiosInstance.get("/api/team/all", { params });
      if (response.data.success) {
        setTeams(response.data.teams || []);
      }
    } catch (error) {
      console.error("Error fetching teams:", error);
      toast.error("Failed to fetch teams");
    } finally {
      setLoading(false);
    }
  }, [filters, searchQuery]);
  const fetchTeamsRef = useRef(fetchTeams);
  const fetchPlayersRef = useRef(fetchPlayers);

  useEffect(() => {
    fetchTeamsRef.current = fetchTeams;
    fetchPlayersRef.current = fetchPlayers;
  }, [fetchTeams, fetchPlayers]);

  useEffect(() => {
    if (activeTab === "players") fetchPlayersRef.current();
    else fetchTeamsRef.current();
  }, [activeTab, filters, selectedRadius, showNearbyOnly, userLocation]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (activeTab === "players") fetchPlayersRef.current();
      else fetchTeamsRef.current();
    }, 500);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const handleSearch = (e) => {
    setSearchQuery(e.target.value);
  };

  const handleFilterChange = (name, value) => {
    setFilters(prev => ({ ...prev, [name]: value }));
  };

  const handleFollowToggle = (targetUserId) => {
    gateInteraction(async () => {
      const wasFollowing = followingIds.includes(targetUserId);

      // ── Optimistic update: flip state instantly ──────────────────────
      setFollowingIds(prev =>
        wasFollowing
          ? prev.filter(id => id !== targetUserId)
          : [...prev, targetUserId]
      );

      // ── Also update follower count in the players list optimistically ─
      setPlayers(prev =>
        prev.map(p => {
          const id = p.id || p._id;
          if (id !== targetUserId) return p;
          const delta = wasFollowing ? -1 : 1;
          return {
            ...p,
            followersCount: Math.max(0, (p.followersCount ?? p.followers?.length ?? 0) + delta),
          };
        })
      );

      try {
        const endpoint = `/api/user/players/${targetUserId}/${wasFollowing ? 'unfollow' : 'follow'}`;
        await axiosInstance.post(endpoint);
        // Success – no toast needed, the UI already reflected the change
      } catch (error) {
        // ── Rollback on failure ──────────────────────────────────────────
        setFollowingIds(prev =>
          wasFollowing
            ? [...prev, targetUserId]
            : prev.filter(id => id !== targetUserId)
        );
        setPlayers(prev =>
          prev.map(p => {
            const id = p.id || p._id;
            if (id !== targetUserId) return p;
            const delta = wasFollowing ? 1 : -1;
            return {
              ...p,
              followersCount: Math.max(0, (p.followersCount ?? p.followers?.length ?? 0) + delta),
            };
          })
        );
        toast.error("Couldn't update follow status. Please try again.");
      }
    });
  };


  const handleAvatarClick = (player) => {
    gateInteraction(() => {
      const playerId = player.id || player._id;
      if (!player.hasActiveStory) {
        navigate(`/profile/${playerId}`);
        return;
      }
      const fetchStories = async () => {
        try {
          const res = await axiosInstance.get(`/api/user/community/user-stories/${playerId}`);
          if (res.data.success && res.data.stories?.length > 0) {
            setViewingStoryGroup({ user: player, stories: res.data.stories });
          } else {
            navigate(`/profile/${playerId}`);
          }
        } catch (error) {
          toast.error("Failed to load stories");
          navigate(`/profile/${playerId}`);
        }
      };
      fetchStories();
    });
  };

  const handleMapPlayerClick = (id) => {
    const element = document.getElementById(`player-card-${id}`);
    if (element) {
      element.scrollIntoView({ behavior: "smooth", block: "center" });
      element.classList.add("ring-2", "ring-[#B3DC26]", "ring-offset-4", "ring-offset-black");
      setTimeout(() => {
        element.classList.remove("ring-2", "ring-[#B3DC26]", "ring-offset-4", "ring-offset-black");
      }, 3000);
    }
  };

  const handleDragEnd = (_, info) => {
    const velocityThreshold = 30;
    const offsetThreshold = 40;
    const vy = info.velocity.y;
    const dy = info.offset.y;

    // Drag UP (negative y) → close/collapse map
    if (vy < -velocityThreshold || dy < -offsetThreshold) {
      if (snapState === "EXPANDED") setSnapState("HALF");
      else if (snapState === "HALF") setSnapState("COLLAPSED");
    }
    // Drag DOWN (positive y) → open/expand map
    else if (vy > velocityThreshold || dy > offsetThreshold) {
      if (snapState === "COLLAPSED") setSnapState("HALF");
      else if (snapState === "HALF") setSnapState("EXPANDED");
    }
  };

  return (
    <div className={`bg-black text-white flex flex-col ${activeTab === "players" ? "fixed inset-0 lg:relative lg:inset-auto lg:left-0 lg:overflow-visible overflow-hidden pt-16 lg:pt-0" : "min-h-screen"}`}>
      
      {activeTab === "players" && (
        <>
          <motion.div 
            animate={{ height: `${SNAP_STATES[snapState]}vh` }}
            transition={{ type: "spring", damping: 25, stiffness: 150 }}
            className="relative w-full bg-[#000000] border-b border-[#B3DC26]/30 overflow-hidden lg:hidden"
          >
            <AnimatePresence>
              {snapState !== "COLLAPSED" && (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="w-full h-full relative"
                >
                  <NearbyPlayersMap 
                    userLocation={userLocation}
                    nearbyPlayers={displayedPlayers} 
                    radiusKm={selectedRadius}
                    onMapMove={handleMapMove}
                    onPlayerClick={(id) => navigate(`/profile/${id}`)}
                  />

                  {/* HEADER STATUS BAR */}
                  <div className="absolute top-4 left-4 z-[1000] flex items-center gap-2 pointer-events-auto">
                    <div className="flex items-center gap-1.5 bg-black/60 backdrop-blur-xl border border-white/10 p-1.5 px-2.5 rounded-[8px] shadow-2xl">
                      <Users size={14} className="text-[#B3DC26]" />
                      <span className="text-[#B3DC26] text-[12px] font-black">{allNearbyPlayers.length}</span>
                    </div>

                    <button 
                      onClick={toggleLocationSharing}
                      className={`flex items-center justify-center p-1.5 w-8 h-8 rounded-[8px] border transition-all duration-300 backdrop-blur-xl shadow-2xl ${ isLocationSharing ? "bg-[#B3DC26]/20 border-[#B3DC26]/30 text-[#B3DC26]" : "bg-red-500/10 border-red-500/20 text-red-500" }`}
                    >
                      {isLocationSharing ? <Eye size={16} /> : <EyeOff size={16} />}
                    </button>
                  </div>

                  {/* LOADING SKELETON */}
                  {!userLocation && !locationError && (
                    <div className="absolute inset-0 z-[2000] bg-[#000000] flex flex-col items-center justify-center">
                      <div className="w-full h-full relative opacity-20">
                        <div className="absolute inset-0" style={{ 
                            backgroundImage: 'radial-gradient(#B3DC26 1px, transparent 1px)', 
                            backgroundSize: '40px 40px' 
                        }} />
                      </div>
                      <div className="absolute flex flex-col items-center gap-4">
                        <div className="relative">
                          <div className="w-16 h-16 border-2 border-[#B3DC26]/20 rounded-full animate-ping absolute inset-0" />
                          <div className="w-16 h-16 border-2 border-[#B3DC26] rounded-full flex items-center justify-center bg-black">
                            <MapPin className="text-[#B3DC26] animate-bounce" size={24} />
                          </div>
                        </div>
                        <div className="text-center">
                          <p className="text-white font-black text-sm uppercase tracking-widest mb-1">Finding your location...</p>
                          <p className="text-white/40 text-[10px] font-bold uppercase tracking-tighter">Connecting to Kridaz Satellites</p>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* ERROR STATE */}
                  {locationError && (
                    <div className="absolute inset-0 z-[2000] bg-[#000000]/90 backdrop-blur-md flex flex-col items-center justify-center p-8 text-center">
                      <div className="w-16 h-16 bg-red-500/20 border border-red-500/30 rounded-[8px] flex items-center justify-center mb-4">
                        <AlertCircle className="text-red-500" size={32} />
                      </div>
                      <h3 className="text-white font-black uppercase tracking-widest mb-2">Location Required</h3>
                      <p className="text-white/40 text-xs font-medium leading-relaxed max-w-xs mb-6">
                        We need your location to show nearby players. Please check your browser permissions.
                      </p>
                      <button 
                        onClick={() => window.location.reload()}
                        className="px-8 py-3 bg-[rgba(255,255,255,0.08)] border border-[rgba(255,255,255,0.08)] rounded-[16px] text-[12px] font-[600] font-inter uppercase text-[#FFFFFF] hover:brightness-110 transition-all"
                      >
                        Retry Connection
                      </button>
                    </div>
                  )}

                  <AnimatePresence>
                    {isRadiusChanging && (
                      <motion.div 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="absolute inset-0 z-[1500] bg-black/40 backdrop-blur-sm flex items-center justify-center"
                      >
                        <Loader2 className="text-[#B3DC26] animate-spin" size={32} />
                      </motion.div>
                    )}
                  </AnimatePresence>

                  <div className="absolute bottom-0 left-0 w-full z-[1000]">
                    <div className="bg-black/80 backdrop-blur-xl border-t border-white/10 p-2.5 px-6 flex items-center gap-4 pointer-events-auto w-full">
                        <span className="text-white/40 text-[9px] font-black uppercase tracking-widest">Radius</span>
                        <input 
                          type="range"
                          min="5" max="100" step="5"
                          value={selectedRadius}
                          onPointerDown={(e) => e.stopPropagation()}
                          onChange={(e) => {
                            e.stopPropagation();
                            setSelectedRadius(Number(e.target.value));
                          }}
                          className="flex-1 h-1 bg-white/20 rounded-lg appearance-none cursor-pointer accent-[#B3DC26]"
                        />
                        <span className="text-[#B3DC26] text-[10px] font-black min-w-[40px] text-right">{selectedRadius} KM</span>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>

          {/* DRAG HANDLE */}
          <motion.div 
            drag="y"
            dragConstraints={{ top: 0, bottom: 0 }}
            dragElastic={0.1}
            onDragEnd={handleDragEnd}
            className="w-full h-10 flex flex-col items-center justify-center cursor-grab active:cursor-grabbing bg-black z-50 group border-b border-white/5 lg:hidden"
          >
            <div className="w-12 h-1.5 bg-white/10 rounded-full group-hover:bg-[#B3DC26]/40 transition-colors" />
            <div className="text-[8px] font-bold text-white/10 uppercase tracking-[0.3em] mt-1 group-hover:text-[#B3DC26]/40 transition-colors">
                Slide to Discover
            </div>
          </motion.div>
        </>
      )}

      {/* BOTTOM PANEL: Feed */}
      <div className={`flex-1 ${activeTab === "players" ? "overflow-y-auto no-scrollbar pb-24 pt-6 px-4 md:px-8" : "pb-12 pt-2 px-1 md:px-2"} bg-black`}>
        <div className={`max-w-6xl mx-auto space-y-6 ${activeTab === "players" ? "mt-6" : "mt-2"}`}>
          
          {/* Tab Switcher */}
          <div className="flex items-center gap-4 border-b border-[rgba(255,255,255,0.08)] pb-1">
            <button 
              onClick={() => setActiveTab("players")}
              className={`pb-4 px-2 text-[12px] font-[600] font-inter uppercase transition-all relative ${activeTab === "players" ? "text-[#B3DC26]" : "text-[rgba(255,255,255,0.70)] hover:text-[#FFFFFF]"}`}
            >
              Players
              {activeTab === "players" && <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#B3DC26]" />}
            </button>
            <button 
              onClick={() => setActiveTab("teams")}
              className={`pb-4 px-2 text-[12px] font-[600] font-inter uppercase transition-all relative ${activeTab === "teams" ? "text-[#B3DC26]" : "text-[rgba(255,255,255,0.70)] hover:text-[#FFFFFF]"}`}
            >
              Teams
              {activeTab === "teams" && <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#B3DC26]" />}
            </button>
          </div>

          {/* Compact Header Row */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-[#121212] border border-[rgba(255,255,255,0.08)] rounded-[16px] p-3 md:p-4">
            <div className="flex items-center gap-4 flex-1">
              <div className="relative flex-1 max-w-md group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[rgba(255,255,255,0.40)] group-focus-within:text-[#B3DC26] transition-colors" size={16} />
                <input 
                  type="text" 
                  value={searchQuery}
                  onChange={handleSearch}
                  placeholder="SEARCH..."
                  className="w-full bg-[#1B1B1B] border border-[rgba(255,255,255,0.08)] focus:border-[#B3DC26]/50 rounded-[16px] h-10 pl-11 pr-4 text-[#FFFFFF] text-[12px] font-[400] font-inter placeholder-[rgba(255,255,255,0.40)] outline-none transition-all uppercase tracking-widest"
                />
              </div>
            </div>

            <div className="flex items-center gap-2 flex-wrap md:flex-nowrap">
              <select 
                value={filters.sport}
                onChange={(e) => handleFilterChange("sport", e.target.value)}
                className="bg-transparent px-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none cursor-pointer hover:text-[#FFFFFF] transition-all uppercase"
              >
                <option value="" className="bg-[#121212] text-[#FFFFFF]">All Sports</option>
                {sports.map(s => <option key={s} value={s} className="bg-[#121212] text-[#FFFFFF]">{s}</option>)}
              </select>
              
              {/* PC View Filters (Hidden on Mobile/Tab) */}
              <div className="hidden lg:flex items-center gap-2">
                <div className="relative group">
                  <MapPin className="absolute left-2.5 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#B3DC26]" size={10} />
                  <select 
                    value={filters.state || ""}
                    onChange={(e) => {
                      handleFilterChange("state", e.target.value);
                      handleFilterChange("city", "");
                    }}
                    className="bg-transparent pl-7 pr-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none w-24 md:w-28 cursor-pointer hover:text-[#FFFFFF] transition-all appearance-none uppercase"
                  >
                    <option value="" className="bg-[#121212] text-[#FFFFFF]">STATE...</option>
                    {statesList.map(s => <option key={s} value={s} className="bg-[#121212] text-[#FFFFFF]">{s}</option>)}
                  </select>
                </div>
                <div className="relative group">
                  <MapPin className="absolute left-2.5 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#B3DC26]" size={10} />
                  <select 
                    value={filters.city || ""}
                    onChange={(e) => handleFilterChange("city", e.target.value)}
                    className="bg-transparent pl-7 pr-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none w-24 md:w-28 cursor-pointer hover:text-[#FFFFFF] transition-all appearance-none uppercase"
                    disabled={!filters.state}
                  >
                    <option value="" className="bg-[#121212] text-[#FFFFFF]">CITY...</option>
                    {citiesList.map(c => <option key={c} value={c} className="bg-[#121212] text-[#FFFFFF]">{c}</option>)}
                  </select>
                </div>
                <div className="relative group">
                  <Navigation className="absolute left-2.5 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#B3DC26]" size={10} />
                  <select 
                    value={selectedRadius}
                    onChange={(e) => setSelectedRadius(Number(e.target.value))}
                    className="bg-transparent pl-7 pr-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none cursor-pointer hover:text-[#FFFFFF] transition-all appearance-none w-24 md:w-28 uppercase"
                  >
                    <option value="5" className="bg-[#121212] text-[#FFFFFF]">5 KM</option>
                    <option value="10" className="bg-[#121212] text-[#FFFFFF]">10 KM</option>
                    <option value="20" className="bg-[#121212] text-[#FFFFFF]">20 KM</option>
                    <option value="50" className="bg-[#121212] text-[#FFFFFF]">50 KM</option>
                    <option value="100" className="bg-[#121212] text-[#FFFFFF]">100 KM</option>
                  </select>
                </div>
              </div>

              {/* Mobile/Tab Location Filters */}
              <div className="relative group lg:hidden">
                <MapPin className="absolute left-2.5 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#B3DC26]" size={10} />
                <select
                  value={filters.state || ""}
                  onChange={(e) => {
                    handleFilterChange("state", e.target.value);
                    handleFilterChange("city", "");
                  }}
                  className="bg-transparent pl-7 pr-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none w-24 md:w-28 cursor-pointer hover:text-[#FFFFFF] transition-all appearance-none uppercase"
                >
                  <option value="" className="bg-[#121212] text-[#FFFFFF]">STATE...</option>
                  {statesList.map(s => <option key={s} value={s} className="bg-[#121212] text-[#FFFFFF]">{s}</option>)}
                </select>
              </div>
              <div className="relative group lg:hidden">
                <MapPin className="absolute left-2.5 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#B3DC26]" size={10} />
                <select
                  value={filters.city || ""}
                  onChange={(e) => handleFilterChange("city", e.target.value)}
                  disabled={!filters.state}
                  className="bg-transparent pl-7 pr-3 py-1.5 text-[12px] font-[400] font-inter text-[rgba(255,255,255,0.70)] focus:text-[#B3DC26] outline-none w-24 md:w-28 cursor-pointer hover:text-[#FFFFFF] transition-all appearance-none disabled:opacity-40 uppercase"
                >
                  <option value="" className="bg-[#121212] text-[#FFFFFF]">CITY...</option>
                  {citiesList.map(c => <option key={c} value={c} className="bg-[#121212] text-[#FFFFFF]">{c}</option>)}
                </select>
              </div>

              {activeTab === "players" && (
                <button 
                  onClick={() => setShowNearbyOnly(!showNearbyOnly)}
                  className={`flex items-center gap-2 px-3 h-10 rounded-[16px] transition-all text-[12px] font-[600] font-inter uppercase ${ showNearbyOnly ? "bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] text-[#000000] shadow-[0px_8px_24px_rgba(179,220,38,0.15)] border-none" : "bg-[#1B1B1B] text-[#FFFFFF] border border-[rgba(255,255,255,0.08)] hover:brightness-110" }`}
                >
                  <Navigation size={14} className={showNearbyOnly ? "animate-pulse" : ""} />
                  Nearby
                </button>
              )}
            </div>
          </div>

          {/* Content Grid */}
          {loading ? (
            activeTab === "players" ? (
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
                {[...Array(10)].map((_, i) => (
                  <div
                    key={i}
                    className="w-full aspect-[3/4] rounded-[16px] border border-[rgba(255,255,255,0.08)] animate-pulse bg-[#121212]"
                  />
                ))}
              </div>
            ) : (
              <div className="grid grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
                {[...Array(6)].map((_, i) => (
                  <div
                    key={i}
                    className="w-full h-64 rounded-[16px] border border-[rgba(255,255,255,0.08)] animate-pulse bg-[#121212]"
                  />
                ))}
              </div>
            )
          ) : activeTab === "players" ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
              {players.map((player) => (
                <div key={player.id || player._id} id={`player-card-${player.id || player._id}`}>
                  <PlayerCard
                    player={player}
                    followingIds={followingIds}
                    handleFollowToggle={handleFollowToggle}
                    handleAvatarClick={handleAvatarClick}
                    navigate={navigate}
                    gateInteraction={gateInteraction}
                  />
                </div>
              ))}
            </div>
          ) : (
            <div className="grid grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
              {teams.length > 0 ? (
                teams.map((team) => (
                  <TeamCard key={team._id} team={team} navigate={navigate} />
                ))
              ) : (
                <div className="col-span-full py-20 text-center">
                  <div className="w-16 h-16 bg-[#121212] rounded-full flex items-center justify-center mx-auto mb-4 border border-[rgba(255,255,255,0.08)] text-gray-500">
                    <Users size={32} />
                  </div>
                  <p className="text-[rgba(255,255,255,0.70)] font-[600] uppercase font-inter text-[12px]">No teams found</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {viewingStoryGroup && (
        <StoryViewer 
          storyGroup={viewingStoryGroup}
          onClose={() => setViewingStoryGroup(null)}
          onDelete={null}
          currentUser={currentUser}
        />
      )}
    </div>
  );
};

export default FindPlayers;

import { useState, useEffect, useRef, useCallback } from "react";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import { useSelector } from "react-redux";
import axiosInstance from "@hooks/useAxiosInstance";
import { motion } from "framer-motion";
import {
  Search, MapPin, Star, Users, Shield, Trophy,
  Activity, Filter, Loader2, Check, X,
  Video, ChevronDown, Navigation, Zap, Calendar, Clock
} from "lucide-react";
import toast from "react-hot-toast";
import { fetchStates, fetchCities } from "@utils/locationService";
import { useSocket } from "@context/SocketContext";
import {
  useCreateMatchRequestMutation,
  useGetUserOnDemandBookingsQuery
} from "../../../redux/api/professionalApi";

const sports = ["ALL SPORTS", "CRICKET", "BADMINTON", "FOOTBALL", "TENNIS", "PICKLEBALL"];
const roles = ["All", "Coach", "Umpire", "Streamer", "Commentator", "Scorer", "Cheerleader"];

export default function FindProfessionals() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { isLoggedIn, user } = useSelector((state) => state.auth);

  // Browse State
  const [professionals, setProfessionals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedSport, setSelectedSport] = useState("ALL SPORTS");
  const [selectedRole, setSelectedRole] = useState(() => {
    const roleParam = searchParams.get("role");
    if (roleParam) {
      const found = roles.find(r => r.toLowerCase() === roleParam.toLowerCase());
      if (found) return found;
    }
    return "All";
  });
  const [searchTerm, setSearchTerm] = useState("");
  const [cityFilter, setCityFilter] = useState("All");
  const [stateFilter, setStateFilter] = useState("All");
  const [availableStates, setAvailableStates] = useState([]);
  const [availableCities, setAvailableCities] = useState([]);

  // Modal State
  const [showMatchModal, setShowMatchModal] = useState(false);

  // Matchmaking Form State
  const [selectedGroundId, setSelectedGroundId] = useState("");
  const [customLocation, setCustomLocation] = useState({ latitude: "", longitude: "", address: "" });

  // Location Auto-Search State
  const [locationQuery, setLocationQuery] = useState("");
  const [locationResults, setLocationResults] = useState([]);
  const [locationSearching, setLocationSearching] = useState(false);
  const [showLocationDropdown, setShowLocationDropdown] = useState(false);
  const [showMoreFilters, setShowMoreFilters] = useState(false);
  const [showLocationSearchModal, setShowLocationSearchModal] = useState(false);
  const locationSearchRef = useRef(null);
  const filterMenuRef = useRef(null);
  const searchTimeoutRef = useRef(null);
  const [selectedRoles, setSelectedRoles] = useState(() => {
    const validRoles = ["COACH", "UMPIRE", "STREAMER", "COMMENTATOR", "SCORER", "CHEERLEADER"];
    const queryRole = searchParams.get("role")?.toUpperCase();
    return queryRole && validRoles.includes(queryRole) ? [queryRole] : [];
  });
  const [budget, setBudget] = useState(1000);
  const [matchDate, setMatchDate] = useState("");
  const [matchStartTime, setMatchStartTime] = useState("");
  const [matchEndTime, setMatchEndTime] = useState("");
  const [expiresInSeconds, setExpiresInSeconds] = useState(40);
  const [grounds, setGrounds] = useState([]);
  const [loadingGrounds, setLoadingGrounds] = useState(false);

  // RTK Query Mutations & Queries
  const [createMatchRequest, { isLoading: isCreatingRequest }] = useCreateMatchRequestMutation();
  const { refetch: refetchBookings } = useGetUserOnDemandBookingsQuery(undefined, {
    skip: !isLoggedIn
  });
  const { socket } = useSocket();

  // Auto-open modal if ?role= query param exists
  useEffect(() => {
    const queryRole = searchParams.get("role")?.toUpperCase();
    if (queryRole && ["COACH", "UMPIRE", "STREAMER", "COMMENTATOR", "SCORER", "CHEERLEADER"].includes(queryRole)) {
      setShowMatchModal(true);
    }
  }, []);

  // Load States & Grounds
  useEffect(() => {
    loadStates();
    fetchGrounds();
  }, []);

  useEffect(() => {
    if (stateFilter !== "All") {
      loadCities(stateFilter);
    } else {
      setAvailableCities([]);
    }
    setCityFilter("All");
  }, [stateFilter]);

  useEffect(() => {
    fetchProfessionals();
  }, [selectedSport, selectedRole, cityFilter, stateFilter]);

  // Socket confirmation listener
  useEffect(() => {
    if (socket && isLoggedIn) {
      const handleMatchConfirmed = (data) => {
        toast.success(`Match Confirmed! ${data.professionalName} is assigned.`);
        if (data.otp && data.bookingId) {
          // localStorage OTP removed per security audit
        }
        refetchBookings();
      };

      socket.on("professional:match_confirmed", handleMatchConfirmed);
      return () => {
        socket.off("professional:match_confirmed", handleMatchConfirmed);
      };
    }
  }, [socket, isLoggedIn, refetchBookings]);

  const loadStates = async () => {
    try {
      const states = await fetchStates();
      setAvailableStates(states);
    } catch (error) {
      console.error("Error loading states:", error);
    }
  };

  const loadCities = async (state) => {
    try {
      const cities = await fetchCities(state);
      setAvailableCities(cities);
    } catch (error) {
      console.error("Error loading cities:", error);
    }
  };

  const fetchGrounds = async () => {
    try {
      setLoadingGrounds(true);
      const res = await axiosInstance.get("/api/user/turf/all");
      setGrounds(res.data.turfs || []);
    } catch (err) {
      console.error("Error loading grounds:", err);
    } finally {
      setLoadingGrounds(false);
    }
  };

  const fetchProfessionals = async () => {
    try {
      setLoading(true);
      const params = {
        sport: selectedSport === "ALL SPORTS" ? "" : selectedSport,
        role: selectedRole === "All" ? "" : selectedRole.toLowerCase(),
        city: cityFilter === "All" ? "" : cityFilter,
        state: stateFilter === "All" ? "" : stateFilter,
        searchTerm
      };
      const res = await axiosInstance.get("/api/professional/list", { params });
      setProfessionals(res.data.professionals || []);
    } catch (error) {
      console.error("Error fetching professionals:", error);
      toast.error("Failed to load professionals");
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchProfessionals();
  };

  const formatDisplayDate = (dateStr) => {
    if (!dateStr) return "Select Date";
    return new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  const formatDisplayTime = (timeStr) => {
    if (!timeStr) return "Select Time";
    const [h, m] = timeStr.split(':');
    const d = new Date();
    d.setHours(h);
    d.setMinutes(m);
    return d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
  };

  const handleDetectLocation = () => {
    if (!navigator.geolocation) {
      toast.error("Geolocation is not supported by your browser");
      return;
    }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const lat = pos.coords.latitude.toString();
        const lon = pos.coords.longitude.toString();
        let address = "Current Geolocation Coordinates";
        try {
          const res = await fetch(
            `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json`,
            { headers: { "Accept-Language": "en" } }
          );
          const data = await res.json();
          if (data.display_name) address = data.display_name;
        } catch {
          // Keep the GPS coordinates if reverse geocoding is unavailable.
        }
        setCustomLocation({ latitude: lat, longitude: lon, address });
        setLocationQuery(address);
        setSelectedGroundId("custom");
        setShowLocationSearchModal(false);
        toast.success("Location detected!");
      },
      (err) => {
        toast.error("Failed to detect location: " + err.message);
      }
    );
  };

  const handleLocationSearch = useCallback((query) => {
    setLocationQuery(query);
    if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
    if (!query || query.length < 3) {
      setLocationResults([]);
      setShowLocationDropdown(false);
      return;
    }
    setLocationSearching(true);
    searchTimeoutRef.current = setTimeout(async () => {
      try {
        const res = await fetch(
          `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(query)}&format=json&limit=6&countrycodes=in&addressdetails=1`,
          { headers: { "Accept-Language": "en" } }
        );
        const data = await res.json();
        setLocationResults(data || []);
        setShowLocationDropdown(data.length > 0);
      } catch {
        setLocationResults([]);
      } finally {
        setLocationSearching(false);
      }
    }, 400);
  }, []);

  const handleSelectLocation = (place) => {
    setCustomLocation({
      latitude: place.lat,
      longitude: place.lon,
      address: place.display_name
    });
    setLocationQuery(place.display_name);
    setShowLocationDropdown(false);
    setLocationResults([]);
    setShowLocationSearchModal(false);
  };

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (locationSearchRef.current && !locationSearchRef.current.contains(e.target)) {
        setShowLocationDropdown(false);
      }
      if (filterMenuRef.current && !filterMenuRef.current.contains(e.target)) {
        setShowMoreFilters(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleToggleRole = (roleVal) => {
    if (selectedRoles.includes(roleVal)) {
      setSelectedRoles(selectedRoles.filter(r => r !== roleVal));
    } else {
      setSelectedRoles([...selectedRoles, roleVal]);
    }
  };

  const handleRequestMatch = async (e) => {
    e.preventDefault();
    if (!isLoggedIn) {
      toast.error("Please login to request matchmaking");
      navigate("/login");
      return;
    }

    if (!selectedGroundId && (!customLocation.latitude || !customLocation.longitude)) {
      toast.error("Please select a ground or capture custom geolocation");
      return;
    }

    if (selectedRoles.length === 0) {
      toast.error("Please select at least one role");
      return;
    }

    if (!matchDate || !matchStartTime || !matchEndTime) {
      toast.error("Please select date, start time, and end time for the match.");
      return;
    }

    const payload = {
      roles: selectedRoles,
      minBudget: 500,
      maxBudget: parseFloat(budget),
      expiresAt: new Date(Date.now() + expiresInSeconds * 1000).toISOString(),
      matchDate,
      matchStartTime,
      matchEndTime
    };

    if (selectedGroundId && selectedGroundId !== "custom") {
      payload.groundId = selectedGroundId;
    } else {
      payload.customLocation = {
        latitude: parseFloat(customLocation.latitude),
        longitude: parseFloat(customLocation.longitude),
        address: customLocation.address || "Custom Geocoded Location"
      };
    }

    try {
      const res = await createMatchRequest(payload).unwrap();
      if (res.success) {
        toast.success("Match request placed! We'll notify you once a pro accepts.");
        setSelectedRoles([]);
        setSelectedGroundId("");
        setCustomLocation({ latitude: "", longitude: "", address: "" });
        setShowMatchModal(false);
        refetchBookings();
      }
    } catch (err) {
      toast.error(err.data?.message || "Failed to create match request");
    }
  };

  const getInitials = (name) => {
    return name?.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2) || "??";
  };

  return (
    <div className="min-h-screen bg-black text-white px-1 md:px-2 pt-2 pb-20 font-sans">

      {/* Search & Filters */}
      <div className="max-w-7xl mx-auto mb-6">
        <div className="max-w-7xl mx-auto">
          <form onSubmit={handleSearch} className="relative mb-6" ref={filterMenuRef}>
            <div className="flex items-center rounded-full border border-white/10 bg-[#262626] shadow-lg transition-colors focus-within:border-[#BFF367]/70 hover:bg-[#303030]">
              <div className="relative min-w-0 flex-1">
                <Search className="pointer-events-none absolute left-4 top-1/2 -translate-y-1/2 text-white/50" size={17} />
                <input
                  type="search"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Search by name, specialty, or keyword..."
                  aria-label="Search professionals"
                  className="h-[38px] w-full rounded-l-full bg-transparent pl-11 pr-4 text-[13px] font-semibold text-white outline-none placeholder:text-white/40"
                />
              </div>

              <div className="hidden h-7 w-px bg-white/10 sm:block" />

              <button
                type="button"
                onClick={() => setShowMoreFilters((isOpen) => !isOpen)}
                className="flex h-[38px] shrink-0 items-center justify-center gap-2 rounded-r-full px-3 text-[10px] font-black text-white transition-colors hover:bg-white/5 focus:outline-none sm:px-4"
                aria-expanded={showMoreFilters}
                aria-controls="professionals-more-filters"
              >
                <Filter size={13} className="text-white/70" />
                <span className="hidden sm:inline">More Filters</span>
              </button>
            </div>

            {showMoreFilters && (
              <div
                id="professionals-more-filters"
                className="absolute right-0 top-full z-30 mt-3 w-full max-w-sm rounded-2xl border border-white/10 bg-[#141414] p-4 shadow-[0_18px_60px_rgba(0,0,0,0.55)]"
              >
                <div className="space-y-4">
                  <label className="block">
                    <span className="mb-2 block text-[10px] font-black uppercase tracking-[0.16em] text-white/45">Role Filter</span>
                    <div className="relative">
                      <Filter className="pointer-events-none absolute left-4 top-1/2 -translate-y-1/2 text-white/55" size={15} />
                      <select
                        value={selectedRole}
                        onChange={(e) => setSelectedRole(e.target.value)}
                        aria-label="Role filter"
                        className="h-[46px] w-full appearance-none rounded-full border border-white/10 bg-[#262626] pl-11 pr-10 text-[13px] font-bold text-white outline-none transition-colors hover:bg-[#303030] focus:border-[#BFF367]/70"
                      >
                        {roles.map((role) => (
                          <option key={role} value={role}>
                            {role === "All" ? "All Roles" : role}
                          </option>
                        ))}
                      </select>
                      <ChevronDown className="pointer-events-none absolute right-4 top-1/2 -translate-y-1/2 text-white/55" size={16} />
                    </div>
                  </label>

                  <label className="block">
                    <span className="mb-2 block text-[10px] font-black uppercase tracking-[0.16em] text-white/45">Sport Filter</span>
                    <div className="relative">
                      <Trophy className="pointer-events-none absolute left-4 top-1/2 -translate-y-1/2 text-white/55" size={15} />
                      <select
                        value={selectedSport}
                        onChange={(e) => setSelectedSport(e.target.value)}
                        aria-label="Sports filter"
                        className="h-[46px] w-full appearance-none rounded-full border border-white/10 bg-[#262626] pl-11 pr-10 text-[13px] font-bold text-white outline-none transition-colors hover:bg-[#303030] focus:border-[#BFF367]/70"
                      >
                        {sports.map((sport) => (
                          <option key={sport} value={sport}>
                            {sport === "ALL SPORTS" ? "All Sports" : sport}
                          </option>
                        ))}
                      </select>
                      <ChevronDown className="pointer-events-none absolute right-4 top-1/2 -translate-y-1/2 text-white/55" size={16} />
                    </div>
                  </label>
                </div>
              </div>
            )}
          </form>

          {/* Ads Space */}
          <div className="px-2 md:px-0">
            <div className="w-full h-[180px] sm:h-[240px] rounded-[16px] overflow-hidden mb-6 relative cursor-pointer group bg-[#111] shadow-[0px_8px_24px_rgba(179,220,38,0.15)] border border-[rgba(255,255,255,0.08)]">
              <img src="/pro-banner.png" alt="Pro Training" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 opacity-90" />
              <div className="absolute inset-0 bg-gradient-to-t from-[#000000]/90 via-[#000000]/40 to-transparent flex flex-col justify-end p-6">
                <span className="text-[#BFF367] text-[10px] font-black uppercase tracking-[0.2em] mb-1">Elite Training</span>
                <h3 className="text-white font-black text-2xl sm:text-3xl max-w-[280px] leading-tight tracking-tight" style={{ fontFamily: "'Open Sans', sans-serif" }}>ELEVATE YOUR GAME</h3>
              </div>
            </div>
          </div>

        {/* Grid Content */}
        {loading ? (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 xl:grid-cols-6 gap-3">
            {[...Array(12)].map((_, i) => (
              <div key={i} className="aspect-[1/1.3] rounded-[8px] bg-white/5 border border-white/5 animate-pulse" />
            ))}
          </div>
        ) : professionals.length === 0 ? (
          <div className="mx-2 md:mx-0 text-center py-12 px-4 border border-[rgba(255,255,255,0.08)] rounded-[16px] bg-[#111] relative overflow-hidden shadow-2xl">
            <div className="relative z-10 flex flex-col items-center">
              <img src="/empty-pros.png" alt="No Professionals Found" className="w-full max-w-[200px] h-[140px] object-cover mb-6 border border-white/5 rounded-2xl" />
              <h3 className="text-lg font-black uppercase tracking-[0.1em] text-[#BFF367] mb-2">Your Next Coach is Waiting</h3>
              <p className="text-white/50 text-[13px] max-w-[280px] leading-relaxed">
                We couldn't find any professionals matching your exact search. Adjust your location or filters to connect with elite trainers!
              </p>
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3">
            {professionals.map((pro) => (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.25 }}
                key={pro.id || pro._id}
                className="relative rounded-[16px] border border-[rgba(255,255,255,0.08)] bg-[#1A1A1A] overflow-hidden transition-all duration-500 group hover:border-[#B3DC26]/50 hover:shadow-[0px_8px_24px_rgba(85,222,232,0.10)] h-56 cursor-pointer"
                onClick={() => navigate(`/profile/${pro.userId || pro.id || pro._id}`)}
              >
                {/* Background Image or Initials */}
                {(pro.image || pro.profilePicture) ? (
                  <img
                    src={pro.image || pro.profilePicture}
                    alt={pro.name}
                    className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 grayscale-[20%] group-hover:grayscale-0"
                    onError={(e) => {
                      e.target.style.display = "none";
                      e.target.nextElementSibling.style.display = "flex";
                    }}
                  />
                ) : null}
                <div
                  className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-[#1a1a1a] to-[#000000]"
                  style={{
                    display: (pro.image || pro.profilePicture) ? "none" : "flex",
                  }}
                >
                  <span className="text-transparent bg-clip-text bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] font-inter font-[700] text-4xl opacity-50">
                    {getInitials(pro.name)}
                  </span>
                </div>

                {/* Gradient Overlay for text readability */}
                <div className="absolute inset-0 bg-gradient-to-t from-[#000000] via-[#000000]/60 to-transparent" />

                {/* Role Badge - Top Right */}
                <div className="absolute top-2 right-2 px-1.5 py-0.5 rounded-full text-[9px] font-[700] font-inter text-[#000000] bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] z-10 uppercase shadow-lg">
                  {pro.role}
                </div>

                {/* Bottom Content */}
                <div className="absolute bottom-0 left-0 right-0 p-3 flex flex-col z-10">
                  {/* Player Name and Rating Row */}
                  <div className="flex items-start justify-between gap-2 mb-0.5">
                    <h3 className="text-[#FFFFFF] text-[14px] font-[600] leading-[20px] line-clamp-1 font-inter">
                      {pro.name || "Anonymous"}
                    </h3>
                    <div className="flex items-center text-[#B3DC26] text-[9px] font-black gap-0.5 shadow-lg bg-[#1B1B1B]/80 backdrop-blur-md border border-[rgba(255,255,255,0.08)] px-1.5 py-0.5 rounded-full shrink-0">
                      <Star size={8} className="fill-[#B3DC26]" />
                      {pro.rating?.toFixed(1) || "5.0"}
                    </div>
                  </div>

                  {/* Location */}
                  <p className="text-[rgba(255,255,255,0.70)] text-[11px] font-[400] leading-[14px] line-clamp-1 mb-1 font-inter">
                    {pro.city ? pro.city.split(",")[0].trim() : pro.location || "Local Provider"}
                  </p>
                </div>
              </motion.div>
            ))}
          </div>
        )}
        </div>
      </div>

      {/* ── Floating Request Match CTA Button ────────────────────────── */}
      {!showMatchModal && (
        <button
          onClick={() => {
            if (!isLoggedIn) {
              toast.error("Please login to request matchmaking");
              navigate("/login");
              return;
            }
            setShowMatchModal(true);
          }}
          className="fixed bottom-24 md:bottom-8 left-1/2 -translate-x-1/2 z-[60] flex items-center gap-1.5 px-4 py-2.5 rounded-full bg-gradient-to-r from-[#BFF367] to-[#BFF367] text-black font-black text-[10px] uppercase tracking-widest shadow-[0_8px_32px_rgba(85,222,232,0.3)] hover:shadow-[0_8px_40px_rgba(85,222,232,0.5)] hover:scale-105 active:scale-95 transition-all duration-300 group"
        >
          <Zap size={14} className="group-hover:animate-pulse" />
          Find Pro's
        </button>
      )}

      {/* ── Match Request Modal ──────────────────────────────────────── */}
      {showMatchModal && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-sm"
            onClick={() => !isCreatingRequest && setShowMatchModal(false)}
          />

          {/* Modal Content */}
          <motion.div 
            initial={{ opacity: 0, y: "100%" }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto bg-[#0a0a0c] border border-white/10 rounded-t-3xl sm:rounded-2xl shadow-[0_-8px_40px_rgba(191,243,103,0.1)] sm:shadow-[0_24px_80px_rgba(191,243,103,0.1)]"
          >
            {/* Modal Header */}
            <div className="sticky top-0 z-10 bg-[#0a0a0c]/95 backdrop-blur-xl border-b border-white/5 p-5 flex items-center justify-between rounded-t-3xl sm:rounded-t-2xl">
              <div className="flex items-center gap-3">
                <div>
                  <h2 className="text-lg font-bold uppercase tracking-tight text-white" style={{ fontFamily: "'Open Sans', sans-serif" }}>Find Professional</h2>
                  <p className="text-[10px] text-white/50" style={{ fontFamily: "'Inter 28pt Light', sans-serif" }}>On-demand matching for coaches, umpires & scorers.</p>
                </div>
              </div>
              <button
                onClick={() => !isCreatingRequest && setShowMatchModal(false)}
                className="p-2 rounded-lg hover:bg-white/5 text-white/40 hover:text-white transition-colors bg-white/5"
              >
                <X size={18} />
              </button>
            </div>

            {/* Modal Body */}
            {isCreatingRequest ? (
              <div className="p-10 sm:p-16 flex flex-col items-center justify-center space-y-8 min-h-[400px]">
                <div className="relative flex items-center justify-center w-32 h-32">
                  <div className="absolute inset-0 border-[3px] border-[#BFF367] rounded-full animate-ping opacity-75"></div>
                  <div className="absolute inset-2 border-[3px] border-[#BFF367] rounded-full animate-ping opacity-60" style={{ animationDelay: '0.2s' }}></div>
                  <div className="absolute inset-4 border-[3px] border-white/20 rounded-full animate-ping opacity-50" style={{ animationDelay: '0.4s' }}></div>
                  <div className="relative bg-[#0d0d0e] rounded-full p-5 border border-white/10 z-10 shadow-[0_0_40px_rgba(191,243,103,0.4)]">
                    <Search size={40} className="text-[#BFF367] animate-pulse" />
                  </div>
                </div>
                <div className="text-center space-y-3">
                  <h3 className="text-xl sm:text-2xl font-black text-white uppercase tracking-widest animate-pulse">Finding Pros...</h3>
                  <p className="text-xs sm:text-sm text-white/50 max-w-[280px] mx-auto leading-relaxed">Analyzing your request and matching with the best professionals nearby</p>
                </div>
              </div>
            ) : (
              <form onSubmit={handleRequestMatch} className="p-5 sm:p-6 space-y-5">
              {/* Roles Selection — Scrollable Inline Row */}
              <div>
                <label className="text-[10px] font-black uppercase text-white/50 tracking-wider block mb-2">Roles</label>
                <div className="flex overflow-x-auto gap-2 pb-2 [&::-webkit-scrollbar]:hidden" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
                  {["COACH", "UMPIRE", "SCORER", "STREAMER", "CHEERLEADER"].map((roleVal) => {
                    const isSelected = selectedRoles.includes(roleVal);
                    return (
                      <button
                        key={roleVal}
                        type="button"
                        onClick={() => handleToggleRole(roleVal)}
                        className={`px-4 py-2 shrink-0 rounded-[8px] text-[10px] font-bold uppercase tracking-wider transition-all flex items-center gap-1.5 ${isSelected
                            ? "bg-[#BFF367]/15 border border-[#BFF367] text-[#BFF367]"
                            : "bg-white/5 border border-white/10 text-white/50 hover:border-white/25 hover:text-white/70"
                          }`}
                      >
                        {isSelected && <Check size={10} strokeWidth={3} />}
                        {roleVal}
                      </button>
                    );
                  })}
                </div>
              </div>

              {/* Venue Selector */}
              <div>
                <label className="text-[10px] font-black uppercase text-white/50 tracking-wider block mb-2">Venue / Location</label>
                <div className="space-y-3 relative">
                  <select
                    value={selectedGroundId}
                    onChange={(e) => {
                      const val = e.target.value;
                      setSelectedGroundId(val);
                      if (val !== "custom") {
                        setCustomLocation({ latitude: "", longitude: "", address: "" });
                      } else {
                        setShowLocationSearchModal(true);
                      }
                    }}
                    className="w-full bg-black border border-white/10 rounded-lg p-3 pr-24 text-xs font-bold text-white focus:border-[#BFF367] outline-none appearance-none"
                  >
                    <option value="">-- Choose Venue/Ground --</option>
                    {grounds.map((g) => (
                      <option key={g._id} value={g._id}>
                        {g.name} - {g.city}, {g.state}
                      </option>
                    ))}
                    <option value="custom">
                      {customLocation.address ? `📍 ${customLocation.address.substring(0, 45)}${customLocation.address.length > 45 ? '...' : ''}` : "📍 Search by Location"}
                    </option>
                  </select>

                  <div className="absolute right-3 top-0 bottom-0 flex items-center pointer-events-none">
                    {selectedGroundId === "custom" && customLocation.address ? (
                      <button
                        type="button"
                        onClick={(e) => {
                          e.stopPropagation();
                          setShowLocationSearchModal(true);
                        }}
                        className="text-[9px] font-bold text-[#BFF367] hover:text-white px-3 py-1.5 rounded bg-[#BFF367]/10 hover:bg-[#BFF367]/20 transition-colors pointer-events-auto mr-3"
                      >
                        CHANGE
                      </button>
                    ) : null}
                    <ChevronDown size={16} className="text-white/50" />
                  </div>

                  {selectedGroundId === "custom" && !customLocation.address && (
                    <div className="p-4 rounded-lg bg-black border border-white/5 space-y-3 animate-in fade-in duration-200">
                      <button
                        type="button"
                        onClick={() => setShowLocationSearchModal(true)}
                        className="w-full py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-xs font-bold text-white transition-colors flex items-center justify-center gap-2"
                      >
                        <MapPin size={14} className="text-[#BFF367]" />
                        Open Location Search
                      </button>
                    </div>
                  )}
                </div>
              </div>

              {/* Schedule / Timing Selection */}
              <div>
                <label className="text-[10px] font-black uppercase text-white/50 tracking-wider block mb-2">Match Schedule</label>
                <div className="flex items-center bg-[#111] border border-white/10 rounded-lg divide-x divide-white/10 overflow-hidden">
                  <div className="flex-[1.2] p-2.5 relative group hover:bg-white/5 transition-colors">
                    <span className="text-[8px] text-[#BFF367] font-bold uppercase mb-1 flex items-center gap-1">
                      <Calendar size={10} /> Date
                    </span>
                    <div className="text-[11px] sm:text-xs font-bold text-white group-hover:text-[#BFF367] transition-colors truncate">
                      {formatDisplayDate(matchDate)}
                    </div>
                    <input
                      type="date"
                      value={matchDate}
                      onChange={(e) => setMatchDate(e.target.value)}
                      onClick={(e) => e.target.showPicker && e.target.showPicker()}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      required
                    />
                  </div>
                  <div className="flex-1 p-2.5 relative group hover:bg-white/5 transition-colors">
                    <span className="text-[8px] text-white/40 font-bold uppercase mb-1 flex items-center gap-1">
                      <Clock size={10} /> Start
                    </span>
                    <div className="text-[11px] sm:text-xs font-bold text-white truncate">
                      {formatDisplayTime(matchStartTime)}
                    </div>
                    <input
                      type="time"
                      value={matchStartTime}
                      onChange={(e) => setMatchStartTime(e.target.value)}
                      onClick={(e) => e.target.showPicker && e.target.showPicker()}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      required
                    />
                  </div>
                  <div className="flex-1 p-2.5 relative group hover:bg-white/5 transition-colors">
                    <span className="text-[8px] text-white/40 font-bold uppercase mb-1 flex items-center gap-1">
                      <Clock size={10} /> End
                    </span>
                    <div className="text-[11px] sm:text-xs font-bold text-white truncate">
                      {formatDisplayTime(matchEndTime)}
                    </div>
                    <input
                      type="time"
                      value={matchEndTime}
                      onChange={(e) => setMatchEndTime(e.target.value)}
                      onClick={(e) => e.target.showPicker && e.target.showPicker()}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      required
                    />
                  </div>
                </div>
              </div>

              {/* Budget Slider */}
              <div>
                <div className="flex items-center justify-between mb-3">
                  <label className="text-[10px] font-black uppercase text-white/50 tracking-wider">Budget (₹)</label>
                  <span className="text-xs font-bold text-[#BFF367]">₹{budget}</span>
                </div>
                <div className="space-y-3">
                  <div className="flex items-center gap-3">
                    <span className="text-[9px] font-bold text-white/40 w-6 shrink-0">Max</span>
                    <div className="flex-1 relative">
                      <input
                        type="range"
                        min={500}
                        max={10000}
                        step={100}
                        value={budget}
                        onChange={(e) => setBudget(parseInt(e.target.value))}
                        className="w-full h-1.5 bg-white/10 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[#BFF367] [&::-webkit-slider-thumb]:shadow-[0_0_8px_rgba(191,243,103,0.4)] [&::-webkit-slider-thumb]:cursor-grab [&::-webkit-slider-thumb]:active:cursor-grabbing [&::-moz-range-thumb]:w-4 [&::-moz-range-thumb]:h-4 [&::-moz-range-thumb]:rounded-full [&::-moz-range-thumb]:bg-[#BFF367] [&::-moz-range-thumb]:border-0"
                      />
                    </div>
                  </div>
                </div>
              </div>



              {/* Submit Button */}
              <button
                type="submit"
                disabled={isCreatingRequest}
                className="w-full py-4 rounded-lg bg-gradient-to-r from-[#BFF367] to-[#BFF367] text-black font-black text-xs uppercase tracking-widest hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-[0_4px_20px_rgba(191,243,103,0.2)] hover:shadow-[0_4px_25px_rgba(191,243,103,0.4)]"
              >
                {isCreatingRequest ? (
                  <>
                    <Loader2 className="animate-spin text-black" size={16} />
                    Initiating Match...
                  </>
                ) : (
                  "⚡ FIND PRO'S"
                )}
              </button>

              {/* Info Footer */}
              <p className="text-[9px] text-white/30 text-center leading-relaxed">
                Your max budget will be reserved from your wallet as escrow. After a match is confirmed, check your{" "}
                <Link to="/booking-history?subTab=professionals" className="text-[#BFF367] underline hover:text-[#BFF367]/80">
                  Booking History
                </Link>{" "}
                for OTP verification and status updates.
              </p>
            </form>
            )}
          </motion.div>
        </div>
      )}

      {/* Location Search Modal */}
      {showLocationSearchModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-6">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowLocationSearchModal(false)} />
          <div className="relative w-full max-w-md bg-[#0a0a0a] border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            {/* Header */}
            <div className="p-4 border-b border-white/5 flex items-center justify-between bg-black">
              <div className="flex items-center gap-2">
                <MapPin size={16} className="text-[#BFF367]" />
                <h3 className="text-sm font-bold text-white uppercase tracking-wider">Search Location</h3>
              </div>
              <button
                onClick={() => setShowLocationSearchModal(false)}
                className="p-1.5 rounded-full hover:bg-white/10 text-white/50 hover:text-white transition-colors"
              >
                <X size={16} />
              </button>
            </div>

            {/* Content */}
            <div className="p-4 flex flex-col min-h-[300px]">
              <div ref={locationSearchRef} className="relative">
                <div className="flex justify-end mb-3">
                  <button
                    type="button"
                    onClick={() => {
                      handleDetectLocation();
                    }}
                    className="px-3 py-1.5 bg-[#BFF367]/10 hover:bg-[#BFF367]/20 text-[10px] font-bold text-[#BFF367] border border-[#BFF367]/20 rounded flex items-center gap-1.5 transition-all"
                  >
                    <Navigation size={12} />
                    Detect My GPS Location
                  </button>
                </div>
                <div className="relative z-10">
                  <MapPin size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-white/30" />
                  <input
                    type="text"
                    placeholder="Search for a place, city, or area..."
                    value={locationQuery}
                    onChange={(e) => handleLocationSearch(e.target.value)}
                    onFocus={() => locationResults.length > 0 && setShowLocationDropdown(true)}
                    className="w-full bg-neutral-900 border border-white/10 rounded-xl pl-10 pr-10 py-3.5 text-sm text-white outline-none focus:border-[#BFF367] transition-colors placeholder-white/30 shadow-inner"
                    autoComplete="off"
                    autoFocus
                  />
                  {locationSearching && (
                    <Loader2 size={16} className="absolute right-3.5 top-1/2 -translate-y-1/2 text-[#BFF367] animate-spin" />
                  )}
                </div>

                {/* Search Results Dropdown inside Modal */}
                {showLocationDropdown && locationResults.length > 0 && (
                  <div className="absolute top-full left-0 right-0 z-50 mt-2 bg-[#111] border border-white/10 rounded-xl shadow-[0_16px_48px_rgba(0,0,0,0.6)] overflow-hidden max-h-60 overflow-y-auto">
                    {locationResults.map((place, idx) => {
                      const parts = place.display_name.split(", ");
                      const primary = parts[0];
                      const secondary = parts.slice(1, 3).join(", ");
                      return (
                        <button
                          key={place.place_id || idx}
                          type="button"
                          onClick={() => handleSelectLocation(place)}
                          className="w-full flex items-start gap-3 px-4 py-3 hover:bg-white/5 text-left transition-colors border-b border-white/5 last:border-b-0 group"
                        >
                          <MapPin size={16} className="text-[#BFF367]/60 mt-0.5 shrink-0 group-hover:text-[#BFF367]" />
                          <div className="min-w-0 flex-1">
                            <p className="text-sm font-bold text-white truncate group-hover:text-[#BFF367] transition-colors">{primary}</p>
                            <p className="text-[11px] text-white/40 truncate mt-0.5">{secondary}</p>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                )}

                {locationQuery.length >= 3 && !locationSearching && locationResults.length === 0 && (
                  <div className="mt-4 p-4 rounded-lg bg-white/5 border border-white/10 text-center">
                    <p className="text-xs text-white/50">No locations found. Try a different search term.</p>
                  </div>
                )}

                {locationQuery.length < 3 && (
                  <div className="mt-6 flex flex-col items-center justify-center opacity-30 text-center px-6">
                    <MapPin size={32} className="mb-3 text-white" />
                    <p className="text-xs text-white/70">Type at least 3 characters to search for a location anywhere in India.</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { 
  IndianRupee, 
  Landmark, 
  ArrowUpRight, 
  CheckCircle, 
  AlertCircle,
  Edit2,
  X,
  Clock,
  TrendingUp,
  AlertTriangle,
  Info
} from "lucide-react";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import axios from "axios";
import { 
  BarChart,
  Bar,
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from "recharts";

const PayoutsTab = ({ role }) => {
  const [banking, setBanking] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  
  // Banking Form state
  const [accountName, setAccountName] = useState("");
  const [accountNumber, setAccountNumber] = useState("");
  const [ifscCode, setIfscCode] = useState("");
  const [bankName, setBankName] = useState("");
  const [upiId, setUpiId] = useState("");
  const [payoutMode, setPayoutMode] = useState("BANK"); // BANK or UPI
  
  // UI States
  const [isEditingBank, setIsEditingBank] = useState(false);
  const [isWithdrawModalOpen, setIsWithdrawModalOpen] = useState(false);
  const [withdrawAmount, setWithdrawAmount] = useState("");
  const [isSubmittingPayout, setIsSubmittingPayout] = useState(false);
  const [isSavingDetails, setIsSavingDetails] = useState(false);
  
  // Card Description Toggles
  const [activeDescCard, setActiveDescCard] = useState(null); // 'usable', 'reserved', 'dispute', 'lifetime' or null
  
  // Feedback
  const [feedbackMsg, setFeedbackMsg] = useState("");
  const [feedbackType, setFeedbackType] = useState("success");

  // Lifetime Earnings Filter state
  const [earningsFilter, setEarningsFilter] = useState("ALL_TIME"); // TODAY, 7_DAYS, THIS_MONTH, LAST_MONTH, CUSTOM
  const [customStartDate, setCustomStartDate] = useState(null);
  const [customEndDate, setCustomEndDate] = useState(null);

  // Mock comparison chart data based on filter selection
  const [chartData, setChartData] = useState([]);

  // Fetch Banking details & wallet balances from API
  const fetchBankingDetails = async () => {
    setIsLoading(true);
    try {
      const token = localStorage.getItem("token") || "";
      const res = await axios.get("/api/owner/banking", {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.data) {
        setBanking(res.data);
        const details = res.data.bankingDetails || {};
        setAccountName(details.accountName || "");
        setAccountNumber(details.accountNumber || "");
        setIfscCode(details.ifscCode || "");
        setBankName(details.bankName || "");
        setUpiId(details.upiId || "");
        setPayoutMode(details.payoutMode || "BANK");
        
        // If banking details aren't fully configured, force edit mode to display form at top
        if (!details.accountName) {
          setIsEditingBank(true);
        } else {
          setIsEditingBank(false);
        }
      }
    } catch (err) {
      console.error("Failed to load banking details", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchBankingDetails();
  }, []);

  // Generate chart data from live balances
  useEffect(() => {
    if (!banking) return;
    const usable = parseFloat(banking.walletBalance || 0);
    const reserved = parseFloat(banking.reservedBalance || 0);
    const dispute = parseFloat(banking.disputeBalance || 0);
    const withdrawn = parseFloat(banking.withdrawnBalance || 0);
    setChartData([
      { name: "Usable", "Current Balance": usable, "Withdrawn": 0 },
      { name: "Reserved", "Current Balance": reserved, "Withdrawn": 0 },
      { name: "Dispute", "Current Balance": dispute, "Withdrawn": 0 },
      { name: "Withdrawn", "Current Balance": 0, "Withdrawn": withdrawn },
    ]);
  }, [banking]);

  // Save Banking Configuration
  const handleSaveBanking = async (e) => {
    e.preventDefault();
    setFeedbackMsg("");
    setIsSavingDetails(true);
    try {
      const token = localStorage.getItem("token") || "";
      const payload = {
        accountName,
        payoutMode,
        ...(payoutMode === "BANK" ? { accountNumber, ifscCode, bankName } : { upiId })
      };
      
      const res = await axios.put("/api/owner/banking", payload, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.data) {
        setFeedbackType("success");
        setFeedbackMsg("Banking configurations saved successfully and sent for pending verification!");
        setIsEditingBank(false);
        fetchBankingDetails();
      }
    } catch (err) {
      setFeedbackType("error");
      setFeedbackMsg(err.response?.data?.message || "Failed to save banking configurations.");
    } finally {
      setIsSavingDetails(false);
    }
  };

  // Submit Withdrawal Request
  const handleRequestPayout = async (e) => {
    e.preventDefault();
    setFeedbackMsg("");
    
    const amountNum = parseFloat(withdrawAmount);
    if (isNaN(amountNum) || amountNum <= 0) {
      setFeedbackType("error");
      setFeedbackMsg("Please enter a valid withdrawal amount.");
      return;
    }

    if (amountNum > parseFloat(banking?.walletBalance || 0)) {
      setFeedbackType("error");
      setFeedbackMsg("Insufficient usable balance in wallet.");
      return;
    }

    setIsSubmittingPayout(true);
    try {
      const token = localStorage.getItem("token") || "";
      const res = await axios.post("/api/owner/banking/payout", { amount: amountNum }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      if (res.data) {
        setFeedbackType("success");
        setFeedbackMsg("Withdrawal request submitted successfully! Pending admin approval.");
        setWithdrawAmount("");
        setIsWithdrawModalOpen(false);
        fetchBankingDetails();
      }
    } catch (err) {
      setFeedbackType("error");
      setFeedbackMsg(err.response?.data?.message || "Failed to process withdrawal request.");
    } finally {
      setIsSubmittingPayout(false);
    }
  };

  const walletBalance = parseFloat(banking?.walletBalance || 0);
  const reservedBalance = parseFloat(banking?.reservedBalance || 0);
  const disputeBalance = parseFloat(banking?.disputeBalance || 0);
  const withdrawnBalance = parseFloat(banking?.withdrawnBalance || 0);

  // Calculate Lifetime Earning based on live balances
  const getFilteredLifetimeEarning = () => {
    return walletBalance + reservedBalance + disputeBalance + withdrawnBalance;
  };

  const hasConfiguredBank = banking?.bankingDetails && banking.bankingDetails.accountName;
  const kycStatus = banking?.bankingDetails?.kycStatus || "PENDING";

  return (
    <div className="space-y-6 text-white font-inter">
      {/* feedback message banner */}
      {feedbackMsg && (
        <div className={`p-4 rounded-xl border flex items-start gap-3 animate-in fade-in duration-300 ${feedbackType === "success" ? "bg-green-500/10 border-green-500/20 text-green-400" : "bg-red-500/10 border-red-500/20 text-red-400"}`}>
          {feedbackType === "success" ? <CheckCircle size={20} className="flex-shrink-0" /> : <AlertCircle size={20} className="flex-shrink-0" />}
          <span className="text-sm font-medium flex-1">{feedbackMsg}</span>
          <button onClick={() => setFeedbackMsg("")} className="text-gray-400 hover:text-white transition-colors">
            <X size={16} />
          </button>
        </div>
      )}

      {/* TOP BANK DETAILS SECTION */}
      <div className="p-6 rounded-2xl bg-gradient-to-br from-[#141414] to-[#0d0d0d] border border-[#2D2D2D] space-y-6 relative overflow-hidden">
        {/* Glow element */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-[#BFF367]/5 blur-[80px] pointer-events-none" />

        {isEditingBank ? (
          // BANK CONFIGURATION INPUT FORM
          <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-[#2D2D2D] pb-4">
              <div className="flex items-center gap-2.5">
                <Landmark size={22} className="text-[#BFF367]" />
                <div>
                  <h3 className="text-lg font-bold tracking-tight">Configure Payout Destination</h3>
                  <p className="text-xs text-gray-400">Fill details to request payouts. Verification status will show as pending.</p>
                </div>
              </div>
              {hasConfiguredBank && (
                <button 
                  onClick={() => setIsEditingBank(false)}
                  className="px-3.5 py-1.5 rounded-lg bg-[#222] hover:bg-[#333] text-xs font-semibold border border-white/5 transition-all"
