const CustomDropdown = ({ value, onChange, options, placeholder, className, disabled }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (containerRef.current && !containerRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const normalizedOptions = options.map(o => typeof o === 'string' ? { value: o, label: o } : o);
  const selectedLabel = normalizedOptions.find(o => String(o.value) === String(value))?.label || placeholder;

  return (
    <div className={`relative ${className}`} ref={containerRef}>
      <button
        type="button"
        disabled={disabled}
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full h-[40px] bg-[#121212] border border-white/10 rounded-[12px] px-3 flex items-center justify-between transition-colors focus:border-[#55DEE8]/30 ${disabled ? 'opacity-50 cursor-not-allowed' : 'hover:border-white/20'}`}
      >
        <span className="truncate text-white text-sm font-bold">{selectedLabel}</span>
      </button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: -5 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -5 }}
            transition={{ duration: 0.15 }}
            className="absolute z-50 top-full mt-1 left-0 w-full min-w-[120px] bg-[#1A1A1A] border border-white/10 rounded-[12px] shadow-xl overflow-hidden max-h-48 overflow-y-auto scrollbar-hide"
          >
            {normalizedOptions.map((opt, i) => (
              <button
                key={i}
                type="button"
                onClick={() => {
                  onChange(opt.value);
                  setIsOpen(false);
                }}
                className={`w-full text-left px-3 py-2.5 text-sm transition-colors hover:bg-white/5 ${String(value) === String(opt.value) ? 'text-[#55DEE8] font-bold bg-[#55DEE8]/5' : 'text-white'}`}
              >
                {opt.label}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>



  );
};

