                  onClick={() => {
                    if (formData.scoringPassword.trim() !== '' && formData.scoringPassword.length >= 6) {
                      setShowPasswordPopup(false);
                      handleSubmit();
                    }
                  }} 
                  disabled={isLoading || formData.scoringPassword.trim() === '' || formData.scoringPassword.length < 6}
