                    <div className="relative w-full rounded-[16px] overflow-hidden border border-white/10 shadow-[var(--shadow-1)]" style={{ height: 220 }}>
                      <iframe title="Location Preview" src={mapPreviewUrl} width="100%" height="100%" style={{ border: 0, filter: "invert(90%) hue-rotate(180deg) saturate(0.7) brightness(0.9)" }} loading="lazy" />
                    </div>
                  </div>
                )}
            </div>
          )}

          {/* STEP 2: Legalities & Management */}
          {currentStep === 2 && (
            <div className="col-span-1 grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12 relative z-10 animate-fade-in">
              <div className="space-y-4 md:space-y-8">
                <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-8 uppercase tracking-[3px]">Legal Documents</h3>
                
                <div className="grid grid-cols-2 gap-x-3 gap-y-4 md:gap-x-8 md:gap-y-6">
                  {[
                    { name: "gstRegistration", label: "GST Registration" },
                    { name: "saleDeed", label: <>Sale Deed <span className="text-red-500">*</span></> },
                    { name: "electricityBill", label: <>Electricity Bill <span className="text-red-500">*</span></> },
                    { name: "rentalAgreement", label: "Rental Agreement" },
                    { name: "ownershipAgreement", label: "Ownership Agreement" },
                    { name: "googleProfileScreenshot", label: "Google Profile Screenshot" }
                  ].map(doc => {
                    const selectedFiles = watch(doc.name);
                    const hasFile = selectedFiles && selectedFiles.length > 0;
                    return (
                      <div className="form-control" key={doc.name}>
                        <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">{doc.label}</span></label>
                        <input type="file" accept=".pdf,image/*" className={`w-full bg-[#121212] border ${errors[doc.name] ? 'border-red-500' : 'border-white/10'} text-white/70 text-[6px] md:text-sm file:bg-[#1B1B1B] file:text-white file:border-none file:px-2 md:file:px-6 file:h-7 md:file:h-12 file:mr-1 md:file:mr-4 file:font-bold file:uppercase file:text-[6px] md:file:text-[10px] file:tracking-widest rounded-[16px] md:rounded-[16px] h-7 md:h-12 flex items-center focus:outline-none transition-all cursor-pointer`} onChange={(e) => setValue(doc.name, e.target.files, { shouldValidate: true })} />
                        {hasFile && (
                          <span className="text-[#B3DC26] text-[8px] md:text-[10px] font-bold mt-2 block ml-1 truncate">
                            ✅ Selected: {selectedFiles[0].name}
                          </span>
                        )}
                        {errors[doc.name] && <span className="text-red-500 text-[8px] md:text-[10px] font-bold uppercase mt-1 md:mt-2 block ml-1">{errors[doc.name].message}</span>}
                      </div>
                    );
                  })}
                </div>
              </div>
              <div className="space-y-4 md:space-y-8">
                <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-8 uppercase tracking-[3px]">Management & Policies</h3>

                <div className="form-control space-y-4">
                  <label className="label"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Venue Managers (Contacts)</span></label>
                  <div className="grid grid-cols-1 md:grid-cols-[1fr_1fr_auto] gap-4">
                    <input type="text" placeholder="Manager Name" value={newManagerName} onChange={(e) => setNewManagerName(e.target.value)} className="w-full bg-[#121212] border border-white/10 text-white text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 focus:outline-none focus:border-[#B3DC26]/60" />
                    <input type="text" placeholder="Phone" value={newManagerPhone} onChange={(e) => setNewManagerPhone(e.target.value)} className="w-full bg-[#121212] border border-white/10 text-white text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 focus:outline-none focus:border-[#B3DC26]/60" />
                    <button type="button" onClick={addManagerContact} className="w-full md:w-auto px-8 h-12 rounded-[16px] bg-[#1B1B1B] text-white hover:bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none  transition-all text-[11px] font-bold uppercase tracking-widest">Add</button>
                  </div>
                  <div className="space-y-3 max-h-[150px] overflow-y-auto custom-scrollbar pr-2">
                    {managerContacts.map((manager, index) => (
                      <div key={index} className="flex items-center justify-between bg-[#121212] p-4 rounded-[16px] border border-white/10">
                        <div className="flex flex-col">
                          <span className="text-white text-[13px] font-bold uppercase tracking-tight">{manager.name}</span>
                          <span className="text-white/70 text-[11px] font-mono mt-0.5">{manager.phone}</span>
                        </div>
                        <button type="button" onClick={() => removeManagerContact(index)} className="text-[#444] hover:text-[#B3DC26] transition-colors uppercase text-[10px] font-bold tracking-widest">Remove</button>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Venue Policies and Rules</span></label>
                  <textarea {...register("policies")} maxLength={1000} className={`w-full bg-[#121212] border ${errors.policies ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-32 md:h-48 rounded-[16px] md:rounded-[16px] p-3 md:p-4 transition-all`}></textarea>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: Slot Management */}
          {currentStep === 3 && (
            <div className="col-span-1 grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12 relative z-10 animate-fade-in">
              <div className="space-y-4 md:space-y-8">
                <div className="grid grid-cols-2 gap-6">
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Slot Duration</span></label>
                    <select {...register("slotDuration")} className={`w-full bg-[#121212] border ${errors.slotDuration ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all appearance-none`}>
                      <option value={30}>30 Minutes</option>
                      <option value={60}>60 Minutes</option>
                      <option value={90}>90 Minutes</option>
                      <option value={120}>120 Minutes</option>
                    </select>
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Break Time</span></label>
                    <select {...register("breakTime")} className={`w-full bg-[#121212] border ${errors.breakTime ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all appearance-none`}>
                      <option value={0}>No Break</option>
                      <option value={10}>10 Minutes</option>
                      <option value={15}>15 Minutes</option>
                      <option value={30}>30 Minutes</option>
                    </select>
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Opening Time</span></label>
                    <input type="time" {...register("openTime")} className={`w-full bg-[#121212] border ${errors.openTime ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all [color-scheme:dark]`} />
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Closing Time</span></label>
                    <input type="time" {...register("closeTime")} disabled={!openTime} className={`w-full bg-[#121212] border ${errors.closeTime ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all disabled:opacity-50 [color-scheme:dark]`} />
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Hourly Rate (INR)</span></label>
                  <input type="number" placeholder="Hourly Rate (INR)" {...register("pricePerHour")} className={`w-full bg-[#121212] border ${errors.pricePerHour ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all`} />
                  {errors.pricePerHour && <span className="text-[#B3DC26] text-[8px] md:text-[10px] font-bold uppercase mt-1 md:mt-2 block ml-1">{errors.pricePerHour.message}</span>}
                </div>

                <div className="space-y-6">
                  <label className="label"><span className="text-[8px] md:text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Weekly Operational Sequence</span></label>
                  <div className="flex w-full gap-1 md:gap-3">
                    {["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"].map(day => {
                      const isActive = availableDays.includes(day);
                      return (
                        <button key={day} type="button" onClick={() => toggleDay(day)} className={`flex-1 py-2 md:py-3 rounded-[16px] md:rounded-[16px] text-[8px] md:text-[11px] font-black uppercase tracking-wider md:tracking-widest transition-all  ${ isActive ? "bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black -[#B3DC26] shadow-[0_5px_15px_rgba(204,255,0,0.2)]" : "bg-[#121212] text-[#444] -white/10 hover:-[#B3DC26]/40" }`}>
                          {day.substring(0, 3)}
                        </button>
                      );
                    })}
                  </div>
                </div>
              </div>

              <div className="space-y-4 md:space-y-8">
                  <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-6 uppercase tracking-[3px]">Slot Review</h3>
                  {generatedSlots.length > 0 ? (
                      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                        {generatedSlots.map((slot, index) => (
                          <div 
                            key={index} 
                            className={`group p-4 md:p-5 rounded-[16px] border transition-all duration-300 relative overflow-hidden flex flex-col justify-between ${ 
                              slot.isActive 
                                ? "bg-[#121212] border-[#B3DC26]/40 shadow-[0_4px_20px_-4px_rgba(191,243,103,0.1)] hover:border-[#B3DC26]/80" 
                                : "bg-[#121212] border-white/10 opacity-60 hover:opacity-100 hover:border-white/20" 
                            }`}
                          >
                            {/* Ambient Glow */}
                            {slot.isActive && (
                              <div className="absolute top-0 right-0 w-24 h-24 bg-[#B3DC26]/10 blur-[24px] rounded-full -mr-10 -mt-10 pointer-events-none transition-all duration-500 group-hover:bg-[#B3DC26]/20" />
                            )}
                            
                            <div className="flex justify-between items-center mb-5 relative z-10">
                              <div className="flex flex-col">
                                <span className={`text-[12px] md:text-[14px] font-bold font-mono tracking-tight transition-colors ${slot.isActive ? 'text-white' : 'text-white/70'}`}>
                                  {slot.startTime} <span className="text-white/70 font-light mx-1">→</span> {slot.endTime}
                                </span>
                              </div>
                              <input 
                                type="checkbox" 
                                className="toggle toggle-sm bg-[#1B1B1B] border-none checked:bg-[#B3DC26] hover:bg-[#2A2A2A] transition-all cursor-pointer" 
                                checked={slot.isActive} 
                                onChange={() => toggleSlotActive(index)} 
                              />
                            </div>
                            
                            <div className={`flex items-center gap-2 rounded-[16px] p-2.5 border transition-all duration-300 relative z-10 ${slot.isActive ? 'bg-[#1B1B1B] border-white/10 focus-within:border-[#B3DC26]/50 focus-within:bg-[#121212]' : 'bg-[#121212] border-transparent'}`}>
                              <span className={`text-[12px] md:text-[14px] font-black ${slot.isActive ? 'text-white/40' : 'text-[#444]'}`}>₹</span>
                              <input 
                                type="number" 
                                value={slot.price} 
                                onChange={(e) => updateSlotPrice(index, Number(e.target.value))} 
                                disabled={!slot.isActive} 
                                placeholder="0"
                                className={`w-full bg-transparent text-[15px] md:text-[18px] font-black focus:outline-none font-mono tracking-wide [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none transition-colors ${slot.isActive ? 'text-[#B3DC26]' : 'text-[#444]'}`} 
                              />
                              {slot.isActive && (
                                <span className="text-[9px] uppercase font-bold tracking-widest text-white/70 ml-auto">Per Slot</span>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-12 border border-dashed border-white/10 rounded-[16px] bg-[#121212]">
                        <span className="text-[#444] text-[11px] font-bold uppercase tracking-[4px]">Set times to generate slots</span>
                      </div>
                    )}
              </div>
            </div>
          )}

          {/* Navigation Buttons */}
          <div className={`col-span-1 flex items-center mt-6 md:mt-8 pt-4 md:pt-6 border-t border-white/10 relative z-10 ${currentStep === 1 ? 'justify-between' : 'justify-end'}`}>
            {currentStep === 1 && (
              <button
                type="button"
                onClick={() => navigate(-1)}
                className="px-6 md:px-8 py-2 md:py-3 rounded-[16px] font-bold text-xs md:text-sm text-white bg-[#1B1B1B] border border-white/10 hover:bg-[#2A2A2A] uppercase tracking-wider transition-all duration-300"
              >
                Cancel
              </button>
            )}
            
            <div className="flex items-center gap-3 md:gap-4">
              <button
                type="button"
                onClick={(e) => { e.preventDefault(); setCurrentStep(prev => Math.max(1, prev - 1)); }}
                className={`px-6 md:px-8 py-2 md:py-3 rounded-[16px] font-bold text-xs md:text-sm uppercase tracking-wider transition-all duration-300 ${ currentStep === 1 ? "hidden" : "bg-[#1B1B1B] text-white border border-white/10 hover:bg-[#2A2A2A]" }`}
              >
                Back
              </button>
              
              {currentStep < 3 ? (
                <button
                  type="button"
                  onClick={(e) => { e.preventDefault(); setCurrentStep(prev => Math.min(3, prev + 1)); }}
                  className="px-8 md:px-10 py-2 md:py-3 rounded-[16px] bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] text-black font-bold text-xs md:text-sm uppercase tracking-wider hover:opacity-90 transition-all duration-300 shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none"
                >
                  Next Step
                </button>
              ) : (
                <button
                  type="submit"
                  disabled={loading}
                  className={`px-8 md:px-12 py-2 md:py-3 rounded-[16px] bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] text-black font-bold text-xs md:text-sm uppercase tracking-wider transition-all duration-300 flex items-center gap-2 shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none ${ loading ? "opacity-70 cursor-not-allowed" : "hover:opacity-90" }`}
                >
                  {loading ? "Submitting..." : "Submit Venue"}
                </button>
              )}
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddTurf;

import React, { useState, useEffect } from "react";
import { Controller } from "react-hook-form";
import { FormField } from "@components/common";
import useEditTurf from "@hooks/venue-owner/useEditTurf";
import { fetchStates, fetchCities, searchLocations } from "@utils/locationService";
import { Search, Plus } from "lucide-react";
import toast from "react-hot-toast";

const EditTurf = () => {
  const {
    register,
    handleSubmit,
    errors,
    control,
    setValue,
    watch,
    onSubmit,
    sportTypes,
    newSportType,
    setNewSportType,
    addSportType,
    removeSportType,
    groundTypes,
    newGroundType,
    setNewGroundType,
    addGroundType,
    removeGroundType,
    facilities,
    addFacility,
    removeFacility,
    openTime,
    closeTime,
    slotDuration,
    breakTime,
    availableDays,
    offDays,
    generatedSlots,
    toggleDay,
    toggleSlotActive,
    updateSlotPrice,
    loading,
    getMyLocation,
    isLocating,
    managerContacts,
    newManagerName,
    setNewManagerName,
    newManagerPhone,
    setNewManagerPhone,
    addManagerContact,
    removeManagerContact
  } = useEditTurf();

  const [currentStep, setCurrentStep] = useState(1);
  const [statesList, setStatesList] = useState([]);
  const [citiesList, setCitiesList] = useState([]);
  
  const [locationSearchQuery, setLocationSearchQuery] = useState("");
  const [locationSuggestions, setLocationSuggestions] = useState([]);
  const [isSearchingLocation, setIsSearchingLocation] = useState(false);
  const [showLocationSuggestions, setShowLocationSuggestions] = useState(false);

  const selectedState = watch("state");
  const watchedLat = watch("latitude");
  const watchedLng = watch("longitude");
  const watchedLocation = watch("location");
  const watchedCity = watch("city");
  const watchedPricePerHour = watch("pricePerHour");
  const watchedSlotDuration = watch("slotDuration") || 60;
  const watchedFacilityCategory = watch("facilityCategory") || "Turf";
  const watchedImages = watch("images");
  const watchedMapUrl = watch("mapUrl");

  // Auto-extract lat/lng from Google Maps URL
  useEffect(() => {
    if (watchedMapUrl) {
      const regexAt = /@(-?\d+\.\d+),(-?\d+\.\d+)/;
      const regexQ = /[?&]q=(-?\d+\.\d+),(-?\d+\.\d+)/;
      let lat, lng;
      const matchAt = watchedMapUrl.match(regexAt);
      if (matchAt && matchAt.length >= 3) {
        lat = matchAt[1];
        lng = matchAt[2];
      } else {
        const matchQ = watchedMapUrl.match(regexQ);
        if (matchQ && matchQ.length >= 3) {
          lat = matchQ[1];
          lng = matchQ[2];
        }
      }
      if (lat && lng) {
        if (watchedLat !== lat) setValue("latitude", lat, { shouldValidate: true, shouldDirty: true });
        if (watchedLng !== lng) setValue("longitude", lng, { shouldValidate: true, shouldDirty: true });
      }
    }
  }, [watchedMapUrl, watchedLat, watchedLng, setValue]);

  // Location Autocomplete
  useEffect(() => {
    const delayDebounceFn = setTimeout(async () => {
      if (locationSearchQuery && locationSearchQuery.length >= 3) {
        setIsSearchingLocation(true);
        const results = await searchLocations(locationSearchQuery);
        setLocationSuggestions(results);
        setIsSearchingLocation(false);
      } else {
        setLocationSuggestions([]);
      }
    }, 500);
    return () => clearTimeout(delayDebounceFn);
  }, [locationSearchQuery]);

  const handleLocationSelect = (loc) => {
    setValue("location", loc.display_name, { shouldValidate: true, shouldDirty: true });
    setValue("city", loc.city || loc.suburb || loc.display_name, { shouldValidate: true, shouldDirty: true });
    setValue("state", loc.state || loc.display_name, { shouldValidate: true, shouldDirty: true });
    setValue("latitude", loc.lat, { shouldValidate: true, shouldDirty: true });
    setValue("longitude", loc.lon, { shouldValidate: true, shouldDirty: true });
    setLocationSearchQuery(loc.display_name);
    setShowLocationSuggestions(false);
  };

  const imagePreviews = React.useMemo(() => {
    if (!watchedImages) return [];
    try {
        if (watchedImages.length > 0) {
            return Array.from(watchedImages).map(file => URL.createObjectURL(file));
        }
    } catch(e) {}
    return [];
  }, [watchedImages]);

  // Calculate projected earnings
  const activeSlotsCount = generatedSlots.filter(s => s.isActive).length;
  const perSlotPrice = (Number(watchedPricePerHour) || 0) * (Number(watchedSlotDuration) / 60);
  const totalDailyEarnings = activeSlotsCount * perSlotPrice;

  // Load states on mount
  useEffect(() => {
    fetchStates().then(setStatesList);
  }, []);

  // Load cities when state changes
  useEffect(() => {
    if (selectedState) {
      fetchCities(selectedState).then(setCitiesList);
    } else {
      setCitiesList([]);
    }
  }, [selectedState]);

  // Build live map preview URL from coords or address
  const mapPreviewUrl = React.useMemo(() => {
    if (watchedLat && watchedLng && !isNaN(Number(watchedLat)) && !isNaN(Number(watchedLng))) {
      return `https://maps.google.com/maps?q=${watchedLat},${watchedLng}&t=&z=16&ie=UTF8&iwloc=&output=embed`;
    }
    const q = [watchedLocation, watchedCity, selectedState].filter(Boolean).join(", ");
    if (q.length > 3) {
      return `https://maps.google.com/maps?q=${encodeURIComponent(q)}&t=&z=15&ie=UTF8&iwloc=&output=embed`;
    }
    return null;
  }, [watchedLat, watchedLng, watchedLocation, watchedCity, selectedState]);

  const sportsOptions = ["Football", "Cricket", "Tennis", "Badminton", "Table Tennis", "Basketball", "Volleyball", "Hockey"];
  const groundTypeOptions = ["Natural Grass", "Artificial Turf", "Clay", "Hard Court", "Small Turf", "Indoor Court"];
  const facilitiesOptions = ["Parking", "Washroom", "Drinking Water", "Changing Room", "First Aid", "Locker Room", "Cafeteria", "WiFi", "Lighting", "Sitting Area"];

  return (
    <div className="h-full custom-scrollbar bg-[#000000] text-white" onClick={() => setShowLocationSuggestions(false)}>
      <div className="px-1 lg:px-3 lg:pt-2 lg:pb-3 space-y-8 animate-fade-in pt-0 pb-4 h-full relative">
        <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
          <div className="space-y-1">
            <div className="flex items-center gap-3">
              <h2 className="text-[20px] sm:text-[24px] lg:text-[32px] mt-2 sm:mt-0 font-black font-['Open_Sans'] tracking-tight text-white uppercase whitespace-nowrap">
                EDIT <span className="text-[#B3DC26]">{watchedFacilityCategory.toUpperCase()}</span>
              </h2>
            </div>
            <p className="text-white/70 font-inter text-[20px] mt-2 ml-4">
              Register a New Facility | Kridaz
            </p>
          </div>
        </header>

        {/* Step Indicators */}
        <div className="flex items-center justify-between relative z-10 mb-8">
          {[1, 2, 3].map((step) => (
            <div key={step} className={`flex-1 flex flex-col items-center gap-2 relative ${currentStep === step ? 'opacity-100' : 'opacity-50'}`}>
              <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm z-10 ${currentStep === step ? 'bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black shadow-[0_0_15px_rgba(204,255,0,0.5)]' : 'bg-[#121212]  -white/10 text-white'}`}>
                {step}
              </div>
              <span className="text-[10px] font-bold uppercase tracking-widest text-center">
                {step === 1 ? 'General Info' : step === 2 ? 'Legalities' : 'Slot Mgmt'}
              </span>
              {step < 3 && (
                <div className={`absolute top-5 left-[50%] w-full h-[2px] ${currentStep > step ? 'bg-[#B3DC26]' : 'bg-[#1B1B1B]'}`} />
              )}
            </div>
          ))}
        </div>

        <form
          onSubmit={handleSubmit(onSubmit, (errors) => {
            const firstErrorKey = Object.keys(errors)[0];
            if (firstErrorKey) {
              const errorMessage = errors[firstErrorKey]?.message || `Please check the ${firstErrorKey} field`;
              let stepError = 1;
              const step2Fields = ['saleDeed', 'electricityBill', 'gstRegistration', 'rentalAgreement', 'ownershipAgreement', 'policies'];
              const step3Fields = ['pricePerHour', 'openTime', 'closeTime', 'slotDuration'];
              if (step2Fields.includes(firstErrorKey)) stepError = 2;
              if (step3Fields.includes(firstErrorKey)) stepError = 3;
              
              toast.error(`Step ${stepError}: ${errorMessage}`);
            } else {
              toast.error("Please fill all required fields correctly.");
            }
          })}
          className="grid grid-cols-1 gap-6 md:gap-12 bg-[#000000] px-2 py-4 md:p-12 rounded-[16px] border-none md:border md:border-white/10 md:shadow-[var(--shadow-2)] relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 w-64 h-64 bg-[#B3DC26]/5 blur-[100px] pointer-events-none" />

          {/* Hidden fields for coords to still take GPS data */}
          <input type="hidden" {...register("latitude")} />
          <input type="hidden" {...register("longitude")} />
          <input type="hidden" {...register("state")} />
          <input type="hidden" {...register("city")} />

          {/* STEP 1: General Information */}
          {currentStep === 1 && (
            <div className="col-span-1 grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10 animate-fade-in">
              <div className="space-y-8">
                <FormField label={`${watchedFacilityCategory} Name`} name="name" type="text" register={register} error={errors.name} className="bg-[#121212] border-white/10 text-white focus:border-[#B3DC26]/60" />
                
                <div className="form-control">
                  <label className="label mb-2">
                    <span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Facility Images (Up to 10)</span>
                  </label>
                  <input type="file" multiple accept="image/*" className="w-full bg-[#121212] border border-white/10 text-white/70 file:bg-[#1B1B1B] file:text-white file:border-none file:px-6 file:h-12 file:mr-4 file:font-bold file:uppercase file:text-[10px] file:tracking-widest rounded-[16px] h-12 flex items-center focus:outline-none transition-all cursor-pointer" onChange={(e) => setValue("images", e.target.files)} />
                  {errors.images && <span className="text-[#B3DC26] text-[10px] font-bold uppercase mt-2 block ml-1">{errors.images.message}</span>}
                  
                  {/* Image Previews */}
                  {imagePreviews.length > 0 && (
                    <div className="flex gap-4 mt-4 overflow-x-auto pb-2 custom-scrollbar">
                        {imagePreviews.map((src, i) => (
                            <img key={i} src={src} alt={`preview ${i}`} className="w-20 h-20 object-cover rounded-[16px] border border-white/10" />
                        ))}
                    </div>
                  )}
                </div>

                <FormField label="YouTube Video URL" name="youtubeUrl" type="text" placeholder="https://www.youtube.com/watch?v=..." register={register} error={errors.youtubeUrl} className="bg-[#121212] border-white/10 text-white focus:border-[#B3DC26]/60" />

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Facility Category</span></label>
                  <select {...register("facilityCategory", { required: "Please select a category" })} className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none">
                    <option value="">Select Category</option>
                    <option value="Turf">Venue</option>
                    <option value="Ground">Ground</option>
                    <option value="Court">Court</option>
                    <option value="Stadium">Stadium</option>
                  </select>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Sport Arsenal</span></label>
                  <select className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none" onChange={(e) => addSportType(e.target.value)} value="">
                    <option value="" disabled>Select Sports</option>
                    {sportsOptions.map(o => <option key={o} value={o} disabled={sportTypes.includes(o)}>{o}</option>)}
                  </select>
                  <div className="mt-4 flex flex-wrap gap-2">
                    {sportTypes.map((type, index) => (
                      <span key={index} className="px-3 py-1.5 bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black font-bold rounded-[16px] text-[10px] flex items-center gap-2 uppercase tracking-widest">
                        {type} <button type="button" onClick={() => removeSportType(type)} className="hover:text-white transition-colors"><Plus size={12} className="rotate-45" /></button>
                      </span>
                    ))}
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Ground Composition</span></label>
                  <select className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none" onChange={(e) => addGroundType(e.target.value)} value="">
                    <option value="" disabled>Select Ground Types</option>
                    {groundTypeOptions.map(o => <option key={o} value={o} disabled={groundTypes.includes(o)}>{o}</option>)}
                  </select>
                  <div className="mt-4 flex flex-wrap gap-2">
                    {groundTypes.map((type, index) => (
                      <span key={index} className="px-3 py-1.5 bg-[#1B1B1B] border border-white/10 text-white font-bold rounded-[16px] text-[10px] flex items-center gap-2 uppercase tracking-widest">
                        {type} <button type="button" onClick={() => removeGroundType(type)} className="hover:text-[#B3DC26] transition-colors"><Plus size={12} className="rotate-45" /></button>
                      </span>
                    ))}
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Facilities</span></label>
                  <select className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none" onChange={(e) => addFacility(e.target.value)} value="">
                    <option value="" disabled>Select Facilities</option>
                    {facilitiesOptions.map(o => <option key={o} value={o} disabled={facilities.includes(o)}>{o}</option>)}
                  </select>
                  <div className="mt-4 flex flex-wrap gap-2">
                    {facilities.map((type, index) => (
                      <span key={index} className="px-3 py-1.5 bg-[#1B1B1B] border border-white/10 text-[#B3DC26] font-bold rounded-[16px] text-[10px] flex items-center gap-2 uppercase tracking-widest">
                        {type} <button type="button" onClick={() => removeFacility(type)} className="hover:text-white transition-colors"><Plus size={12} className="rotate-45" /></button>
                      </span>
                    ))}
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Facility Description</span></label>
                  <textarea {...register("description")} className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-32 rounded-[16px] p-4 transition-all"></textarea>
                </div>
              </div>

              <div className="space-y-8">
                {/* Searchable Location Input */}
                <div className="form-control relative">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Search Location</span></label>
                  <div className="relative" onClick={(e) => e.stopPropagation()}>
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/70" size={16} />
                    <input 
                      type="text" 
                      placeholder="Type to search location..." 
                      className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] pl-12 pr-4 transition-all"
                      value={locationSearchQuery}
                      onChange={(e) => {
                        const val = e.target.value;
                        setLocationSearchQuery(val);
                        setShowLocationSuggestions(true);
                        setValue("location", val, { shouldValidate: true, shouldDirty: true });
                        setValue("city", val, { shouldValidate: true, shouldDirty: true });
                        setValue("state", val, { shouldValidate: true, shouldDirty: true });
                      }}
                      onFocus={() => setShowLocationSuggestions(true)}
                    />
                    
                    {/* Autocomplete dropdown */}
                    {showLocationSuggestions && locationSuggestions.length > 0 && (
                      <div className="absolute z-50 top-[52px] left-0 right-0 bg-[#121212] border border-white/10 rounded-[16px] shadow-2xl overflow-hidden max-h-[300px] overflow-y-auto custom-scrollbar">
                        {locationSuggestions.map((loc, i) => (
                          <div 
                            key={i} 
                            className="p-4 border-b border-white/10 last:border-b-0 hover:bg-[#1B1B1B] cursor-pointer transition-colors"
                            onClick={() => handleLocationSelect(loc)}
                          >
                            <p className="text-sm text-white font-medium truncate">{loc.display_name}</p>
                            {(loc.city || loc.state) && (
                              <p className="text-[10px] text-white/70 mt-1 uppercase tracking-wider">{[loc.city, loc.state].filter(Boolean).join(", ")}</p>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                  {errors.location && <span className="text-[#B3DC26] text-[10px] font-bold uppercase mt-2 block ml-1">{errors.location.message}</span>}
                </div>

                <FormField label="Direct Google Maps URL" name="mapUrl" type="text" placeholder="https://maps.app.goo.gl/..." register={register} error={errors.mapUrl} className="bg-[#121212] border-white/10 text-white focus:border-[#B3DC26]/60" />

                {mapPreviewUrl && (
                  <div className="form-control">
                    <label className="label mb-4"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1 flex items-center gap-2">📍 Map Preview</span></label>
                    <div className="relative w-full rounded-[16px] overflow-hidden border border-white/10 shadow-[var(--shadow-1)]" style={{ height: 220 }}>
                      <iframe title="Location Preview" src={mapPreviewUrl} width="100%" height="100%" style={{ border: 0, filter: "invert(90%) hue-rotate(180deg) saturate(0.7) brightness(0.9)" }} loading="lazy" />
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* STEP 2: Legalities & Management */}
          {currentStep === 2 && (
            <div className="col-span-1 grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10 animate-fade-in">
              <div className="space-y-8">
                <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-8 uppercase tracking-[3px]">Legal Documents</h3>
                
                {[
                  { name: "gstRegistration", label: "GST Registration" },
                  { name: "saleDeed", label: "Sale Deed (Mandatory)*" },
                  { name: "electricityBill", label: "Electricity Bill (Mandatory)*" },
                  { name: "rentalAgreement", label: "Rental Agreement" },
                  { name: "ownershipAgreement", label: "Ownership Agreement" },
                  { name: "googleProfileScreenshot", label: "Google Profile Screenshot" }
                ].map(doc => {
                  const selectedFiles = watch(doc.name);
                  const hasFile = selectedFiles && selectedFiles.length > 0;
                  return (
                    <div className="form-control" key={doc.name}>
                      <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">{doc.label}</span></label>
                      <input type="file" accept=".pdf,image/*" className="w-full bg-[#121212] border border-white/10 text-white/70 file:bg-[#1B1B1B] file:text-white file:border-none file:px-6 file:h-12 file:mr-4 file:font-bold file:uppercase file:text-[10px] file:tracking-widest rounded-[16px] h-12 flex items-center focus:outline-none transition-all cursor-pointer" onChange={(e) => setValue(doc.name, e.target.files, { shouldValidate: true })} />
                      {hasFile && (
                        <span className="text-[#B3DC26] text-[10px] font-bold mt-2 block ml-1 truncate">
                          ✅ Selected: {selectedFiles[0].name}
                        </span>
                      )}
                      {errors[doc.name] && <span className="text-red-500 text-[10px] font-bold uppercase mt-2 block ml-1">{errors[doc.name].message}</span>}
                    </div>
                  );
                })}
              </div>
              <div className="space-y-8">
                <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-8 uppercase tracking-[3px]">Management & Policies</h3>

                <div className="form-control space-y-4">
                  <label className="label"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Venue Managers (Contacts)</span></label>
                  <div className="flex flex-col md:flex-row gap-4">
                    <input type="text" placeholder="Manager Name" value={newManagerName} onChange={(e) => setNewManagerName(e.target.value)} className="w-full bg-[#121212] border border-white/10 text-white text-sm h-12 rounded-[16px] px-4 focus:outline-none focus:border-[#B3DC26]/60" />
                    <input type="text" placeholder="Phone" value={newManagerPhone} onChange={(e) => setNewManagerPhone(e.target.value)} className="w-full bg-[#121212] border border-white/10 text-white text-sm h-12 rounded-[16px] px-4 focus:outline-none focus:border-[#B3DC26]/60" />
                    <button type="button" onClick={addManagerContact} className="shrink-0 px-8 rounded-[16px] bg-white text-black hover:bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none transition-all text-[11px] font-bold uppercase tracking-widest">Add</button>
                  </div>
                  <div className="space-y-3 max-h-[150px] overflow-y-auto custom-scrollbar pr-2">
                    {managerContacts.map((manager, index) => (
                      <div key={index} className="flex items-center justify-between bg-[#121212] p-4 rounded-[16px] border border-white/10">
                        <div className="flex flex-col">
                          <span className="text-white text-[13px] font-bold uppercase tracking-tight">{manager.name}</span>
                          <span className="text-white/70 text-[11px] font-mono mt-0.5">{manager.phone}</span>
                        </div>
                        <button type="button" onClick={() => removeManagerContact(index)} className="text-[#444] hover:text-[#B3DC26] transition-colors uppercase text-[10px] font-bold tracking-widest">Remove</button>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="form-control">
                  <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Venue Policies and Rules</span></label>
                  <textarea {...register("policies")} maxLength={1000} className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-48 rounded-[16px] p-4 transition-all"></textarea>
                </div>
              </div>
            </div>
          )}

          {/* STEP 3: Slot Management */}
          {currentStep === 3 && (
            <div className="col-span-1 grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10 animate-fade-in">
              <div className="space-y-8">
                <div className="grid grid-cols-2 gap-6">
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Slot Duration</span></label>
                    <select {...register("slotDuration")} className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none">
                      <option value={30}>30 Minutes</option>
                      <option value={60}>60 Minutes</option>
                      <option value={90}>90 Minutes</option>
                      <option value={120}>120 Minutes</option>
                    </select>
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Break Time</span></label>
                    <select {...register("breakTime")} className="w-full bg-[#121212] border border-white/10 text-white focus:border-[#B3DC26]/60 focus:outline-none text-sm h-12 rounded-[16px] px-4 transition-all appearance-none">
                      <option value={0}>No Break</option>
                      <option value={10}>10 Minutes</option>
                      <option value={15}>15 Minutes</option>
                      <option value={30}>30 Minutes</option>
                    </select>
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Opening Time</span></label>
                    <input type="time" {...register("openTime")} className={`w-full bg-[#121212] border ${errors.openTime ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all [color-scheme:dark]`} />
                  </div>
                  <div className="form-control">
                    <label className="label mb-2"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Closing Time</span></label>
                    <input type="time" {...register("closeTime")} disabled={!openTime} className={`w-full bg-[#121212] border ${errors.closeTime ? 'border-red-500' : 'border-white/10'} text-white focus:border-[#B3DC26]/60 focus:outline-none text-[10px] md:text-sm h-9 md:h-12 rounded-[16px] md:rounded-[16px] px-3 md:px-4 transition-all disabled:opacity-50 [color-scheme:dark]`} />
                  </div>
                </div>

                <FormField label="Hourly Rate (INR)" name="pricePerHour" type="number" register={register} error={errors.pricePerHour} className="bg-[#121212] border-white/10 text-white focus:border-[#B3DC26]/60" />

                <div className="space-y-6">
                  <label className="label"><span className="text-[11px] font-bold text-white/70 uppercase tracking-widest ml-1">Weekly Operational Sequence</span></label>
                  <div className="flex flex-wrap gap-3">
                    {["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"].map(day => {
                      const isActive = availableDays.includes(day);
                      return (
                        <button key={day} type="button" onClick={() => toggleDay(day)} className={`px-5 py-3 rounded-[16px] text-[11px] font-black uppercase tracking-widest transition-all  ${ isActive ? "bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black -[#B3DC26] shadow-[0_5px_15px_rgba(204,255,0,0.2)]" : "bg-[#121212] text-[#444] -white/10 hover:-[#B3DC26]/40" }`}>
                          {day.substring(0, 3)}
                        </button>
                      );
                    })}
                  </div>
                </div>
              </div>

              <div className="space-y-8">
                  <h3 className="text-[14px] font-bold text-[#B3DC26] border-b border-white/10 pb-3 mb-6 uppercase tracking-[3px]">Slot Review</h3>
                  {generatedSlots.length > 0 ? (
                      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                        {generatedSlots.map((slot, index) => (
                          <div key={index} className={`p-4 rounded-[16px] border transition-all ${ slot.isActive ? "bg-[#1B1B1B] border-[#B3DC26]/30" : "bg-[#121212] border-white/10 opacity-50" }`}>
                            <div className="flex justify-between items-center mb-3">
                              <span className={`text-[12px] font-bold font-mono tracking-tight ${slot.isActive ? 'text-white' : 'text-white/70'}`}>
                                {slot.startTime} - {slot.endTime}
                              </span>
                              <input type="checkbox" className="toggle toggle-sm bg-[#1B1B1B] border-none checked:bg-[#B3DC26]" checked={slot.isActive} onChange={() => toggleSlotActive(index)} />
                            </div>
                            <div className="flex items-center gap-2">
                              <span className="text-[11px] font-bold text-white/70">₹</span>
                              <input type="number" value={slot.price} onChange={(e) => updateSlotPrice(index, Number(e.target.value))} disabled={!slot.isActive} className={`w-full bg-transparent text-[14px] font-bold focus:outline-none font-mono ${slot.isActive ? 'text-[#B3DC26]' : 'text-[#444]'}`} />
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-12 border border-dashed border-white/10 rounded-[16px] bg-[#121212]">
                        <span className="text-[#444] text-[11px] font-bold uppercase tracking-[4px]">Set times to generate slots</span>
                      </div>
                    )}
              </div>
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="col-span-1 flex justify-between mt-12 pt-8 border-t border-white/10 relative z-10">
            <button
              type="button"
              onClick={(e) => { e.preventDefault(); setCurrentStep(prev => Math.max(1, prev - 1)); }}
              className={`px-8 py-3 rounded-[16px] font-bold text-sm uppercase tracking-wider transition-all duration-300 ${ currentStep === 1 ? "opacity-0 pointer-events-none" : "bg-[#1B1B1B] text-white hover:bg-[#2A2A2A]" }`}
            >
              Back
            </button>
            
            {currentStep < 3 ? (
              <button
                type="button"
                onClick={(e) => { e.preventDefault(); setCurrentStep(prev => Math.min(3, prev + 1)); }}
                className="px-10 py-3 rounded-[16px] bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black font-bold text-sm uppercase tracking-wider hover:opacity-90 transition-all duration-300"
              >
                Next Step
              </button>
            ) : (
              <button
                type="submit"
                disabled={loading}
                className={`px-12 py-3 rounded-[16px] bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none text-black font-bold text-sm uppercase tracking-wider transition-all duration-300 flex items-center gap-2 ${ loading ? "opacity-70 cursor-not-allowed" : "hover:opacity-90" }`}
              >
                {loading ? "Submitting..." : "Submit Venue"}
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditTurf;

import React, { useState } from "react";
import { format } from "date-fns";
import { useParams, useNavigate } from "react-router-dom";
import { 
  ArrowLeft, Calendar, Clock, MapPin, Users, Mail, Phone, 
  CheckCircle2, AlertCircle, Trash2, Edit2, Star, Zap, X, Activity,
  ChevronLeft, ChevronRight, FileText, Navigation, User
} from "lucide-react";
import useTurfDetails from "@hooks/venue-owner/useTurfDetails";
import DashboardSkeleton from "../Dashboard/DashboardSkeleton";
import toast from "react-hot-toast";
import GlobalBackButton from '@/shared/components/GlobalBackButton';

// Booking Information Popup
const BookingModal = ({ slot, onClose }) => {
  if (!slot) return null;
  const { bookingDetails, startTime, endTime, isBooked } = slot;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={onClose} />
      <div className="relative bg-[#000000] border border-white/10 rounded-[16px] w-full max-w-md overflow-hidden shadow-2xl animate-in zoom-in-95 duration-300">
        {/* Header */}
        <div className="p-8 pb-4 flex justify-between items-start">
          <div>
            <p className="text-[10px] font-bold text-white/70 uppercase tracking-[3px] mb-2">Slot Telemetry</p>
            <h3 className="text-2xl font-bold text-white uppercase tracking-tight font-['Open_Sans']">
              {startTime} - {endTime}
            </h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-[#111] rounded-[16px] transition-colors border border-transparent hover:border-white/10">
            <X size={18} className="text-white/70" />
          </button>
        </div>

        <div className="p-8 pt-0 space-y-8">
          {isBooked ? (
            <>
              <div className="flex items-center gap-4 p-6 bg-[#121212] border border-white/10 rounded-[16px]">
                <div className="w-14 h-14 rounded-[16px] bg-[#1B1B1B] border border-[#404040] flex items-center justify-center overflow-hidden shrink-0">
                  {bookingDetails.user?.profileImage ? (
                    <img src={bookingDetails.user.profileImage} className="w-full h-full object-cover" />
                  ) : (
                    <Users size={24} className="text-[#B3DC26]" />
                  )}
                </div>
                <div className="min-w-0">
                  <h4 className="text-lg font-bold text-white uppercase tracking-tight truncate font-['Open_Sans']">
                    {bookingDetails.user?.name || bookingDetails.guestDetails?.name || "Guest Player"}
                  </h4>
                  <div className="flex items-center gap-2 mt-1">
                    <div className={`px-2 py-0.5 text-black text-[8px] font-bold uppercase rounded-[16px] ${(bookingDetails.user?.isGuest || bookingDetails.guestDetails) ? 'bg-[#878C9F]' : 'bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none'}`}>
                      {(bookingDetails.user?.isGuest || bookingDetails.guestDetails) ? 'Manual' : 'Verified'}
                    </div>
                    <span className="text-[10px] text-white/70 font-bold uppercase tracking-widest">
                      {(bookingDetails.user?.isGuest || bookingDetails.guestDetails) ? 'Offline Record' : 'Athlete Profile'}
                    </span>
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                <p className="text-[10px] font-bold text-white/70 uppercase tracking-[2px] px-1">Contact Intelligence</p>
                <div className="grid grid-cols-1 gap-2">
                  <a href={(bookingDetails.user?.email || bookingDetails.guestDetails?.email) ? `mailto:${bookingDetails.user?.email || bookingDetails.guestDetails?.email}` : "#"} className="flex items-center justify-between p-4 bg-[#121212] hover:bg-[#1B1B1B] rounded-[16px] border border-white/10 transition-all group">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-[#1B1B1B] rounded-[16px] flex items-center justify-center text-white/70 group-hover:text-[#B3DC26]">
                        <Mail size={12} />
                      </div>
                      <span className="text-xs text-white/70 font-medium">{bookingDetails.user?.email || bookingDetails.guestDetails?.email || "No Email Provided"}</span>
                    </div>
                    <ChevronRight size={14} className="text-[#2D2D2D]" />
                  </a>
                  <a href={(bookingDetails.user?.phoneNumber || bookingDetails.guestDetails?.phone) ? `tel:${bookingDetails.user?.phoneNumber || bookingDetails.guestDetails?.phone}` : "#"} className="flex items-center justify-between p-4 bg-[#121212] hover:bg-[#1B1B1B] rounded-[16px] border border-white/10 transition-all group">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-[#1B1B1B] rounded-[16px] flex items-center justify-center text-white/70 group-hover:text-[#B3DC26]">
                        <Phone size={12} />
                      </div>
                      <span className="text-xs text-white/70 font-medium">{bookingDetails.user?.phoneNumber || bookingDetails.guestDetails?.phone || "No Phone Provided"}</span>
                    </div>
                    <ChevronRight size={14} className="text-[#2D2D2D]" />
                  </a>
                </div>
              </div>

              <div className="flex justify-between items-center p-6 bg-[#121212] rounded-[16px] border border-white/10">
                <div className="flex flex-col">
                  <span className="text-[10px] font-bold text-white/70 uppercase tracking-widest">Revenue Impact</span>
                  <span className="text-[8px] text-[#444] font-bold uppercase">Settled via Platform</span>
                </div>
                <span className="text-3xl font-bold text-[#B3DC26] font-['Open_Sans'] tracking-tighter">Rs {bookingDetails.totalPrice}</span>
              </div>
            </>
          ) : (
            <div className="py-12 text-center space-y-4 bg-[#111] rounded-[16px] border border-dashed border-white/10">
              <div className="w-16 h-16 bg-[#1B1B1B] rounded-full flex items-center justify-center mx-auto">
                <Zap size={24} className="#2D2D2D" />
              </div>
              <div>
                <h4 className="text-base font-bold text-white uppercase tracking-tight">Available Unit</h4>
                <p className="text-white/70 text-xs max-w-[200px] mx-auto mt-2 opacity-60">No bookings detected for this sequence. Slot is open for athlete deployment.</p>
              </div>
            </div>
          )}
        </div>

        <div className="p-8 pt-0">
          <button 
            onClick={onClose}
            className="w-full py-4 bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none hover:opacity-90 rounded-[16px] text-[11px] font-bold text-black uppercase tracking-[2px] transition-all"
          >
            Acknowledge & Close
          </button>
        </div>
      </div>
    </div>
  );
};

export default function TurfDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { turfData, isLoading, error, toggleVisibility, deleteArena } = useTurfDetails(id);
  // Use local date string (YYYY-MM-DD) so it matches date-fns format() which also uses local timezone
  const toLocalDateString = (d) => format(d, 'yyyy-MM-dd');
  const [selectedDate, setSelectedDate] = useState(toLocalDateString(new Date()));
  const [selectedSlot, setSelectedSlot] = useState(null);
  const [isDescExpanded, setIsDescExpanded] = useState(false);
  const [isPolicyExpanded, setIsPolicyExpanded] = useState(false);

  const handleToggleVisibility = async () => {
    const success = await toggleVisibility();
    if (success) toast.success("Visibility updated");
    else toast.error("Failed to update visibility");
  };

  const handleDelete = async () => {
    if (window.confirm("Are you sure you want to decommission this arena? This will permanently delete all associated data.")) {
      const success = await deleteArena();
      if (success) {
        toast.success("Arena decommissioned");
        navigate("/venue-owner/turfs");
      } else {
        toast.error("Failed to decommission arena");
      }
    }
  };

  React.useEffect(() => {
    setSelectedDate(toLocalDateString(new Date()));
  }, []);

  if (isLoading) return <DashboardSkeleton />;
  if (error) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8 bg-[#000000]">
      <AlertCircle className="text-red-500 mb-6" size={48} />
      <h2 className="text-2xl font-bold text-white mb-2 uppercase tracking-tight font-['Open_Sans']">Error Synchronizing Data</h2>
      <p className="text-white/70 mb-8 max-w-md">{error || "Connection failure to server intelligence roster."}</p>
      <GlobalBackButton />
    </div>
  );

  if (!turfData || !turfData.turf) return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8 bg-[#000000]">
      <Zap size={48} className="text-[#2D2D2D] mb-6" />
      <h2 className="text-2xl font-bold text-white mb-2 uppercase tracking-tight font-['Open_Sans']">Arena Missing</h2>
      <p className="text-white/70 mb-8">We couldn't retrieve the operational metrics for this facility.</p>
      <GlobalBackButton />
    </div>
  );

  const { turf, slots = [] } = turfData;
  const pending = turf.pendingUpdates || {};

  const PendingBadge = ({ label = "Pending Update" }) => (
    <span className="ml-2 px-2 py-0.5 bg-amber-500/10 border border-amber-500/20 text-amber-500 text-[8px] font-bold uppercase tracking-widest rounded-[16px] animate-pulse">
      {label}
    </span>
  );

  const filteredBookings = slots.filter(slot => {
    try {
      const slotDate = format(new Date(slot.startTime), "yyyy-MM-dd");
      return slotDate === selectedDate;
    } catch (e) {
      return false;
    }
  });

  const displaySlots = slots
    .filter(slot => {
      try {
        return format(new Date(slot.startTime), "yyyy-MM-dd") === selectedDate;
      } catch (e) {
        return false;
      }
    })
    .sort((a, b) => new Date(a.startTime) - new Date(b.startTime))
    .map(slot => ({
      ...slot,
      // Map startTime/endTime to human readable format for UI
      startTime: format(new Date(slot.startTime), "hh:mm a"),
      endTime: format(new Date(slot.endTime), "hh:mm a"),
      isActive: slot.isActive !== false // Default to true if not specified
    }));

  const uniqueDates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() + i);
    return format(d, "yyyy-MM-dd");
  });

  return (
    <div className="space-y-8 animate-fade-in pb-20 bg-[#000000] min-h-screen">
      {selectedSlot && (
        <BookingModal 
          slot={selectedSlot} 
          onClose={() => setSelectedSlot(null)} 
        />
      )}

      {/* Navigation & Header */}
      <div className="flex flex-col gap-8">
        <div className="flex items-center gap-4">
          <GlobalBackButton />
          <div className="h-px flex-1 bg-[#1B1B1B]/50" />
        </div>

        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-8 pb-8 border-b border-white/10">
          <div className="flex flex-col md:flex-row gap-8 items-start">
             <div className="w-32 h-32 rounded-[16px] overflow-hidden border border-white/10 shrink-0 shadow-2xl relative">
                <img src={pending.image || turf.image} alt={turf.name} className="w-full h-full object-cover opacity-80" />
                {pending.image && <div className="absolute top-2 right-2 p-1 bg-amber-500 rounded-full animate-pulse" title="New Image Pending" />}
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
             </div>
             <div className="space-y-3">
                <div className="flex flex-wrap items-center gap-4">
                   <div className="space-y-1">
                      <h1 className={`text-4xl font-bold uppercase tracking-tight font-['Open_Sans'] ${ turf.status === 'pending' ? 'text-amber-500' : turf.status === 'rejected' ? 'text-red-500' : 'text-white' }`}>
                         {turf.name}
                      </h1>
                      {pending.name && (
                         <p className="text-amber-500 text-[10px] font-bold uppercase tracking-widest flex items-center gap-2">
                            <span className="opacity-40">Update to:</span> {pending.name} <PendingBadge />
                         </p>
                      )}
                   </div>
                    <div className={`px-3 py-1 border rounded-[16px] flex items-center gap-1 ${ turf.status === 'approved' ? 'bg-[#B3DC26]/10 border-[#B3DC26]/20 text-[#B3DC26]' : turf.status === 'rejected' ? 'bg-red-500/10 border-red-500/20 text-red-500' : 'bg-amber-500/10 border-amber-500/20 text-amber-500' }`}>
                       <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${ turf.status === 'approved' ? 'bg-[#B3DC26]' : turf.status === 'rejected' ? 'bg-red-500' : 'bg-amber-500' }`} />
                       <span className="text-[9px] font-bold uppercase tracking-widest">{turf.status}</span>
                    </div>
                   <div className="px-3 py-1 bg-[#111] border border-white/10 rounded-[16px] flex items-center gap-2">
                      <Star size={12} className="text-[#B3DC26] fill-[#BFF367]" />
                      <span className="text-[10px] font-bold text-white font-['Open_Sans']">{turf.avgRating?.toFixed(1) || "NEW"}</span>
                   </div>
                </div>
                <div className="flex flex-wrap gap-6 text-white/70 text-[10px] font-bold uppercase tracking-[2px]">
                   <div className="space-y-1">
                      <div className="flex items-center gap-2">
                         <MapPin size={14} className={turf.status === 'rejected' ? 'text-red-500/60' : 'text-[#B3DC26]/60'} />
                         {turf.location}{turf.city ? `, ${turf.city}` : ""}{turf.state ? `, ${turf.state}` : ""}
                      </div>
                      {pending.location && (
                         <p className="text-amber-500/80 text-[8px] font-bold lowercase tracking-widest flex items-center gap-2 pl-5">
                            G�� {pending.location} <PendingBadge label="Loc" />
                         </p>
                      )}
                   </div>
                   <div className="space-y-1">
                      <div className="flex items-center gap-2">
                         <Clock size={14} className={turf.status === 'rejected' ? 'text-red-500/60' : 'text-[#B3DC26]/60'} />
                         {turf.openTime} - {turf.closeTime}
                      </div>
                      {(pending.openTime || pending.closeTime) && (
                         <p className="text-amber-500/80 text-[8px] font-bold lowercase tracking-widest flex items-center gap-2 pl-5">
                            G�� {pending.openTime || turf.openTime} - {pending.closeTime || turf.closeTime} <PendingBadge label="Time" />
                         </p>
                      )}
                   </div>
                   <div className="space-y-1">
                      <div className="flex items-center gap-2">
                         <span className={`font-bold ${turf.status === 'rejected' ? 'text-red-500/60' : 'text-[#B3DC26]/60'}`}>Rs</span>
                         {turf.pricePerHour}/hr base
                      </div>
                      {pending.pricePerHour && (
                         <p className="text-amber-500/80 text-[8px] font-bold lowercase tracking-widest flex items-center gap-2 pl-5">
                            G�� Rs {pending.pricePerHour}/hr <PendingBadge label="Price" />
                         </p>
                      )}
                   </div>
                </div>
                {turf.status !== 'approved' && (
                   <div className={`flex items-center gap-2 p-2 px-3 rounded-[16px] border w-fit mt-2 ${ turf.status === 'rejected' ? 'bg-red-500/5 border-red-500/10 text-red-500/80' : 'bg-amber-500/5 border-amber-500/10 text-amber-500/80' }`}>
                      <AlertCircle size={12} />
                      <span className="text-[9px] font-bold uppercase tracking-widest">
                         {turf.status === 'rejected' ? 'Critical: Corrections Required for Deployment' : 'Intelligence Audit: Verification in Progress'}
                      </span>
                   </div>
                )}
             </div>
          </div>
          <div className="flex flex-wrap gap-3">
             <button 
                onClick={handleToggleVisibility}
                className={`px-6 py-2.5 border rounded-[16px] font-bold uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${ turf.isActive ? "bg-[#B3DC26]/5 border-[#B3DC26]/20 text-[#B3DC26] hover:bg-[#B3DC26]/10" : "bg-black border-white/10 text-[#444] hover:text-white" }`}
             >
                <Zap size={14} className={turf.isActive ? "fill-[#BFF367]" : ""} />
                {turf.isActive ? "Visible" : "Hidden"}
             </button>
             <button 
                onClick={() => navigate(`/venue-owner/edit-turf/${id}`)}
                className={`px-6 py-2.5 border rounded-[16px] font-bold uppercase text-[10px] tracking-widest transition-all flex items-center gap-2 ${ turf.status === 'rejected' ? "bg-red-500 text-white border-red-500 hover:bg-red-600 shadow-[0_5px_15px_rgba(239,68,68,0.2)]" : "bg-[#121212] border-white/10 text-white/70 hover:text-white" }`}
             >
                <Edit2 size={14} />
                {turf.status === 'rejected' ? "Review & Re-apply" : "Edit Arena"}
             </button>
             <button 
                onClick={handleDelete}
                className="px-6 py-2.5 bg-red-500/10 border border-red-500/20 rounded-[16px] text-red-500 font-bold uppercase text-[10px] tracking-widest hover:bg-red-500/20 transition-all flex items-center gap-2"
             >
                <Trash2 size={14} />
                Decommission
             </button>
          </div>
        </div>
      </div>

      {/* Media Intelligence & Operational Footage */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
         {/* Gallery Scroller */}
         <div className="lg:col-span-7 bg-[#121212] border border-white/10 rounded-[16px] p-6 space-y-6 overflow-hidden">
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-2">
                  <div className="w-1 h-3 bg-[#B3DC26] rounded-full" />
                  <p className="text-[10px] font-bold text-white/70 uppercase tracking-[2px]">Arena Visual Assets</p>
               </div>
               <div className="flex gap-2">
                  <button 
                    onClick={() => {
                      const el = document.getElementById('gallery-scroll');
                      el.scrollBy({ left: -300, behavior: 'smooth' });
                    }}
                    className="w-8 h-8 flex items-center justify-center bg-[#111] border border-white/10 rounded-full text-white/70 hover:text-[#B3DC26] hover:border-[#B3DC26]/40 transition-all"
                  >
                    <ChevronLeft size={16} />
                  </button>
                  <button 
                    onClick={() => {
                      const el = document.getElementById('gallery-scroll');
                      el.scrollBy({ left: 300, behavior: 'smooth' });
                    }}
                    className="w-8 h-8 flex items-center justify-center bg-[#111] border border-white/10 rounded-full text-white/70 hover:text-[#B3DC26] hover:border-[#B3DC26]/40 transition-all"
                  >
                    <ChevronRight size={16} />
                  </button>
               </div>
            </div>
            
            <div 
              id="gallery-scroll"
              className="flex gap-4 overflow-x-auto custom-scrollbar pb-4 snap-x"
            >
               {(turf.images || [turf.image]).map((img, i) => (
                  <div key={i} className="min-w-[280px] h-[180px] rounded-[16px] border border-white/10 overflow-hidden relative group/img snap-start">
                     <img src={img} className="w-full h-full object-cover opacity-80 group-hover/img:opacity-100 transition-opacity" />
                     <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                  </div>
               ))}
               {pending.images && Array.from(pending.images).map((img, i) => (
                  <div key={`p-${i}`} className="min-w-[280px] h-[180px] rounded-[16px] border-2 border-amber-500/40 overflow-hidden relative group/img snap-start">
                     <div className="absolute top-3 left-3 z-10">
                        <PendingBadge label="New Upload" />
                     </div>
                     <img src={typeof img === 'string' ? img : URL.createObjectURL(img)} className="w-full h-full object-cover opacity-90" />
                     <div className="absolute inset-0 bg-gradient-to-t from-amber-900/20 to-transparent" />
                  </div>
               ))}
            </div>
         </div>

         {/* Video Intelligence */}
         <div className="lg:col-span-5 bg-[#121212] border border-white/10 rounded-[16px] p-6 space-y-6">
            <div className="flex items-center gap-2">
               <div className="w-1 h-3 bg-red-600 rounded-full animate-pulse" />
               <p className="text-[10px] font-bold text-white/70 uppercase tracking-[2px]">Operational Footage (YouTube)</p>
            </div>
            
            {(pending.youtubeUrl || turf.youtubeUrl) ? (
               <div className={`relative aspect-video rounded-[16px] overflow-hidden border ${pending.youtubeUrl ? 'border-amber-500/40' : 'border-white/10'}`}>
                  {pending.youtubeUrl && (
                     <div className="absolute top-3 right-3 z-10">
                        <PendingBadge label="Stream Update" />
                     </div>
                  )}
                  <iframe
                    width="100%"
                    height="100%"
                    src={(pending.youtubeUrl || turf.youtubeUrl).replace("watch?v=", "embed/")}
                    title="YouTube video player"
                    frameBorder="0"
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                    allowFullScreen
                    className="opacity-90"
                  ></iframe>
               </div>
            ) : (
               <div className="aspect-video bg-[#050505] rounded-[16px] border border-dashed border-white/10 flex flex-col items-center justify-center text-center p-8">
                  <Activity size={32} className="text-[#2D2D2D] mb-4" />
                  <p className="text-[10px] font-bold text-[#444] uppercase tracking-widest leading-relaxed">No telemetry broadcast configured for this facility.</p>
               </div>
            )}
         </div>
      </div>

      {/* Operational Pulse & Intelligence */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
         {/* Live Stats */}
         <div className="xl:col-span-4 grid grid-cols-2 gap-4">
            <div className="p-6 bg-[#121212] border border-white/10 rounded-[16px] flex flex-col justify-between min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 opacity-10 text-[#B3DC26] group-hover:opacity-20 transition-opacity">
                  <Activity size={40} />
               </div>
               <p className="text-[10px] font-bold text-white/70 uppercase tracking-[3px]">Today's Load</p>
               <div>
                  <h4 className="text-3xl font-bold text-white font-['Open_Sans'] uppercase">
                    {Math.round((filteredBookings.filter(s => s.isBooked).length / (filteredBookings.length || 1)) * 100)}%
                  </h4>
                  <p className="text-[9px] text-[#B3DC26] font-bold uppercase tracking-widest mt-1">Live Occupancy</p>
               </div>
            </div>
            <div className="p-6 bg-[#121212] border border-white/10 rounded-[16px] flex flex-col justify-between min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 opacity-10 text-[#B3DC26] group-hover:opacity-20 transition-opacity">
                  <Zap size={40} />
               </div>
               <p className="text-[10px] font-bold text-white/70 uppercase tracking-[3px]">Revenue</p>
               <div className="space-y-1">
                  <h4 className="text-3xl font-bold text-white font-['Open_Sans'] uppercase flex items-baseline gap-2">
                    Rs {filteredBookings.filter(s => s.isBooked).reduce((acc, b) => acc + (b.bookingDetails?.totalPrice || 0), 0)}
                    {pending.pricePerHour && (
                       <span className="text-amber-500 text-sm font-bold opacity-80">G�� Rs {pending.pricePerHour}/hr <PendingBadge label="Rate" /></span>
                    )}
                  </h4>
                  <p className="text-[9px] text-[#B3DC26] font-bold uppercase tracking-widest mt-1">Daily Yield</p>
               </div>
            </div>
         </div>

         {/* Consolidated Intelligence */}
         <div className="xl:col-span-8 space-y-8">
            <div className="p-6 bg-[#121212] border border-white/10 rounded-[16px] flex flex-col md:flex-row gap-8">
              <div className="flex-1 space-y-4">
                 <div className="flex items-center gap-2">
                    <div className="w-1 h-3 bg-[#B3DC26] rounded-full" />
                    <p className="text-[10px] font-bold text-white/70 uppercase tracking-[2px]">Facility DNA</p>
                 </div>
                 <div className="space-y-4">
                    <div>
                       <p className="text-[9px] text-[#444] font-bold uppercase tracking-widest mb-2 flex items-center gap-2">
                          Ground Composition
                          {pending.groundTypes && <PendingBadge />}
                       </p>
                       <div className="flex flex-wrap gap-2">
                          {(pending.groundTypes || turf.groundTypes || []).map((ground, i) => (
                             <span key={i} className={`px-2 py-1 border rounded-[16px] text-[9px] font-bold uppercase tracking-wider snap-start ${ pending.groundTypes ? 'bg-amber-500/5 border-amber-500/20 text-amber-500' : 'bg-[#111] border-white/10 text-white' }`}>
                                {ground}
                             </span>
                          ))}
                       </div>
                    </div>
                    <div>
                       <p className="text-[9px] text-[#444] font-bold uppercase tracking-widest mb-2 flex items-center gap-2">
                          Capabilities
                          {pending.facilities && <PendingBadge />}
                       </p>
                       <div className="flex flex-wrap gap-2">
                          {(pending.facilities || turf.facilities || []).map((facility, i) => (
                             <span key={i} className={`px-2 py-1  rounded-[16px] text-[9px] font-bold uppercase tracking-wider snap-start ${ pending.facilities ? 'bg-amber-500/10 -amber-500/20 text-amber-500' : 'bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none -[#B3DC26] text-black' }`}>
                                {facility}
                             </span>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>

              <div className="w-px bg-[#1B1B1B] hidden md:block" />

              <div className="flex-1 space-y-4">
                 <div className="flex items-center gap-2">
                    <div className="w-1 h-3 bg-[#B3DC26] rounded-full" />
                    <p className="text-[10px] font-bold text-white/70 uppercase tracking-[2px]">Sport Arsenal</p>
                 </div>
                 <div className="flex flex-wrap gap-2">
                    {(pending.sportTypes || turf.sportTypes || []).map((sport, i) => (
                       <div key={i} className={`flex items-center gap-3 border p-3 rounded-[16px] w-full group/sport transition-colors ${ pending.sportTypes ? 'bg-amber-500/5 border-amber-500/20' : 'bg-[#111] border-white/10 hover:border-[#B3DC26]/40' }`}>
