                  >
                    <div className="flex justify-between items-start">
                       <div className="space-y-1">
                          <p className={`text-[9px] font-bold uppercase tracking-widest ${slot.isBooked ? "text-[#B3DC26]/60" : "text-[#444]"}`}>Time Sequence</p>
                          <h4 className="text-lg font-bold text-white font-['Open_Sans'] uppercase tracking-tight">
                             {slot.startTime} - {slot.endTime}
                          </h4>
                          <p className="text-[10px] text-[#B3DC26] font-bold tracking-widest mt-1">
                             Rs {slot.price || turf.pricePerHour} <span className="text-white/70 text-[8px]">/ slot</span>
                          </p>
                       </div>
                       {slot.isActive && (
                         <div className={`px-2 py-0.5 rounded-[16px] text-[8px] font-bold uppercase tracking-widest  ${ slot.isBooked ? "bg-gradient-to-r from-[#55DEE8] to-[#B3DC26] shadow-[0_8px_24px_rgba(179,220,38,0.15)] border-none -[#B3DC26] text-black" : "bg-[#111] -white/10 text-white/70" }`}>
                           {slot.isBooked ? "Booked" : "Open"}
                         </div>
                       )}
                    </div>

                    <div className="relative z-10">
                      {slot.isBooked ? (
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 rounded-[16px] bg-[#111] border border-white/10 flex items-center justify-center overflow-hidden">
                              {slot.bookingDetails.user?.profileImage ? (
                                <img src={slot.bookingDetails.user.profileImage} className="w-full h-full object-cover" />
                              ) : (
                                <Users size={16} className="text-[#B3DC26]/60" />
                              )}
                           </div>
                           <div className="flex-1 min-w-0">
                              <h5 className="text-[13px] font-bold text-white truncate uppercase tracking-tight font-['Open_Sans']">
                                {slot.bookingDetails.user?.name || "Guest Player"}
                              </h5>
                              <p className="text-[9px] text-[#B3DC26] font-bold uppercase tracking-[2px] mt-1">View Details</p>
                           </div>
                        </div>
                      ) : (
                        <div className="flex items-center gap-3 opacity-20 group-hover:opacity-60 transition-opacity">
                           <div className="p-1.5 bg-[#111] rounded-full"><CheckCircle2 size={12} className="text-white/70" /></div>
                           <p className="text-[9px] font-bold text-white/70 uppercase tracking-[2px]">Available Sequence</p>
                        </div>
                      )}
                    </div>

                    {/* Action Hint */}
                    {slot.isActive && slot.isBooked && (
                       <div className="absolute bottom-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                          <Zap size={12} className="text-[#B3DC26]" />
                       </div>
                    )}
                  </button>
                ))
              ) : (
                <div className="col-span-full py-32 bg-[#000000] border border-dashed border-white/10 rounded-[16px] flex flex-col items-center justify-center text-center">
                   <div className="w-16 h-16 bg-[#111] rounded-full flex items-center justify-center mb-6 border border-white/10">
                      <Zap size={24} className="text-[#2D2D2D]" />
                   </div>
                   <h4 className="text-xl font-bold text-white uppercase tracking-tight mb-2 font-['Open_Sans']">Zero Operational Data</h4>
                   <p className="text-white/70 text-xs max-w-xs mx-auto opacity-60">No slots are configured for the selected timeline. Adjust your arena settings to deploy new sessions.</p>
                </div>
              )}
           </div>
        </div>
      </div>
    </div>
  );
}

const fs = require('fs');
