    step1Block = step1Block.replace(/\\n              <\\/div>\\n            <\\/div>\\n          \\)}\\n/g, '\\n            </div>\\n          )}\\n');

    content = before + step1Block + after;
    fs.writeFileSync(path, content, 'utf8');
