              className="flex items-center gap-1 font-semibold text-[10px] md:text-[15px] transition-all hover:text-[#BFF367] text-[#888] whitespace-nowrap"
            >
              View All <span className="hidden md:inline">Pros</span> <ChevronRight size={16} />
            </Link>
          </div>
        </div>

        {/* Professionals Grid */}
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 xl:grid-cols-6 gap-3 md:gap-4">
          {professionalsLoading ? (
            [...Array(6)].map((_, i) => (
              <div
                key={i}
                className="aspect-[1/1.3] rounded-[8px] bg-white/5 border border-white/5 animate-pulse"
              />
            ))
          ) : professionals.length === 0 ? (
            <div className="col-span-full py-12 text-center border-2 border-dashed border-white/5 rounded-[8px]">
              <p className="text-white/20 font-mono text-[10px] uppercase tracking-widest">
                No professionals active in your area
              </p>
            </div>
          ) : (
            professionals.slice(0, 8).map((pro) => (
              <div
                key={pro._id || pro.id}
                className="group cursor-pointer"
                onClick={() => navigate(`/profile/${pro.userId || pro.id || pro._id}`)}
              >
                <div className="relative bg-[#121212] rounded-[8px] p-1.5 border border-white/5 transition-all duration-500 hover:border-[#BFF367]/20 hover:shadow-[0_15px_30px_rgba(0,0,0,0.4)]">
                  {/* Compact Profile Image Section */}
                  <div className="relative aspect-[1/1.2] rounded-[8px] overflow-hidden block mb-2.5">
                    <div className="w-full h-full bg-[#1A1A1A] flex items-center justify-center">
                      {pro.profilePicture ? (
                        <img
                          src={pro.profilePicture}
                          alt={pro.name}
                          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                          onError={(e) => {
                            e.target.style.display = "none";
                            e.target.nextElementSibling.style.display = "flex";
                          }}
                        />
                      ) : null}
                      <div
                        className="relative z-10 flex items-center justify-center w-full h-full bg-gradient-to-br from-[#1a1a1a] to-[#0a0a0a]"
                        style={{
                          display: pro.profilePicture ? "none" : "flex",
                        }}
                      >
                        <span className="text-[#BFF367] font-black text-3xl tracking-tighter opacity-20 group-hover:opacity-40 transition-opacity duration-500">
                          {pro.name
                            ?.split(" ")
                            .map((w) => w[0])
                            .join("")
                            .toUpperCase()
                            .slice(0, 2)}
                        </span>
                      </div>
                    </div>

                    {/* Price Badge */}
                    <div className="absolute top-2 right-2 z-20">
                      <div className="px-2 py-1 rounded-[6px] bg-black/60 backdrop-blur-md border border-white/10 flex items-center justify-center text-[#BFF367] text-[8px] font-bold shadow-lg">
                        ₹{pro.price || "500"}/
                        {pro.role === "coach" ? "hr" : "match"}
                      </div>
                    </div>

                    {/* Role Badge */}
                    <div className="absolute top-2 left-2 z-20">
                      <div className="px-2 py-1 rounded-[6px] bg-black/60 backdrop-blur-md border border-white/10 flex items-center justify-center text-white text-[8px] font-black tracking-widest gap-1 shadow-lg">
                        {pro.role === "umpire" ? (
                          <Shield size={8} className="text-[#BFF367]" />
                        ) : pro.role === "streamer" ? (
                          <Video size={8} className="text-[#BFF367]" />
                        ) : pro.role === "scorer" ? (
                          <Activity size={8} className="text-[#BFF367]" />
                        ) : (
                          <Award size={8} className="text-[#BFF367]" />
                        )}
                        <span className="text-[#BFF367]">
                          {pro.role?.toUpperCase()}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Content Section */}
                  <div className="px-1.5 pb-1">
                    <div className="flex items-center gap-1 mb-0.5">
                      <h3 className="text-white font-bold text-[13px] tracking-tight group-hover:text-[#BFF367] transition-colors line-clamp-1 font-open-sans capitalize">
                        {pro.name?.toLowerCase()}
                      </h3>
                      <div className="flex items-center justify-center w-3 h-3 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)] shrink-0">
                        <Check
                          size={7}
                          strokeWidth={4}
                          className="text-white"
                        />
                      </div>
                    </div>

                    <p className="text-white/40 text-[9px] font-medium leading-tight mb-3 line-clamp-1">
                      <span className="capitalize">
                        {pro.businessDetails?.specialization?.toLowerCase() ||
                          "expert coach"}
                      </span>{" "}
                      •{" "}
                      {pro.businessDetails?.experience?.toLowerCase() ||
                        "5+ years"}
                    </p>

                    {/* Bottom Bar */}
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className="flex items-center gap-1 text-white/80">
                          <Star
                            size={12}
                            className="text-[#BFF367] fill-[#BFF367]"
                          />
                          <span className="text-[10px] font-bold">
                            {pro.rating?.toFixed(1) || "5.0"}
                          </span>
                        </div>
                        <div className="flex items-center text-white/30">
                          <span className="text-[9px] font-medium">
                            ({pro.numReviews || 0})
                          </span>
                        </div>
                      </div>

                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          navigate(`/profile/${pro.userId || pro.id || pro._id}`);
                        }}
                        className="px-4 py-2 rounded-[8px] font-black text-[9px] uppercase tracking-wider transition-all duration-300 text-black hover:scale-105 shadow-[0_0_15px_rgba(85,222,232,0.3)]"
                        style={{ background: GRAD }}
                      >
                        BOOK
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </section>
  );
}

import React, { useEffect, useRef, useState, useCallback } from "react";
import { X, Image as ImageIcon, Video, Sparkles, SwitchCamera } from "lucide-react";
import { useNavigate } from "react-router-dom";

const POST_TYPES = ["Post", "Reel", "Story"];

const NewPostLanding = () => {
  const navigate = useNavigate();
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const recordedChunksRef = useRef([]);
  const holdTimerRef = useRef(null);
  
  const [stream, setStream] = useState(null);
  const streamRef = useRef(null);
  const [activeTab, setActiveTab] = useState("Reel");
  const [facingMode, setFacingMode] = useState("environment");
  const [isRecording, setIsRecording] = useState(false);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const recordingDurationRef = useRef(0);
  const [previewMedia, setPreviewMedia] = useState(null);
  
  useEffect(() => {
    recordingDurationRef.current = recordingDuration;
  }, [recordingDuration]);
  
  const startCamera = useCallback(async () => {
    // Ensure any existing streams are fully stopped before starting a new one
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = videoRef.current.srcObject.getTracks();
      tracks.forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode },
        audio: true 
      });
      setStream(mediaStream);
      streamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
      try {
        const mediaStreamFallback = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode }
        });
        setStream(mediaStreamFallback);
        streamRef.current = mediaStreamFallback;
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStreamFallback;
        }
      } catch (fallbackErr) {
        console.error("Error accessing camera fallback:", fallbackErr);
      }
    }
  }, [facingMode]);

  const toggleCamera = () => {
    setFacingMode(prev => prev === "environment" ? "user" : "environment");
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => {
        track.stop();
        // Also fire stop event manually just in case
        try { track.enabled = false; } catch(e) {}
      });
      streamRef.current = null;
    }
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = videoRef.current.srcObject.getTracks();
      tracks.forEach(track => {
        track.stop();
        try { track.enabled = false; } catch(e) {}
      });
      videoRef.current.srcObject = null;
    }
    setStream(prevStream => {
      if (prevStream) {
        prevStream.getTracks().forEach(track => track.stop());
      }
      return null;
    });
  }, []);

  // Start the camera when the component mounts
  useEffect(() => {
    startCamera();

    // Cleanup camera when leaving the page
    return () => {
      stopCamera();
    };
  }, [startCamera]); // We handle stream dependencies in stopCamera

  // No need for a separate useEffect to re-attach stream as it's handled by startCamera

  // Handle Recording Timer
  useEffect(() => {
    let interval;
    if (isRecording) {
      interval = setInterval(() => {
        setRecordingDuration(prev => prev + 1);
      }, 1000);
    } else {
      setRecordingDuration(0);
    }
    return () => clearInterval(interval);
  }, [isRecording]);

  // Auto-stop recording at 60 seconds
  useEffect(() => {
    if (isRecording && recordingDuration >= 60) {
      stopRecording();
    }
  }, [recordingDuration, isRecording]);

  const setPreview = (file) => {
    const isVideo = file.type.startsWith('video');
    setPreviewMedia({
      file,
      type: isVideo ? 'video' : 'image',
      url: URL.createObjectURL(file)
    });
    stopCamera();
  };

  const handleMediaCaptured = useCallback((file) => {
    if (activeTab === "Reel") {
      navigate('/reels/upload', { state: { preSelectedFile: file } });
    } else if (activeTab === "Post") {
      navigate('/create-post', { state: { preSelectedFile: file } });
    } else if (activeTab === "Story") {
      navigate('/create-story', { state: { preSelectedFile: file } });
    }
  }, [activeTab, navigate]);

  const takePhoto = () => {
    if (!videoRef.current || !canvasRef.current) return;
    
    const video = videoRef.current;
    const canvas = canvasRef.current;
    
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    
    const context = canvas.getContext('2d');
    context.drawImage(video, 0, 0, canvas.width, canvas.height);
    
    canvas.toBlob((blob) => {
      if (blob) {
        const file = new File([blob], "photo.jpg", { type: "image/jpeg" });
        setPreview(file);
      }
    }, 'image/jpeg', 0.95);
  };

  const startRecording = () => {
    if (!stream) return;
    
    recordedChunksRef.current = [];
    try {
      let options = {};
      if (typeof MediaRecorder.isTypeSupported === 'function') {
        if (MediaRecorder.isTypeSupported('video/mp4')) {
          options = { mimeType: 'video/mp4' };
        } else if (MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')) {
          options = { mimeType: 'video/webm;codecs=vp9,opus' };
        } else if (MediaRecorder.isTypeSupported('video/webm')) {
          options = { mimeType: 'video/webm' };
        }
      }
      
      const mediaRecorder = new MediaRecorder(stream, options);
      
      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          recordedChunksRef.current.push(event.data);
        }
      };
      
      mediaRecorder.onstop = () => {
        if (recordingDurationRef.current < 5) return;
        
        const finalMimeType = mediaRecorder.mimeType || 'video/webm';
        const ext = finalMimeType.includes('mp4') ? 'mp4' : 'webm';
        const blob = new Blob(recordedChunksRef.current, { type: finalMimeType });
        const file = new File([blob], `video.${ext}`, { type: finalMimeType });
        setPreview(file);
        setIsRecording(false);
      };
      
      mediaRecorderRef.current = mediaRecorder;
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Failed to start MediaRecorder", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== "inactive") {
      if (recordingDurationRef.current < 5) {
        import("react-hot-toast").then((module) => {
          module.default.error("Video must be at least 5 seconds long", { id: "video-duration-error" });
        });
        mediaRecorderRef.current.onstop = null; // Discard
        mediaRecorderRef.current.stop();
        setIsRecording(false);
      } else {
        mediaRecorderRef.current.stop();
      }
    }
  };

  const handlePointerDown = (e) => {
    // Prevent context menu or long press text selection
    e.preventDefault();
    
    // For Posts, we only allow taking photos (tapping), not recording video
    if (activeTab === "Post") return;
    
    holdTimerRef.current = setTimeout(() => {
      startRecording();
    }, 500); // 500ms hold to start recording video
  };

  const handlePointerUp = (e) => {
    e.preventDefault();
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
      holdTimerRef.current = null;
    }
    
    if (isRecording) {
      stopRecording();
    } else {
      // If we didn't hold long enough to trigger recording, it's a photo tap
      if (activeTab === "Reel") {
        import("react-hot-toast").then((module) => {
          module.default.error("Reels must be a video.", { id: "reel-photo-error" });
        });
        return;
      }
      takePhoto();
    }
  };



  // Handle Tab Switch
  const handleTabSwitch = (type) => {
    if (type === "Post") {
      navigate("/create-post");
      return;
    }
    setActiveTab(type);
  };

  const handleGalleryUpload = () => {
    // Determine accepted file types based on active tab
    let acceptTypes = "image/*,video/*";
    if (activeTab === "Reel") {
      acceptTypes = "video/*";
    }

    const input = document.createElement("input");
    input.type = "file";
    input.accept = acceptTypes;
    input.multiple = activeTab === "Post";
    input.onchange = (e) => {
      const files = Array.from(e.target.files);
      if (files.length > 0) {
        if (activeTab === "Post") {
          // If we allow multiple, bypass duration check for images and navigate directly
          navigate('/create-post', { state: { preSelectedFiles: files } });
        } else {
          const file = files[0];
          if (file.type.startsWith('video')) {
            const videoElement = document.createElement('video');
            videoElement.preload = 'metadata';
            videoElement.onloadedmetadata = () => {
              window.URL.revokeObjectURL(videoElement.src);
              if (videoElement.duration < 5) {
                import("react-hot-toast").then((module) => {
                  module.default.error("Video must be at least 5 seconds long", { id: "video-duration-error" });
                });
                return;
              }
              handleMediaCaptured(file);
            };
            videoElement.src = URL.createObjectURL(file);
          } else {
            if (activeTab === "Reel") {
              import("react-hot-toast").then((module) => {
                module.default.error("Photos are not allowed on Reels", { id: "reel-photo-error" });
              });
              return;
            }
            handleMediaCaptured(file);
          }
        }
      }
    };
    input.click();
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (previewMedia) {
    return (
      <div className="w-full h-[100dvh] relative bg-black overflow-hidden font-sans">
        {previewMedia.type === 'video' ? (
          <video src={previewMedia.url} className="absolute inset-0 w-full h-full object-cover scale-[1.02]" autoPlay loop playsInline muted controls />
        ) : (
          <img src={previewMedia.url} className="absolute inset-0 w-full h-full object-cover scale-[1.02]" alt="Preview" />
        )}
        
        {/* Top Controls */}
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-center z-10">
          <button 
            onClick={() => {
              URL.revokeObjectURL(previewMedia.url);
              setPreviewMedia(null);
              startCamera();
            }}
            className="w-10 h-10 rounded-full bg-black/40 backdrop-blur-md text-white flex items-center justify-center border border-white/10 hover:bg-black/60 transition-colors"
          >
            <X size={24} />
          </button>
        </div>

        {/* Bottom Controls */}
        <div className="absolute bottom-0 left-0 w-full z-20 flex justify-between items-center px-6 pb-12 pointer-events-auto">
          {/* Spacer for flex distribution */}
          <div className="flex-1" />
          
          <button 
            onClick={() => handleMediaCaptured(previewMedia.file)}
            className="px-8 py-3 bg-[#BFF367] text-black font-bold uppercase tracking-wider rounded-full shadow-[0_0_20px_rgba(191,243,103,0.3)] hover:scale-105 active:scale-95 transition-all"
          >
            Continue
          </button>
          
          <div className="flex-1 flex justify-end">
            <button 
              onClick={() => {
                URL.revokeObjectURL(previewMedia.url);
                setPreviewMedia(null);
                startCamera();
              }}
              className="px-6 py-2.5 bg-white/10 backdrop-blur-md text-white font-medium rounded-full hover:bg-white/20 transition-colors flex items-center gap-2"
            >
              Retake
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-[100dvh] relative bg-black overflow-hidden font-sans">
      {/* Live Camera Background */}
      <video 
        ref={videoRef}
        autoPlay 
        playsInline 
        muted 
        className="absolute inset-0 w-full h-full object-cover scale-[1.02]"
      />
      <canvas ref={canvasRef} className="hidden" />
      
      {/* Top Gradient for visibility of top controls */}
      <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-black/60 to-transparent pointer-events-none" />

      {/* Top Controls */}
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-center z-10">
        <button 
          onClick={() => navigate(-1)}
          className="w-10 h-10 rounded-full bg-black/40 backdrop-blur-md text-white flex items-center justify-center border border-white/10 hover:bg-black/60 transition-colors"
        >
          <X size={24} />
        </button>
        {isRecording && (
          <div className="flex items-center gap-2 bg-red-500/80 backdrop-blur-md px-3 py-1.5 rounded-full">
            <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
            <span className="text-white text-xs font-bold">{formatTime(recordingDuration)}</span>
          </div>
        )}
        <div className="w-10 h-10 rounded-full bg-black/40 backdrop-blur-md text-white flex items-center justify-center border border-white/10">
          <Sparkles size={20} className="text-[#BFF367]" />
        </div>
      </div>

      {/* Bottom Controls Area */}
      <div className="absolute bottom-0 left-0 w-full z-20 flex flex-col items-center pb-6 pointer-events-auto">
        
        {/* Post Type Selector */}
        <div className="bg-black/60 backdrop-blur-xl border border-white/10 rounded-full p-1.5 flex gap-1 shadow-2xl mb-4">
          {POST_TYPES.map((type) => (
            <button
              key={type}
              onClick={() => handleTabSwitch(type)}
              className={`px-6 py-2 rounded-full text-sm font-semibold transition-all duration-300 ${
                activeTab === type 
                  ? "bg-white text-black shadow-md scale-105" 
                  : "text-white/70 hover:text-white hover:bg-white/10"
              }`}
            >
              {type}
            </button>
          ))}
        </div>

        {/* Actions Row */}
        <div className="relative flex items-center justify-center w-full h-24 mt-2">
          
          {/* Upload Button */}
          <button 
            onClick={handleGalleryUpload}
            className={`absolute transition-all duration-300 flex items-center justify-center gap-2 hover:bg-white/10 bg-black/60 backdrop-blur-md border border-white/20 rounded-full shadow-xl left-6 px-4 py-2`}
          >
            <div className={`w-8 h-8 rounded-full bg-[#BFF367]/10 flex items-center justify-center`}>
              {activeTab === "Reel" ? (
                <Video size={16} className="text-[#BFF367]" />
              ) : (
                <ImageIcon size={16} className="text-[#BFF367]" />
              )}
            </div>
            <span className="text-[11px] font-bold text-white tracking-wide uppercase">Upload</span>
          </button>

          {/* Capture Button */}
          <button 
             onPointerDown={handlePointerDown}
             onPointerUp={handlePointerUp}
             onPointerLeave={handlePointerUp} // Safety to stop if finger slides off
             className={`w-20 h-20 rounded-full border-[4px] flex items-center justify-center transition-all duration-300 ${isRecording ? 'border-red-500/50 scale-110' : 'border-white/50 hover:scale-105 active:scale-95'}`}
          >
            <div className={`w-16 h-16 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(255,255,255,0.3)] transition-all duration-300 ${isRecording ? 'bg-red-500 scale-75 rounded-[12px]' : 'bg-white'}`}>
              {!isRecording && <div className="w-14 h-14 border-[2px] border-black/10 rounded-full" />}
            </div>
          </button>

          {/* Flip Camera Button */}
          <button 
            onClick={toggleCamera}
            className={`absolute transition-all duration-300 flex items-center justify-center w-12 h-12 hover:bg-white/10 bg-black/60 backdrop-blur-md border border-white/20 rounded-full shadow-xl right-6`}
          >
            <SwitchCamera size={22} className="text-white" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default NewPostLanding;

import { baseApi } from './baseApi';

export const communityApi = baseApi.injectEndpoints({
  endpoints: (builder) => ({
    getCommunityFeed: builder.query({
      query: (params) => ({
        url: '/api/user/community',
        params,
      }),
      providesTags: ['Community'],
    }),
    getPostById: builder.query({
      query: (postId) => `/api/user/community/${postId}`,
      providesTags: (result, error, id) => [{ type: 'Community', id }],
    }),
    getStoriesFeed: builder.query({
      query: (params) => ({
        url: '/api/user/stories/feed',
        params,
      }),
      providesTags: ['Stories'],
    }),
    getCommunityStats: builder.query({
      query: () => '/api/user/community/stats',
      providesTags: ['Community'],
    }),
    createPost: builder.mutation({
      query: (formData) => ({
        url: '/api/user/community',
        method: 'POST',
        body: formData,
      }),
      invalidatesTags: ['Community'],
    }),
    updatePost: builder.mutation({
      query: ({ postId, formData }) => ({
        url: `/api/user/community/${postId}`,
        method: 'PUT',
        body: formData,
      }),
      invalidatesTags: ['Community'],
    }),
    deletePost: builder.mutation({
      query: (postId) => ({
        url: `/api/user/community/${postId}`,
        method: 'DELETE',
      }),
      invalidatesTags: ['Community'],
    }),
    reportPost: builder.mutation({
      query: ({ postId, reason }) => ({
        url: `/api/user/community/${postId}/report`,
        method: 'POST',
        body: { reason },
      }),
    }),
    likePost: builder.mutation({
      query: (postId) => ({
        url: `/api/user/community/${postId}/like`,
        method: 'POST',
      }),
      async onQueryStarted(postId, { dispatch, queryFulfilled }) {
        // Optimistic update for likes
        const patchResult = dispatch(
          communityApi.util.updateQueryData('getCommunityFeed', undefined, (draft) => {
            const post = draft.posts.find((p) => p._id === postId);
            // This is a simplified optimistic update; real implementation depends on user state
            if (post) {
               // We don't have the user ID easily here without extra logic, 
               // but we can increment length as a placeholder or wait for response.
               // For now, let's wait for queryFulfilled for likes as it's more complex (add/remove).
            }
          })
        );
        try {
          await queryFulfilled;
        } catch {
          patchResult.undo();
        }
      },
      invalidatesTags: ['Community'],
    }),
    addPostComment: builder.mutation({
      query: ({ postId, text }) => ({
        url: `/api/user/community/${postId}/comment`,
        method: 'POST',
        body: { text },
      }),
      invalidatesTags: ['Community'],
    }),
    deleteComment: builder.mutation({
      query: ({ postId, commentId }) => ({
        url: `/api/user/community/${postId}/comment/${commentId}`,
        method: 'DELETE',
      }),
      invalidatesTags: ['Community'],
    }),
    getCommunityUploadUrl: builder.query({
      query: (params) => ({
        url: '/api/user/community/upload-url',
        params,
      }),
    }),
    confirmCommunityPost: builder.mutation({
      query: (data) => ({
        url: '/api/user/community/confirm-post',
        method: 'POST',
        body: data,
      }),
      async onQueryStarted(data, { dispatch, queryFulfilled }) {
        try {
          const { data: result } = await queryFulfilled;
          // After successful confirmation, add the post to the top of the feed immediately
          if (result.success && result.post) {
            dispatch(
              communityApi.util.updateQueryData('getCommunityFeed', undefined, (draft) => {
                if (!draft.posts) draft.posts = [];
                // Check if post already exists (to avoid duplicates from refetch)
                const exists = draft.posts.some(p => (p._id || p.id) === (result.post._id || result.post.id));
                if (!exists) {
                  draft.posts.unshift(result.post);
                }
              })
            );
          }
        } catch (err) {
          // If it fails, the refetch will handle it or tags will handle it
        }
      },
      invalidatesTags: ['Community'],
    }),
    getStoryUploadUrl: builder.query({
      query: (params) => ({
        url: '/api/user/stories/upload-url',
        params,
      }),
    }),
    confirmStoryUpload: builder.mutation({
      query: (data) => ({
        url: '/api/user/stories/confirm-upload',
        method: 'POST',
        body: data,
      }),
      invalidatesTags: ['Stories'],
      async onQueryStarted(arg, { dispatch, queryFulfilled }) {
        try {
          const { data: result } = await queryFulfilled;
          if (result.success && result.story) {
            dispatch(
              communityApi.util.updateQueryData('getStoriesFeed', undefined, (draft) => {
                if (draft.stories) {
                  // Find or create group for the author (using userId field from backend)
                  const author = result.story.userId;
                  const groupIndex = draft.stories.findIndex(g => (g.author._id || g.author.id) === (author._id || author.id));
                  if (groupIndex !== -1) {
                    draft.stories[groupIndex].stories.unshift(result.story);
                  } else {
                    draft.stories.unshift({
                      author: author,
                      stories: [result.story]
                    });
                  }
                }
              })
            );
          }
        } catch (err) {}
      }
    }),
    getUserStories: builder.query({
      query: (userId) => `/api/user/community/user-stories/${userId}`,
    }),
    uploadStory: builder.mutation({
      query: (formData) => ({
        url: '/api/user/stories',
        method: 'POST',
        body: formData,
      }),
      invalidatesTags: ['Stories'],
    }),
    deleteStory: builder.mutation({
      query: (storyId) => ({
        url: `/api/user/stories/${storyId}`,
        method: 'DELETE',
      }),
      invalidatesTags: ['Stories'],
    }),
    getPostReports: builder.query({
      query: (params) => ({
        url: '/api/community/admin/reports',
        params,
      }),
      providesTags: ['Community'],
    }),
    deleteAdminPost: builder.mutation({
      query: (postId) => ({
        url: `/api/community/admin/posts/${postId}`,
        method: 'DELETE',
      }),
      invalidatesTags: ['Community'],
    }),
  }),
});

export const {
