export const VideoSection = ({ videos = [] }) => {
 const scrollRef = useRef(null);

 useEffect(() => {
 if (videos.length > 0) {
 const scrollWidth = scrollRef.current.scrollWidth;
 const viewportWidth = scrollRef.current.offsetWidth;
 
